// ── Safe storage shim (works in sandboxed iframes) ──────────
const _memStore = {};
const safeStorage = {
  getItem: (k) => { try { return typeof window !== 'undefined' ? window.localStorage.getItem(k) : (_memStore[k] ?? null); } catch { return _memStore[k] ?? null; } },
  setItem: (k, v) => { try { if (typeof window !== 'undefined') window.localStorage.setItem(k, v); } catch {} _memStore[k] = String(v); },
  removeItem: (k) => { try { if (typeof window !== 'undefined') window.localStorage.removeItem(k); } catch {} delete _memStore[k]; },
};

