    <div key={key} className="bounce" style={{ minWidth: 16, height: 16, borderRadius: 8, background: C.accent, border: `2px solid ${C.bg}`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700, color: '#fff', padding: '0 3px' }}>{count}</div>
