// ── Credentials (swap for env vars in Next.js) ───────────────
const SUPABASE_URL     = "https://wvtrpugktvnualpbjadd.supabase.co";
const SUPABASE_ANON_KEY = (typeof process !== "undefined" && process.env?.NEXT_PUBLIC_SUPABASE_ANON_KEY) || "";
const PAYSTACK_PUBLIC_KEY = (typeof process !== "undefined" && process.env?.NEXT_PUBLIC_PAYSTACK_KEY) || "";

// ── Minimal Supabase REST client (zero dependencies) ─────────
const _sbHeaders = () => ({
  "Content-Type": "application/json",
  "apikey": SUPABASE_ANON_KEY,
  "Authorization": `Bearer ${_getJWT() || SUPABASE_ANON_KEY}`,
  "Prefer": "return=representation",
});

function _getJWT() {
  try { const s = safeStorage.getItem("errand_sb_session"); return s ? JSON.parse(s).access_token : null; } catch { return null; }
}
function _saveSession(session) {
  if (session) safeStorage.setItem("errand_sb_session", JSON.stringify(session));
  else safeStorage.removeItem("errand_sb_session");
}

const sbAuth = {
  async signUp({ email, password, name, phone }) {
    const r = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
      method: "POST", headers: _sbHeaders(),
      body: JSON.stringify({ email, password, data: { name, phone } }),
    });
    const d = await r.json();
    if (d.error) throw new Error(d.error.message || d.msg || "Sign up failed");
    _saveSession(d.session);
    return { user: d.user };
  },
  async signIn({ email, password }) {
    const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
      method: "POST", headers: _sbHeaders(),
      body: JSON.stringify({ email, password }),
    });
    const d = await r.json();
    if (d.error) throw new Error(d.error_description || d.error || "Sign in failed");
    _saveSession(d);
    return { user: d.user };
  },
  async signOut() {
    try {
      await fetch(`${SUPABASE_URL}/auth/v1/logout`, { method: "POST", headers: _sbHeaders() });
    } catch (_) {}
    _saveSession(null);
  },
  async getUser() {
    const token = _getJWT();
    if (!token) return null;
    try {
      const r = await fetch(`${SUPABASE_URL}/auth/v1/user`, { headers: _sbHeaders() });
      if (!r.ok) { _saveSession(null); return null; }
      return await r.json();
    } catch { return null; }
  },
  async resetPassword(email) {
    await fetch(`${SUPABASE_URL}/auth/v1/recover`, {
      method: "POST", headers: _sbHeaders(),
      body: JSON.stringify({ email }),
    });
  },
  async refreshSession() {
    try {
      const s = safeStorage.getItem("errand_sb_session");
      if (!s) return null;
      const { refresh_token } = JSON.parse(s);
      const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`, {
        method: "POST", headers: _sbHeaders(),
        body: JSON.stringify({ refresh_token }),
      });
      const d = await r.json();
      if (d.access_token) { _saveSession(d); return d; }
    } catch (_) {}
    return null;
  },
};

// ── Supabase DB (PostgREST) ───────────────────────────────────
const sbDB = {
  async select(table, { filter, order, limit = 50 } = {}) {
    let url = `${SUPABASE_URL}/rest/v1/${table}?select=*&limit=${limit}`;
    if (filter) url += `&${filter}`;
    if (order) url += `&order=${order}`;
    const r = await fetch(url, { headers: _sbHeaders() });
    if (!r.ok) throw new Error(`DB select failed: ${r.status}`);
    return r.json();
  },
  async insert(table, data) {
    const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
      method: "POST", headers: _sbHeaders(),
      body: JSON.stringify(data),
    });
    if (!r.ok) throw new Error(`DB insert failed: ${r.status}`);
    return r.json();
  },
  async update(table, data, filter) {
    let url = `${SUPABASE_URL}/rest/v1/${table}`;
    if (filter) url += `?${filter}`;
    const r = await fetch(url, {
      method: "PATCH", headers: _sbHeaders(),
      body: JSON.stringify(data),
    });
    if (!r.ok) throw new Error(`DB update failed: ${r.status}`);
    return r.json();
  },
  async delete(table, filter) {
    let url = `${SUPABASE_URL}/rest/v1/${table}`;
    if (filter) url += `?${filter}`;
    const r = await fetch(url, { method: "DELETE", headers: _sbHeaders() });
    if (!r.ok) throw new Error(`DB delete failed: ${r.status}`);
    return r.json();
  },
  async upsert(table, data, onConflict = "id") {
    const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=${onConflict}`, {
      method: "POST",
      headers: { ..._sbHeaders(), Prefer: "resolution=merge-duplicates,return=representation" },
      body: JSON.stringify(data),
    });
    if (!r.ok) throw new Error(`DB upsert failed: ${r.status}`);
    return r.json();
  },
};

// ── Supabase Realtime (WebSocket) ─────────────────────────────
const sbRealtime = {
  _ws: null, _subs: {}, _reconnectTimer: null,
  connect() {
    if (this._ws?.readyState === 1) return;
    const wsUrl = SUPABASE_URL.replace("https", "wss").replace("http", "ws");
    try {
      this._ws = new WebSocket(`${wsUrl}/realtime/v1/websocket?apikey=${SUPABASE_ANON_KEY}&vsn=1.0.0`);
      this._ws.onopen = () => {
        // Re-subscribe all active subscriptions on reconnect
        Object.values(this._subs).forEach(sub => this._sendJoin(sub.topic));
      };
      this._ws.onmessage = (e) => {
        try {
          const msg = JSON.parse(e.data);
          if (msg.event === "phx_reply" && msg.payload?.status === "ok") return;
          const handlers = this._subs[msg.topic]?.handlers || [];
          handlers.forEach(fn => fn(msg));
        } catch (_) {}
      };
      this._ws.onclose = () => {
        this._reconnectTimer = setTimeout(() => this.connect(), 3000);
      };
      this._ws.onerror = () => { this._ws?.close(); };
    } catch (_) {}
  },
  _sendJoin(topic) {
    if (this._ws?.readyState !== 1) return;
    this._ws.send(JSON.stringify({ topic, event: "phx_join", payload: { config: { broadcast: { self: true }, presence: { key: "" } } }, ref: Date.now().toString() }));
  },
  subscribe(table, callback) {
    const topic = `realtime:public:${table}`;
    if (!this._subs[topic]) { this._subs[topic] = { topic, handlers: [] }; }
    this._subs[topic].handlers.push(callback);
    this.connect();
    this._sendJoin(topic);
    return () => {
      if (this._subs[topic]) {
        this._subs[topic].handlers = this._subs[topic].handlers.filter(fn => fn !== callback);
      }
    };
  },
};

// ── Supabase Storage ──────────────────────────────────────────
const sbStorage = {
  async upload(bucket, path, file) {
    const r = await fetch(`${SUPABASE_URL}/storage/v1/object/${bucket}/${path}`, {
      method: "POST",
      headers: { "apikey": SUPABASE_ANON_KEY, "Authorization": `Bearer ${_getJWT() || SUPABASE_ANON_KEY}`, "Content-Type": file.type },
      body: file,
    });
    if (!r.ok) throw new Error(`Upload failed: ${r.status}`);
    return r.json();
  },
  getPublicUrl(bucket, path) {
    return `${SUPABASE_URL}/storage/v1/object/public/${bucket}/${path}`;
  },
};

// ── Simple event bus for in-tab realtime fallback ─────────────
const _bus = {
  _listeners: {},
  emit(k, v) { (this._listeners[k] || []).forEach(fn => fn(v)); },
  on(k, fn) {
    this._listeners[k] = this._listeners[k] || [];
    this._listeners[k].push(fn);
    return () => { this._listeners[k] = this._listeners[k].filter(f => f !== fn); };
  },
};


// ── TOAST ────────────────────────────────────────────────────
let _showToast = () => {};
function useToast() { return _showToast || (() => {}); }

function Toasts({ C }) {
  const [list, setList] = useState([]);
  _showToast = useCallback((msg, icon = "✓", type = "default") => {
    const id = Date.now() + Math.random();
    setList(p => [...p, { id, msg, icon, type }]);
    setTimeout(() => setList(p => p.map(t => t.id === id ? { ...t, dying: true } : t)), 2700);
    setTimeout(() => setList(p => p.filter(t => t.id !== id)), 3100);
  }, []);
  if (!list.length) return null;
  return (
    <div style={{ position: "fixed", bottom: 82, left: "50%", transform: "translateX(-50%)", zIndex: 2000, display: "flex", flexDirection: "column", gap: 8, pointerEvents: "none", width: "calc(100vw - 32px)", maxWidth: 420 }}>
      {list.map(t => (
        <div key={t.id} style={{
          display: "flex", alignItems: "center", gap: 9,
          background: C.card, border: `1px solid ${C.border}`,
          borderRadius: 13, padding: "10px 14px", maxWidth: 260,
          boxShadow: `0 8px 28px rgba(0,0,0,.22)`,
          animation: t.dying ? "toastOut .3s ease forwards" : "toastIn .25s ease forwards",
          borderLeft: t.type === "success" ? `3px solid ${C.green}` : t.type === "error" ? `3px solid #EF4444` : `3px solid ${C.accent}`,
        }}>
          <span style={{ fontSize: 14 }}>{t.icon}</span>
          <span style={{ fontSize: 13, fontWeight: 500, color: C.text, lineHeight: 1.3 }}>{t.msg}</span>
        </div>
      ))}
    </div>
  );
}


// ── PRIMITIVES ────────────────────────────────────────────────
const Btn = ({ children, onClick, block, outline, ghost, sm, danger, grad, C, style }) => {
  const [pressed, setPressed] = useState(false);
  const isPrimary = !ghost && !outline && !danger;
  const bg = ghost ? "transparent" : outline ? "transparent" : danger ? "#EF4444" : grad ? C.gradAccent : isPrimary ? `linear-gradient(135deg,${C.accent},#FF9500)` : C.accent;
  const haptic = () => { try { if ('vibrate' in navigator) navigator.vibrate(8); } catch(e){} };
  return (
    <button onClick={() => { haptic(); if(onClick) onClick(); }} className="btn-ripple"
      role="button"
      onPointerDown={() => setPressed(true)}
      onPointerUp={() => setPressed(false)}
      onPointerLeave={() => setPressed(false)}
      style={{
        display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 7,
        width: block ? "100%" : undefined,
        minHeight: sm ? 40 : 48,
        padding: sm ? "8px 20px" : "13px 26px",
        borderRadius: sm ? 10 : 14,
        fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700,
        fontSize: sm ? 13 : 15, cursor: "pointer", letterSpacing: "0.02em",
        transform: pressed ? "scale(.96) translateY(1px)" : "scale(1) translateY(0)",
        transition: "transform 280ms cubic-bezier(.34,1.56,.64,1), box-shadow .2s ease, filter .15s",
        border: outline ? `1.5px solid ${danger ? "#EF4444" : C.accent}` : "none",
        background: bg,
        color: ghost ? C.sub : outline ? (danger ? "#EF4444" : C.accent) : "#fff",
        boxShadow: isPrimary ? (
          pressed
            ? `0 2px 8px ${C.accentGlow}`
            : `0 6px 24px ${C.accentGlow}, 0 1px 0 rgba(255,255,255,.18) inset`
        ) : "none",
        flexShrink: 0, ...style,
      }}
    >{children}</button>
  );
};

