// ── useRealTimeLocation — live GPS with reverse geocoding ─────
function useRealTimeLocation() {
  const [location, setLocation] = React.useState({
    lat: null, lng: null,
    area: null, city: "Lagos",
    loading: false, error: null, granted: false,
  });

  const reverseGeocode = async (lat, lng) => {
    try {
      const res = await fetch(
        `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`,
        { headers: { "Accept-Language": "en" } }
      );
      const data = await res.json();
      const addr = data.address || {};
      const area = addr.suburb || addr.neighbourhood || addr.quarter ||
                   addr.city_district || addr.town || addr.village || null;
      const city = addr.city || addr.state_district || addr.state || "Lagos";
      setLocation(prev => ({ ...prev, area, city, loading: false }));
    } catch {
      setLocation(prev => ({ ...prev, loading: false }));
    }
  };

  const requestLocation = React.useCallback(() => {
    if (typeof navigator === "undefined" || !("geolocation" in navigator)) {
      setLocation(prev => ({ ...prev, error: "GPS not supported", loading: false }));
      return;
    }
    setLocation(prev => ({ ...prev, loading: true, error: null }));
    navigator.geolocation.getCurrentPosition(
      ({ coords }) => {
        const { latitude: lat, longitude: lng } = coords;
        setLocation(prev => ({ ...prev, lat, lng, granted: true }));
        reverseGeocode(lat, lng);
      },
      (err) => {
        setLocation(prev => ({ ...prev, error: err.message, loading: false }));
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 60000 }
    );
  }, []);

  // Watch position for live updates
  React.useEffect(() => {
    if (typeof navigator === "undefined" || !("geolocation" in navigator)) return;
    const watchId = navigator.geolocation.watchPosition(
      ({ coords }) => {
        const { latitude: lat, longitude: lng } = coords;
        setLocation(prev => ({ ...prev, lat, lng, granted: true }));
        reverseGeocode(lat, lng);
      },
      () => {},
      { enableHighAccuracy: true, maximumAge: 30000 }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  return { ...location, requestLocation };
}


const CSS = (C) => `
@import url('https://api.fontshare.com/v2/css?f[]=satoshi@400,500,700&f[]=syne@600,700,800&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Geist+Mono:wght@400;500;600&display=swap');

/* ── Reset ── */
*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
html,body{height:100%;background:${C.bg};}
body{font-family:'Satoshi',system-ui,sans-serif;color:${C.text};font-size:calc(16px * var(--text-scale, 1));line-height:1.6;
  -webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;}
.disp{font-family:'Syne',sans-serif;font-weight:700;letter-spacing:-0.03em;}
.mono{font-family:'Geist Mono',monospace;font-variant-numeric:tabular-nums;}
.body-alt{font-family:'Satoshi',system-ui,sans-serif;}
input,textarea,select,button{font-family:'Satoshi',system-ui,sans-serif;}

/* ── Design tokens via CSS custom properties ── */
:root{
  /* spacing */
  --sp-1:8px; --sp-2:16px; --sp-3:24px; --sp-4:32px; --sp-5:40px; --sp-6:48px; --sp-half:4px;
  /* radii */
  --r-sm:8px; --r-md:14px; --r-lg:18px; --r-xl:22px; --r-2xl:26px; --r-pill:100px;
  /* shadows */
  --shadow-sm:0 1px 3px rgba(0,0,0,.1),0 1px 2px rgba(0,0,0,.06);
  --shadow-md:0 4px 16px rgba(0,0,0,.12),0 1px 4px rgba(0,0,0,.08);
  --shadow-lg:0 8px 32px rgba(0,0,0,.18),0 2px 8px rgba(0,0,0,.1);
  --shadow-xl:0 16px 48px rgba(0,0,0,.25),0 4px 16px rgba(0,0,0,.1);
  /* easing */
  --ease-spring:cubic-bezier(.34,1.56,.64,1);
  --ease-out:cubic-bezier(.22,1,.36,1);
  --ease-in-out:cubic-bezier(.65,0,.35,1);
  /* durations */
  --dur-fast:120ms; --dur-base:200ms; --dur-slow:320ms; --dur-slower:500ms;
  /* fluid type scale */
  --text-xs:12px; --text-sm:13px; --text-base:16px; --text-md:17px;
  --text-lg:18px; --text-xl:22px; --text-2xl:28px; --text-3xl:32px;
  /* theme vars (also set by applyThemeVars) */
  --c-bg:${C.bg}; --c-surface:${C.surface}; --c-card:${C.card}; --c-border:${C.border};
  --c-accent:${C.accent}; --c-accent-bg:${C.accentBg}; --c-accent-line:${C.accentLine};
  --c-text:${C.text}; --c-sub:${C.sub}; --c-muted:${C.muted};
  --c-green:${C.green}; --c-gold:${C.gold}; --c-glass:${C.glass};
  --c-grad-accent:${C.gradAccent}; --c-grad-cool:${C.gradCool};
}

/* ── Layout shell ── */
.app-shell{display:flex;min-height:100vh;position:relative;}
.sidebar{display:none;}
.main-col{flex:1;min-width:0;position:relative;min-height:100vh;overflow:hidden;max-width:480px;margin:0 auto;}
.screen{position:absolute;inset:0;overflow-y:auto;overflow-x:hidden;
  -webkit-overflow-scrolling:touch;scroll-behavior:smooth;}
.screen::-webkit-scrollbar{display:none;}
.hrow{display:flex;overflow-x:auto;gap:10px;scrollbar-width:none;}
.hrow::-webkit-scrollbar{display:none;}

/* ── Screen transitions ── */
.screen-enter{animation:screenIn 220ms var(--ease-out) both;}
.screen-back {animation:screenBack 220ms var(--ease-out) both;}
@keyframes screenIn  {from{opacity:0;transform:translateX(20px) scale(.982)} to{opacity:1;transform:none}}
@keyframes screenBack{from{opacity:0;transform:translateX(-20px) scale(.982)} to{opacity:1;transform:none}}

/* ── Scroll-reveal ── */
.reveal{opacity:0;transform:translateY(16px) scale(.988);
  transition:opacity var(--dur-slow) var(--ease-out),transform var(--dur-slow) var(--ease-out);}
.reveal.visible{opacity:1;transform:none;}

/* ── Skeleton shimmer ── */
.skel{background:linear-gradient(90deg,${C.card} 20%,${C.dark?`rgba(255,149,0,.06)`:`rgba(255,77,26,.04)`} 50%,${C.card} 80%);
  background-size:300% 100%;animation:skelMove 1.8s ease-in-out infinite;border-radius:var(--r-md);}
@keyframes skelMove{0%{background-position:200% 0}100%{background-position:-200% 0}}

/* ── Ripple button ── */
.btn-ripple{position:relative;overflow:hidden;min-height:48px;}
.btn-ripple::after{content:'';position:absolute;inset:0;background:rgba(255,255,255,.12);
  transform:scale(0);border-radius:inherit;transition:transform .25s var(--ease-out),opacity .25s;opacity:0;}
.btn-ripple:active::after{transform:scale(1);opacity:1;}
.btn-ripple:hover{filter:brightness(1.07);}

/* ── Tap feedback ── */
.tap{transition:transform 280ms cubic-bezier(.34,1.56,.64,1),opacity 200ms;cursor:pointer;}
.tap:active{transform:scale(.94) translateY(1px);opacity:.85;}

/* ── Elevation & glass system ── */
.card-elev-0{background:${C.card};border:1px solid ${C.border};}
.card-elev-1{transition:box-shadow 280ms cubic-bezier(.34,1.56,.64,1),transform 280ms cubic-bezier(.34,1.56,.64,1);background:${C.dark?'rgba(17,17,32,.92)':'rgba(255,255,255,.92)'};
  border:1px solid ${C.glassBorder};
  backdrop-filter:blur(16px) saturate(160%);-webkit-backdrop-filter:blur(16px) saturate(160%);}
.card-elev-2{background:${C.dark?'rgba(22,22,40,.88)':'rgba(253,252,250,.88)'};
  border:1px solid ${C.glassBorder};
  backdrop-filter:blur(32px) saturate(200%);-webkit-backdrop-filter:blur(32px) saturate(200%);}
.glass{background:${C.glass};backdrop-filter:blur(20px) saturate(180%);
  -webkit-backdrop-filter:blur(20px) saturate(180%);border:1px solid ${C.glassBorder};}

/* ── Theme mesh background ── */
.theme-mesh{background:${C.meshBg || 'none'};}

/* ── Bounce in ── */
@keyframes bounceIn{0%{transform:scale(0)}55%{transform:scale(1.2)}75%{transform:scale(.92)}100%{transform:scale(1)}}
@keyframes slideDown{from{opacity:0;transform:translateX(-50%) translateY(-20px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}
.bounce{animation:bounceIn .28s var(--ease-spring) both;}

/* ── Sidebar (desktop ≥1024px) ── */
@media(min-width:1024px){
  .sidebar{display:flex;flex-direction:column;width:260px;flex-shrink:0;
    padding:28px 14px;border-right:1px solid ${C.border};
    background:${C.dark?'rgba(6,6,15,.96)':'rgba(244,241,237,.96)'};
    backdrop-filter:blur(28px);-webkit-backdrop-filter:blur(28px);
    position:sticky;top:0;height:100vh;overflow-y:auto;}
  .bottom-nav{display:none!important;}
  .main-col{overflow-y:auto;height:100vh;}
  .main-col::-webkit-scrollbar{display:none;}
  .screen{position:static;overflow:visible;height:auto;}
  .screen-enter,.screen-back{animation:none;}
}

/* ── Gradient text ── */
.grad-text{background:var(--c-grad-accent);-webkit-background-clip:text;
  -webkit-text-fill-color:transparent;background-clip:text;}
.grad-cool{background:var(--c-grad-cool);-webkit-background-clip:text;
  -webkit-text-fill-color:transparent;background-clip:text;}

/* ── Glow utilities ── */
.glow-accent{box-shadow:0 0 0 1px ${C.accentLine},0 4px 24px ${C.accentGlow},0 0 48px ${C.accentGlow};}
.glow-green{box-shadow:0 0 0 1px ${C.greenLine||C.green+'33'},0 4px 20px ${C.greenLine||C.green+'33'};}
.pulse-dot{width:8px;height:8px;border-radius:50%;background:${C.green};
  animation:pulseRing 2s ease-out infinite;}
@keyframes pulseRing{0%{box-shadow:0 0 0 0 ${C.green}55}70%{box-shadow:0 0 0 9px transparent}100%{box-shadow:0 0 0 0 transparent}}
@keyframes loadBar{0%{width:0%;margin-left:0}50%{width:100%;margin-left:0}100%{width:0%;margin-left:100%}}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}
@keyframes pulseGlow{0%,100%{opacity:.6;transform:translateX(-50%) scale(1)}50%{opacity:1;transform:translateX(-50%) scale(1.08)}}

/* ── Focus ring — WCAG 2.2 SC 2.4.11 / 2.4.12 ── */
/* Min 2px, contrasting color, not clipped by overflow */
*:focus-visible{
  outline:3px solid ${C.accent};
  outline-offset:2px;
  border-radius:var(--r-sm);
  box-shadow:0 0 0 5px ${C.accentBg};
}
/* Hide focus ring for mouse users */
[data-focus-hide] *:focus-visible{outline:none;box-shadow:none;}

/* ── Focus ring — WCAG 2.2 ── */
*:focus-visible{outline:2.5px solid ${C.accent};outline-offset:3px;border-radius:var(--r-sm);}
[data-focus-enhanced] *:focus-visible{outline:3.5px solid ${C.accent};outline-offset:4px;box-shadow:0 0 0 6px ${C.accentBg};}

/* ── High contrast overrides ── */
[data-high-contrast]{
  --c-border:${C.dark?'rgba(255,255,255,.35)':'rgba(0,0,0,.35)'} !important;
  --c-sub:${C.dark?'rgba(255,255,255,.8)':'rgba(0,0,0,.8)'} !important;
  --c-muted:${C.dark?'rgba(255,255,255,.5)':'rgba(0,0,0,.5)'} !important;
}
[data-high-contrast] .card-elev-0,[data-high-contrast] .card-elev-1,[data-high-contrast] .card-elev-2{
  border-width:2px !important;
}

/* ── Reduced motion overrides ── */
[data-reduce-motion] *,[data-reduce-motion] *::before,[data-reduce-motion] *::after{
  animation-duration:.01ms !important;
  animation-iteration-count:1 !important;
  transition-duration:.01ms !important;
}

/* ── Screen reader only utility ── */
.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0;}

/* ── Text scale ── */
body{font-size:calc(16px * var(--text-scale, 1));}

/* ── WCAG 2.5.5: pointer targets ── */
[role="button"],[role="tab"],[role="switch"]{min-height:48px;min-width:48px;}

/* ── Scrollbar ── */
*::-webkit-scrollbar{width:2px;height:2px;}
*::-webkit-scrollbar-track{background:transparent;}
*::-webkit-scrollbar-thumb{background:${C.border};border-radius:10px;}

/* ── Hover lift ── */
.hover-lift{transition:transform 280ms cubic-bezier(.34,1.56,.64,1),box-shadow 280ms var(--ease-out);}
.hover-lift:hover{transform:translateY(-3px) scale(1.01);box-shadow:0 12px 32px rgba(0,0,0,.18);}
/* 2026 spring card */
.spring-card{transition:all 280ms cubic-bezier(.34,1.56,.64,1);}
.spring-card:active{transform:scale(.97) translateY(1px);}
/* Mono prices */
.price{font-family:'Geist Mono',monospace;font-variant-numeric:tabular-nums;font-weight:600;}
/* AI badge */
.ai-badge{display:inline-flex;align-items:center;gap:3px;background:linear-gradient(135deg,rgba(155,111,255,.18),rgba(255,77,26,.12));border:1px solid rgba(155,111,255,.28);border-radius:8px;padding:2px 7px;font-size:10px;font-weight:800;color:#9B6FFF;letter-spacing:.04em;}

/* ── Semantic colour utilities (use CSS vars where possible) ── */
/* ── Leaflet map overrides ── */
.leaflet-container{font-family:'Satoshi',system-ui,sans-serif!important;}
.leaflet-popup-content-wrapper{border-radius:12px!important;box-shadow:0 4px 20px rgba(0,0,0,.18)!important;}
.leaflet-popup-tip-container{display:none;}
.leaflet-control-zoom{border:none!important;border-radius:10px!important;overflow:hidden;}
.leaflet-control-zoom a{background:var(--c-card)!important;color:var(--c-text)!important;border-color:var(--c-border)!important;font-size:16px!important;line-height:28px!important;width:30px!important;height:30px!important;}
.leaflet-control-zoom a:hover{background:var(--c-accent-bg)!important;}

/* ── Touch targets ≥44px (WCAG 2.5.5) ── */
.bottom-nav{height:calc(64px + env(safe-area-inset-bottom,0px));}.bottom-nav > *{min-height:64px;}

/* ── Safe-area insets ── */
.screen{padding-bottom:calc(80px + env(safe-area-inset-bottom, 0px));}

/* ── 2026 Neo-minimal card ── */
.neo-card{
  background:${C.dark?"rgba(255,255,255,.035)":"rgba(255,255,255,.9)"};
  border:1px solid ${C.border};
  border-radius:18px;
  backdrop-filter:blur(32px) saturate(180%);
  -webkit-backdrop-filter:blur(32px) saturate(180%);
  transition:transform 280ms cubic-bezier(.34,1.56,.64,1),box-shadow 280ms var(--ease-out),border-color 200ms;
}
.neo-card:active{transform:scale(.97) translateY(1px);}

/* ── Floating glass panel ── */
.float-panel{
  background:${C.dark?"rgba(12,10,26,.88)":"rgba(255,255,255,.88)"};
  backdrop-filter:blur(40px) saturate(200%);
  -webkit-backdrop-filter:blur(40px) saturate(200%);
  border:1px solid ${C.glassBorder};
  border-radius:24px;
  box-shadow:0 24px 64px rgba(0,0,0,.24),0 2px 0 rgba(255,255,255,.06) inset;
}

/* ── 2026 input style ── */
.input-neo{
  background:${C.dark?"rgba(255,255,255,.04)":"rgba(0,0,0,.03)"};
  border:1.5px solid ${C.border};
  border-radius:14px;
  padding:14px 16px;
  font-size:15px;
  font-family:'Satoshi',system-ui,sans-serif;
  color:${C.text};
  transition:border-color 200ms,box-shadow 200ms;
  outline:none;
}
.input-neo:focus{
  border-color:${C.accent};
  box-shadow:0 0 0 4px ${C.accentBg};
}
.input-neo::placeholder{color:${C.muted};}

/* ── Geist Mono for all prices ── */
.price,.mono,[data-price]{
  font-family:'Geist Mono',monospace;
  font-variant-numeric:tabular-nums;
}

/* ── Satoshi specific weights ── */
.font-medium{font-weight:500;}
.font-bold{font-weight:700;}

/* ── Warmer scrollbar ── */
*::-webkit-scrollbar{width:2px;height:2px;}
*::-webkit-scrollbar-thumb{background:${C.accent}40;border-radius:10px;}

/* ── 2026 section label ── */
.section-label-2026{
  font-size:12px;
  font-weight:800;
  letter-spacing:1.4px;
  text-transform:uppercase;
  color:${C.muted};
  margin-bottom:10px;
  line-height:1.4;
}
/* Caption/small text (Grok: 12-13pt, line-height 1.4) */
.caption{font-size:12px;color:${C.sub};line-height:1.4;}

/* ── Swipe hint ── */
@keyframes swipeHint{0%{transform:translateX(0)}30%{transform:translateX(12px)}60%{transform:translateX(-6px)}100%{transform:translateX(0)}}
.swipe-hint{animation:swipeHint 1.8s ease-in-out 1.5s both;}

/* ── Foldable landscape ── */
@media(min-width:600px) and (orientation:landscape) and (max-width:1023px){
  .app-shell{flex-direction:row;}
  .main-col{overflow-y:auto;height:100vh;}
  .screen{position:static;overflow:visible;height:auto;}
}

.text-accent{color:var(--c-accent);}
.text-green{color:var(--c-green);}
.text-gold{color:var(--c-gold);}
.text-muted{color:var(--c-muted);}
.text-sub{color:var(--c-sub);}
.bg-accent{background:var(--c-accent);}
.bg-surface{background:var(--c-surface);}
.border-accent{border-color:var(--c-accent-line)!important;}

/* ── Card hover states ── */
.card-hover{transition:border-color 200ms,box-shadow 280ms var(--ease-out),transform 280ms cubic-bezier(.34,1.56,.64,1);}
.card-hover:hover{border-color:${C.accentLine}!important;box-shadow:0 8px 28px ${C.accentGlow};transform:translateY(-2px) scale(1.005);}

/* ── Status badge utilities ── */
.badge{display:inline-flex;align-items:center;padding:3px 9px;border-radius:var(--r-pill);font-size:var(--text-xs);font-weight:700;letter-spacing:.4px;}
.badge-accent{background:${C.accentBg};color:${C.accent};border:1px solid ${C.accentLine};}
.badge-green{background:${C.greenBg};color:${C.green};border:1px solid ${C.greenLine||C.green+'33'};}
.badge-gold{background:${C.goldBg};color:${C.gold};}
.badge-muted{background:${C.card};color:${C.sub};border:1px solid ${C.border};}

/* ── Input refinements ── */
.input-base{background:${C.surface};border:1.5px solid ${C.border};border-radius:var(--r-md);
  padding:10px 14px;color:${C.text};font-size:var(--text-base);width:100%;outline:none;
  transition:border-color var(--dur-fast),box-shadow var(--dur-fast);}
.input-base:focus{border-color:${C.accent};box-shadow:0 0 0 3px ${C.accentBg};}
.input-base::placeholder{color:${C.muted};}

/* ── Section header style ── */
.section-label{font-size:var(--text-xs);font-weight:700;letter-spacing:1.2px;
  text-transform:uppercase;color:${C.muted};margin-bottom:8px;}

/* ── Micro-animation keyframes ── */
@keyframes staggerIn{from{opacity:0;transform:translateY(16px) scale(.96)}to{opacity:1;transform:none}}
@keyframes pageEnter{from{opacity:0;transform:translateY(12px) scale(.99)}to{opacity:1;transform:none}}
@keyframes rippleOut{to{transform:translate(-50%,-50%) scale(30);opacity:0}}
@keyframes statusPop{0%{transform:scale(1)}40%{transform:scale(1.18)}70%{transform:scale(.94)}100%{transform:scale(1)}}
@keyframes slideInRight{from{opacity:0;transform:translateX(16px)}to{opacity:1;transform:none}}
@keyframes countUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}
@keyframes breathe{0%,100%{transform:scale(1)}50%{transform:scale(1.04)}}

/* ── Reduced motion — honour OS preference ── */
@media(prefers-reduced-motion:reduce){
  *{animation-duration:.01ms!important;animation-iteration-count:1!important;transition-duration:.01ms!important;}
  .reveal{opacity:1;transform:none;}
}

/* ── High-contrast mode enhancements ── */
@media(forced-colors:active){
  .card-elev-0,.card-elev-1,.card-elev-2{border:2px solid ButtonText!important;}
  .btn-ripple{forced-color-adjust:none;}
}
[data-hc="true"]{
  --focus-ring:3px solid currentColor;
}
[data-hc="true"] *:focus-visible{
  outline:3px solid currentColor!important;
  outline-offset:4px!important;
}

/* ── Screen-reader only ── */
.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0;}

/* ── Keyboard focus ring (enhanced) ── */
:focus-visible{outline:2.5px solid var(--c-accent);outline-offset:3px;border-radius:var(--r-sm);}

/* ── Accessibility utilities ── */
.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0;}
[data-hc="1"]{--c-border:rgba(255,255,255,.5)!important;--c-sub:rgba(255,255,255,.9)!important;}
[data-hc="1"] *{--shadow-md:0 0 0 2px currentColor!important;}
[data-reduced-motion="1"] *{animation-duration:.01ms!important;transition-duration:.01ms!important;}

/* ── Confetti / status animations ── */
@keyframes statusPing{0%{transform:scale(1);opacity:1}100%{transform:scale(2.2);opacity:0}}
@keyframes checkCircle{0%{stroke-dashoffset:166}100%{stroke-dashoffset:0}}
@keyframes checkMark{0%{stroke-dashoffset:29}100%{stroke-dashoffset:0}}
@keyframes floatUp{from{opacity:1;transform:translateY(0)}to{opacity:0;transform:translateY(-40px)}}

/* ── Misc keyframes ── */
@keyframes splashRing{0%,100%{transform:scale(1);opacity:.5}50%{transform:scale(1.22);opacity:.12}}
@keyframes up{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:none}}
@keyframes slideUp{from{transform:translateY(100%)}to{transform:none}}
@keyframes spin{to{transform:rotate(360deg)}}
@keyframes blink{0%,80%,100%{opacity:.25;transform:scale(.7)}40%{opacity:1;transform:scale(1)}}
@keyframes toastIn{from{transform:translateY(16px) scale(.96);opacity:0}to{transform:none;opacity:1}}
@keyframes toastOut{to{opacity:0;transform:translateY(8px) scale(.95)}}
@keyframes shimmer{0%,100%{opacity:.45}50%{opacity:1}}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes scaleIn{from{opacity:0;transform:scale(.88)}to{opacity:1;transform:none}}

/* ── Film grain overlay ── */
.app-shell::before{content:'';position:fixed;inset:0;pointer-events:none;z-index:9998;
  opacity:${C.dark?'.022':'.015'};
  background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");}

/* ── Ambient glow (mobile) ── */
@media(max-width:1023px){
  .app-shell::after{content:'';position:fixed;top:-30%;right:-20%;width:60%;height:60%;
    border-radius:50%;background:${C.dark?`radial-gradient(circle,${C.accentGlow},rgba(255,149,0,.08))`:'rgba(255,77,26,.05)'};
    filter:blur(80px);pointer-events:none;z-index:0;opacity:.45;}
}
`;

