const ORDER_HISTORY = [
  { id: "ERR-0893", store: "FoodMart",  emoji: "🛒", date: "Today, 2:30 PM",   status: "delivered", total: 6200,  items: ["Fresh Tomatoes 1kg","Basmati Rice 5kg","Free-range Eggs ×12"], rating: null },
  { id: "ERR-0871", store: "GlowStore", emoji: "💄", date: "Feb 20, 4:15 PM",  status: "delivered", total: 9900,  items: ["Vitamin C Serum","Matte Lipstick Set"], rating: 5 },
  { id: "ERR-0854", store: "TechHub",   emoji: "📱", date: "Feb 17, 11:00 AM", status: "delivered", total: 26000, items: ["Wireless Earbuds","USB-C Fast Charger"], rating: 4 },
  { id: "ERR-0812", store: "FoodMart",  emoji: "🛒", date: "Feb 12, 6:20 PM",  status: "cancelled", total: 4800,  items: ["Chicken Breast 1kg","Basmati Rice 5kg"], rating: null },
  { id: "ERR-0790", store: "HomeNest",  emoji: "🛋️", date: "Feb 8, 1:45 PM",   status: "delivered", total: 11300, items: ["Throw Pillows ×2","Desk Lamp LED"], rating: 4 },
];

function OrderHistory({ goTo, addToCart, C }) {
  const toast = useToast();
  const [section, setSection] = useState("active"); // active | completed
  const [activeFilter, setActiveFilter] = useState("all");
  const [completedFilter, setCompletedFilter] = useState("all");
  const [expanded, setExpanded] = useState(null);
  const [rating, setRating] = useState({});
  const [ratingDone, setRatingDone] = useState({});

  // Augmented order history with payment status
  const ALL_ORDERS = [
    { id: "ERR-0893", store: "FoodMart",  icon: "store", date: "Today, 2:30 PM",   status: "delivered", payStatus: "paid",    total: 6200,  items: ["Fresh Tomatoes 1kg","Basmati Rice 5kg","Free-range Eggs ×12"], rating: null },
    { id: "ERR-0891", store: "TechHub",   icon: "zap",   date: "Today, 11:00 AM",  status: "on_the_way",payStatus: "paid",    total: 9800,  items: ["USB-C Fast Charger"], rating: null },
    { id: "ERR-0889", store: "GlowStore", icon: "heart", date: "Yesterday",         status: "confirmed", payStatus: "unpaid",  total: 4200,  items: ["Matte Lipstick Set"], rating: null },
    { id: "ERR-0885", store: "FreshFarm", icon: "store", date: "Yesterday",         status: "confirmed", payStatus: "unpaid",  total: 2800,  items: ["Organic Veggies"], rating: null },
    { id: "ERR-0880", store: "HomeNest",  icon: "store", date: "Feb 22",            status: "confirmed", payStatus: "appeal",  total: 6800,  items: ["Desk Lamp LED"], rating: null },
    { id: "ERR-0871", store: "GlowStore", icon: "heart", date: "Feb 20, 4:15 PM",  status: "delivered", payStatus: "paid",    total: 9900,  items: ["Vitamin C Serum","Matte Lipstick Set"], rating: 5 },
    { id: "ERR-0854", store: "TechHub",   icon: "zap",   date: "Feb 17, 11:00 AM", status: "delivered", payStatus: "paid",    total: 26000, items: ["Wireless Earbuds","USB-C Fast Charger"], rating: 4 },
    { id: "ERR-0812", store: "FoodMart",  icon: "store", date: "Feb 12, 6:20 PM",  status: "cancelled", payStatus: "refunded",total: 4800,  items: ["Chicken Breast 1kg","Basmati Rice 5kg"], rating: null },
    { id: "ERR-0790", store: "HomeNest",  icon: "store", date: "Feb 8, 1:45 PM",   status: "delivered", payStatus: "paid",    total: 11300, items: ["Throw Pillows ×2","Desk Lamp LED"], rating: 4 },
  ];

  const ACTIVE_STATUSES = ["confirmed","on_the_way","shopping","pending"];
  const COMPLETED_STATUSES = ["delivered","cancelled"];

  const activeOrders = ALL_ORDERS.filter(o => ACTIVE_STATUSES.includes(o.status));
  const completedOrders = ALL_ORDERS.filter(o => COMPLETED_STATUSES.includes(o.status));

  const filterActive = (orders) => {
    if (activeFilter === "all") return orders;
    if (activeFilter === "unpaid") return orders.filter(o => o.payStatus === "unpaid");
    if (activeFilter === "paid") return orders.filter(o => o.payStatus === "paid");
    if (activeFilter === "appeal") return orders.filter(o => o.payStatus === "appeal");
    return orders;
  };

  const filterCompleted = (orders) => {
    if (completedFilter === "all") return orders;
    if (completedFilter === "completed") return orders.filter(o => o.status === "delivered");
    if (completedFilter === "cancelled") return orders.filter(o => o.status === "cancelled");
    return orders;
  };

  const reorder = (order) => {
    order.items.forEach((name, i) => addToCart({ id: 700 + i, name, price: Math.round(order.total / order.items.length) }));
    toast(`${order.items.length} items added to cart`, "success");
    goTo("cart");
  };

  const payStatusConfig = {
    paid:     { label: "Paid",       color: C.green,  bg: C.greenBg  },
    unpaid:   { label: "Unpaid",     color: "#F59E0B", bg: "rgba(245,158,11,.1)" },
    appeal:   { label: "Appeal",     color: "#8B5CF6", bg: "rgba(139,92,246,.1)" },
    refunded: { label: "Refunded",   color: C.accent, bg: C.accentBg },
  };

  const OrderCard = ({ order, idx }) => {
    const open = expanded === order.id;
    const ps = payStatusConfig[order.payStatus] || payStatusConfig.paid;
    return (
      <div style={{ marginBottom: 10, animation: `staggerIn 360ms ${idx * 55}ms cubic-bezier(.34,1.56,.64,1) both` }}>
        <div style={{ background: C.card, border: `1.5px solid ${open ? C.accentLine : C.border}`, borderRadius: 16, overflow: "hidden", transition: "border-color .2s" }}>
          <div onClick={() => setExpanded(open ? null : order.id)} style={{ padding: "14px 16px", display: "flex", gap: 12, alignItems: "center", cursor: "pointer" }}>
            <div style={{ width: 46, height: 46, borderRadius: 14, background: C.accentBg, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              <Icon name={order.icon} size={22} color={C.accent} />
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 3, flexWrap: "wrap" }}>
                <div className="disp" style={{ fontSize: 14.5, color: C.text }}>{order.store}</div>
                <AnimatedStatus status={order.status} C={C} size="sm" />
              </div>
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <span style={{ color: C.muted, fontSize: 12 }}>{order.id} · {order.date}</span>
              </div>
            </div>
            <div style={{ textAlign: "right", flexShrink: 0 }}>
              <div className="disp mono" style={{ fontSize: 15, color: C.text }}>₦{order.total.toLocaleString()}</div>
              <div style={{ display: "inline-flex", alignItems: "center", gap: 4, background: ps.bg, borderRadius: 6, padding: "2px 8px", marginTop: 4 }}>
                <span style={{ fontSize: 12, fontWeight: 700, color: ps.color }}>{ps.label}</span>
              </div>
            </div>
            <Icon name={open ? "up" : "down"} size={16} color={C.muted} style={{ flexShrink: 0, marginLeft: 4 }} />
          </div>

          {open && (
            <div style={{ borderTop: `1px solid ${C.border}`, padding: "14px 16px", animation: "up .2s ease" }}>
              <div style={{ marginBottom: 14 }}>
                <div style={{ color: C.muted, fontSize: 12, fontWeight: 800, letterSpacing: "1.2px", marginBottom: 10, textTransform: "uppercase" }}>Items ({order.items.length})</div>
                {order.items.map((item, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderBottom: i < order.items.length - 1 ? `1px solid ${C.border}` : "none" }}>
                    <div style={{ width: 8, height: 8, borderRadius: "50%", background: C.accent, flexShrink: 0 }} />
                    <span style={{ flex: 1, fontSize: 13.5, color: C.text }}>{item}</span>
                    <span style={{ color: C.sub, fontSize: 12 }}>₦{Math.round(order.total / order.items.length).toLocaleString()}</span>
                  </div>
                ))}
              </div>

              {order.payStatus === "unpaid" && (
                <div style={{ background: "rgba(245,158,11,.1)", border: "1px solid rgba(245,158,11,.25)", borderRadius: 12, padding: "12px 14px", marginBottom: 14, display: "flex", gap: 10, alignItems: "center" }}>
                  <Icon name="alert" size={18} color="#F59E0B" />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, color: C.text }}>Payment pending</div>
                    <div style={{ color: C.sub, fontSize: 12, marginTop: 2 }}>Complete payment to confirm your order</div>
                  </div>
                  <button onClick={() => toast("Opening payment…", "success")} style={{ padding: "7px 14px", background: "#F59E0B", border: "none", borderRadius: 9, color: "#fff", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: 12.5, cursor: "pointer" }}>Pay now</button>
                </div>
              )}

              {order.payStatus === "appeal" && (
                <div style={{ background: "rgba(139,92,246,.1)", border: "1px solid rgba(139,92,246,.25)", borderRadius: 12, padding: "12px 14px", marginBottom: 14, display: "flex", gap: 10, alignItems: "center" }}>
                  <Icon name="shield" size={18} color="#8B5CF6" />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, color: C.text }}>Appeal in progress</div>
                    <div style={{ color: C.sub, fontSize: 12, marginTop: 2 }}>Our team is reviewing your case. Usually resolves in 24–48h.</div>
                  </div>
                </div>
              )}

              {order.status === "delivered" && !ratingDone[order.id] && (
                <div style={{ marginBottom: 14, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: "12px 14px" }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: C.text, marginBottom: 9 }}>{order.rating ? "Your rating" : "Rate this order"}</div>
                  <div style={{ display: "flex", gap: 6 }}>
                    {[1,2,3,4,5].map(s => (
                      <span key={s} onClick={() => setRating(r => ({ ...r, [order.id]: s }))}
                        style={{ fontSize: 24, cursor: "pointer", filter: s <= (rating[order.id] || order.rating || 0) ? "none" : "grayscale(1)", transition: "filter .15s, transform .1s", transform: s === (rating[order.id] || order.rating) ? "scale(1.2)" : "" }}>⭐</span>
                    ))}
                    {(rating[order.id]) > 0 && !order.rating && (
                      <button onClick={() => { setRatingDone(r => ({ ...r, [order.id]: true })); toast("Thanks for your rating!", "success"); }}
                        style={{ marginLeft: "auto", padding: "5px 13px", background: C.accent, border: "none", borderRadius: 8, color: "#fff", fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif" }}>Submit</button>
                    )}
                  </div>
                </div>
              )}
              {ratingDone[order.id] && <div style={{ color: C.green, fontSize: 13, marginBottom: 14, fontWeight: 500 }}>✓ Rating submitted — thanks!</div>}

              <div style={{ display: "flex", gap: 9 }}>
                {order.status === "delivered" && (
                  <button onClick={() => reorder(order)} className="btn-ripple" style={{ flex: 1, padding: "10px", background: C.accent, border: "none", borderRadius: 11, color: "#fff", fontWeight: 600, fontSize: 13.5, cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
                    <Icon name="refresh" size={15} color="#fff" /> Reorder
                  </button>
                )}
                {ACTIVE_STATUSES.includes(order.status) && (
                  <button onClick={() => goTo("tracking")} className="btn-ripple" style={{ flex: 1, padding: "10px", background: C.accentBg, border: `1px solid ${C.accentLine}`, borderRadius: 11, color: C.accent, fontWeight: 600, fontSize: 13.5, cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
                    <Icon name="pin" size={15} color={C.accent} /> Track
                  </button>
                )}
                <button onClick={() => goTo("tracking")} className="btn-ripple" style={{ flex: 1, padding: "10px", background: C.card, border: `1px solid ${C.border}`, borderRadius: 11, color: C.text, fontWeight: 500, fontSize: 13.5, cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
                  <Icon name="receipt" size={15} color={C.sub} /> Receipt
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  const currentOrders = section === "active" ? filterActive(activeOrders) : filterCompleted(completedOrders);

  return (
    <div className="screen" style={{ background: C.bg, paddingBottom: 86 }}>
      {/* Header */}
      <div style={{ padding: "52px 20px 16px", display: "flex", gap: 12, alignItems: "center" }}>
        <Back onClick={() => goTo("profile")} C={C} />
        <div>
          <div className="disp" style={{ fontSize: 26, color: C.text, letterSpacing: "-0.04em" }}>My Orders</div>
          <div style={{ color: C.sub, fontSize: 12, marginTop: 2 }}>{ALL_ORDERS.length} total · {activeOrders.length} active</div>
        </div>
      </div>

      {/* Section toggle: Active / Completed */}
      <div style={{ display: "flex", background: C.card, borderRadius: 12, margin: "0 20px 16px", padding: 3, border: `1px solid ${C.border}` }}>
        {[["active","Active","zap"],["completed","Completed","check"]].map(([id,label,icon]) => {
          const on = section === id;
          const count = id === "active" ? activeOrders.length : completedOrders.length;
          return (
            <button key={id} onClick={() => setSection(id)} style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 7, padding: "11px 8px", border: "none", borderRadius: 10, cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: on ? 700 : 500, fontSize: 14, transition: "all .2s", background: on ? C.accent : "transparent", color: on ? "#fff" : C.sub }}>
              <Icon name={icon} size={15} color={on ? "#fff" : C.sub} />
              {label}
              <span style={{ fontSize: 12, fontWeight: 800, background: on ? "rgba(255,255,255,.22)" : C.accentBg, color: on ? "#fff" : C.accent, borderRadius: 100, padding: "2px 8px", fontFamily: "Geist Mono,monospace" }}>{count}</span>
            </button>
          );
        })}
      </div>

      {/* Sub-filters */}
      <div className="hrow" style={{ padding: "0 20px 14px", gap: 7 }}>
        {section === "active"
          ? [["all","All"],["unpaid","Unpaid"],["paid","Paid"],["appeal","Appeal"]].map(([id,l]) => (
              <button key={id} onClick={() => setActiveFilter(id)} style={{ padding: "6px 15px", borderRadius: 20, border: `1.5px solid ${activeFilter === id ? C.accent : C.border}`, background: activeFilter === id ? C.accentBg : "transparent", whiteSpace: "nowrap", fontWeight: activeFilter === id ? 700 : 400, fontSize: 12.5, cursor: "pointer", color: activeFilter === id ? C.accent : C.sub, flexShrink: 0, transition: "all .15s", fontFamily: "Satoshi,system-ui,sans-serif" }}>{l}</button>
            ))
          : [["all","All"],["completed","Completed"],["cancelled","Cancelled"]].map(([id,l]) => (
              <button key={id} onClick={() => setCompletedFilter(id)} style={{ padding: "6px 15px", borderRadius: 20, border: `1.5px solid ${completedFilter === id ? C.accent : C.border}`, background: completedFilter === id ? C.accentBg : "transparent", whiteSpace: "nowrap", fontWeight: completedFilter === id ? 700 : 400, fontSize: 12.5, cursor: "pointer", color: completedFilter === id ? C.accent : C.sub, flexShrink: 0, transition: "all .15s", fontFamily: "Satoshi,system-ui,sans-serif" }}>{l}</button>
            ))
        }
      </div>

      {/* Order list */}
      <div style={{ padding: "0 20px" }}>
        {currentOrders.length === 0 && (
          <div style={{ textAlign: "center", padding: "60px 20px" }}>
            <div style={{ display: "flex", justifyContent: "center", marginBottom: 16 }}>
              <Icon name="orders" size={48} color={C.muted} strokeWidth={1.2} />
            </div>
            <div style={{ color: C.text, fontWeight: 600, fontSize: 16, marginBottom: 6 }}>No orders here</div>
            <div style={{ color: C.sub, fontSize: 13 }}>Your {section} orders will appear here</div>
          </div>
        )}
        {currentOrders.map((order, idx) => <OrderCard key={order.id} order={order} idx={idx} />)}
      </div>
    </div>
  );
}

