function SignOutButton({ C }) {
  const { signOut } = useAuth() || {};
  return (
    <button onClick={() => signOut?.()} style={{ width: "100%", padding: "13px", background: "transparent", border: `1px solid ${C.border}`, borderRadius: 13, color: "#EF4444", cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 600, fontSize: 14.5, marginBottom: 8 }}>Sign out</button>
  );
}


