// ═════════════════════════════════════════════════════════════
//  FEATURE 2 — PUSH NOTIFICATIONS
//  Web Push via Service Worker + in-app notification centre
// ═════════════════════════════════════════════════════════════

// ── usePushNotifications ─────────────────────────────────────
// ── Push notification event bus (in-app real-time alerts) ─────
const _pushBus = { _cbs: [], emit(n) { this._cbs.forEach(fn => fn(n)); }, sub(fn) { this._cbs.push(fn); return () => { this._cbs = this._cbs.filter(f => f !== fn); }; } };

// Convert VAPID public key from base64url to Uint8Array (required by pushManager)
function _urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const raw = atob(base64);
  return Uint8Array.from([...raw].map(c => c.charCodeAt(0)));
}

// Send a push notification to a user via Supabase Edge Function
// Deploy edge fn at: supabase/functions/push-notify/index.ts
async function serverSendPush(userId, { title, body, url = "/", tag, actions = [] }) {
  try {
    await fetch(`${SUPABASE_URL}/functions/v1/push-notify`, {
      method: "POST",
      headers: { ..._sbHeaders(), "Content-Type": "application/json" },
      body: JSON.stringify({ user_id: userId, title, body, url, tag, actions }),
    });
  } catch (e) {
    console.info("Push notify edge fn unavailable:", e.message);
  }
}

function usePushNotifications() {
  const [permission, setPermission] = useState(
    typeof Notification !== "undefined" ? Notification.permission : "default"
  );
  const [subscribed, setSubscribed] = useState(false);
  const [inAppQueue, setInAppQueue] = useState([]);
  const swRegRef = useRef(null);

  // Subscribe to in-app notification bus
  useEffect(() => {
    const unsub = _pushBus.sub(n => {
      setInAppQueue(q => [...q, { ...n, id: Date.now() + Math.random() }]);
    });
    return unsub;
  }, []);

  // Auto-dismiss in-app alerts after 4s
  useEffect(() => {
    if (!inAppQueue.length) return;
    const t = setTimeout(() => setInAppQueue(q => q.slice(1)), 4000);
    return () => clearTimeout(t);
  }, [inAppQueue]);

  const request = async () => {
    if (typeof Notification === "undefined") return "unsupported";
    const p = await Notification.requestPermission();
    setPermission(p);
    if (p === "granted") {
      setSubscribed(true);
      // Register SW for push if available
      if ("serviceWorker" in navigator) {
        try {
          const reg = await navigator.serviceWorker.ready;
          swRegRef.current = reg;
          // Subscribe to real Web Push with VAPID
          // VAPID public key — generate with: npx web-push generate-vapid-keys
          const VAPID_PUBLIC_KEY = (typeof process !== "undefined" && process.env?.NEXT_PUBLIC_VAPID_PUBLIC_KEY) || "";
          try {
            const sub = await reg.pushManager.subscribe({
              userVisibleOnly: true,
              applicationServerKey: _urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
            });
            // Save subscription endpoint to Supabase so server can push later
            await sbDB.insert("push_subscriptions", {
              endpoint: sub.endpoint,
              p256dh: btoa(String.fromCharCode(...new Uint8Array(sub.getKey("p256dh")))),
              auth_key: btoa(String.fromCharCode(...new Uint8Array(sub.getKey("auth")))),
              user_id: (await sbAuth.getUser())?.id || "guest",
              created_at: new Date().toISOString(),
            }).catch(() => {}); // non-blocking
            setSubscribed(true);
          } catch (e) {
            // Blob-URL SW can't use pushManager — that's OK, in-app toasts still work
            console.info("Web Push unavailable (blob SW):", e.message);
          }
        } catch (_) {}
      }
    }
    return p;
  };

  // Show OS notification (if granted) + always emit in-app + fire server push
  const send = (title, body, opts = {}) => {
    const n = { title, body, icon: opts.icon || "🛍️", tag: opts.tag, url: opts.url };
    // In-app toast notification
    _pushBus.emit(n);
    // OS notification if permitted (works when app is foregrounded)
    if (permission === "granted") {
      try { new Notification(title, { body, icon: "/icon-192.png", tag: opts.tag, silent: false }); } catch (_) {}
    }
    // Server-side push (reaches background/closed app via SW)
    sbAuth.getUser().then(user => {
      if (user?.id) serverSendPush(user.id, { title, body, tag: opts.tag, url: opts.url });
    }).catch(() => {});
  };

  // Simulate real-time Supabase push events (order updates, deals, messages)
  const simulateOrderUpdate = (orderId, status) => {
    const msgs = {
      confirmed: { title: "Order confirmed! 🎉", body: "Your order is being prepared.", icon: "✅" },
      picked_up:  { title: "Shopper picked up! 🛵", body: "Your order is on its way.", icon: "🛵" },
      delivered:  { title: "Delivered! 📦", body: "Rate your experience.", icon: "📦" },
      cancelled:  { title: "Order cancelled", body: "A refund will be issued.", icon: "❌" },
    };
    const m = msgs[status] || { title: "Order update", body: `Status: ${status}`, icon: "🔔" };
    send(m.title, m.body, { tag: `order-${orderId}`, icon: m.icon });
  };

  const dismissInApp = (id) => setInAppQueue(q => q.filter(n => n.id !== id));

  return { permission, subscribed, request, send, inAppQueue, dismissInApp, simulateOrderUpdate };
}

// ── InAppNotificationToast — floating push alert overlay ──────
function InAppNotificationToast({ C }) {
  const { inAppQueue, dismissInApp } = usePushNotifications();
  if (!inAppQueue.length) return null;
  const n = inAppQueue[0];
  return (
    <div style={{
      position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)",
      zIndex: 9999, width: "calc(100% - 32px)", maxWidth: 420,
      background: C.card, border: `1px solid ${C.border}`,
      borderRadius: 16, padding: "13px 15px",
      boxShadow: `0 8px 32px rgba(0,0,0,.3)`,
      display: "flex", alignItems: "center", gap: 12,
      animation: "slideDown .3s var(--ease-spring)",
    }}>
      <div style={{ width: 40, height: 40, borderRadius: 12, background: C.accentBg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>
        {n.icon || "🔔"}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontWeight: 700, fontSize: 14, color: C.text, marginBottom: 2 }}>{n.title}</div>
        <div style={{ color: C.sub, fontSize: 13, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{n.body}</div>
      </div>
      <button onClick={() => dismissInApp(n.id)} style={{ background: "none", border: "none", color: C.muted, fontSize: 18, cursor: "pointer", padding: 4, flexShrink: 0 }}>✕</button>
    </div>
  );
}

