// ── AppIcon SVG (proper branded mark) ────────────────────────
function AppIcon({ size = 64, style }) {
  const r = Math.round(size * 0.22);
  return (
    <svg width={size} height={size} viewBox="0 0 64 64" fill="none" xmlns="http://www.w3.org/2000/svg" style={style}>
      <defs>
        <linearGradient id="igr" x1="0" y1="0" x2="64" y2="64" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#FF4D1A"/>
          <stop offset="100%" stopColor="#FF9500"/>
        </linearGradient>
      </defs>
      <rect width="64" height="64" rx={r} fill="url(#igr)"/>
      {/* Bag body */}
      <path d="M13 29C13 26.2 15.2 24 18 24H46C48.8 24 51 26.2 51 29V46C51 48.8 48.8 51 46 51H18C15.2 51 13 48.8 13 46V29Z" fill="white" fillOpacity="0.96"/>
      {/* Handle */}
      <path d="M23 24C23 18 27 13 32 13C37 13 41 18 41 24" stroke="white" strokeWidth="3.5" strokeLinecap="round" fill="none"/>
      {/* Speed lines */}
      <path d="M19 35.5H30" stroke="#FF5720" strokeWidth="2.5" strokeLinecap="round"/>
      <path d="M19 41.5H35.5" stroke="#FF5720" strokeWidth="2.5" strokeLinecap="round"/>
      {/* Motion dot */}
      <circle cx="41" cy="38.5" r="4.5" fill="#FF5720"/>
    </svg>
  );
}

// ── SEO meta injector ─────────────────────────────────────────
function useSEO({ title, description, image, url } = {}) {
  const { cityData } = useCity();
  useEffect(() => {
    const cityName = cityData?.name || "Lagos";
    const base = `Errand — Your personal ${cityName} market, delivered`;
    const desc = description || `Shop from local ${cityName} stores with real personal shoppers. Fast delivery, live GPS tracking, and instant payments.`;
    const ogImg = image || "https://errand.ng/og-cover.png";
    const canonical = url || (typeof window !== "undefined" ? window.location.href : "https://errand.ng");

    document.title = title ? `${title} · Errand` : base;

    const setMeta = (attr, attrVal, content) => {
      let el = document.querySelector(`meta[${attr}="${attrVal}"]`);
      if (!el) { el = document.createElement("meta"); el.setAttribute(attr, attrVal); document.head.appendChild(el); }
      el.content = content;
    };
    const setLink = (rel, href) => {
      let el = document.querySelector(`link[rel="${rel}"]`);
      if (!el) { el = document.createElement("link"); el.rel = rel; document.head.appendChild(el); }
      el.href = href;
    };

    // Standard
    setMeta("name", "description", desc);
    setMeta("name", "keywords", `errand, ${cityName.toLowerCase()} delivery, personal shopper, groceries, food delivery, nigeria ecommerce`);
    setMeta("name", "author", "Errand Technologies");
    setMeta("name", "theme-color", "#FF5720");
    setMeta("name", "mobile-web-app-capable", "yes");
    setMeta("name", "apple-mobile-web-app-capable", "yes");
    setMeta("name", "apple-mobile-web-app-status-bar-style", "black-translucent");
    setMeta("name", "apple-mobile-web-app-title", "Errand");

    // Open Graph
    setMeta("property", "og:type", "website");
    setMeta("property", "og:site_name", "Errand");
    setMeta("property", "og:title", title ? `${title} · Errand` : base);
    setMeta("property", "og:description", desc);
    setMeta("property", "og:image", ogImg);
    setMeta("property", "og:image:width", "1200");
    setMeta("property", "og:image:height", "630");
    setMeta("property", "og:image:alt", `Errand — ${cityName} delivery app`);
    setMeta("property", "og:url", canonical);
    setMeta("property", "og:locale", "en_NG");

    // Twitter / X
    setMeta("name", "twitter:card", "summary_large_image");
    setMeta("name", "twitter:site", "@errandng");
    setMeta("name", "twitter:creator", "@errandng");
    setMeta("name", "twitter:title", title ? `${title} · Errand` : base);
    setMeta("name", "twitter:description", desc);
    setMeta("name", "twitter:image", ogImg);
    setMeta("name", "twitter:image:alt", `Errand — ${cityName} delivery app`);

    // Canonical
    setLink("canonical", canonical);

    // Viewport
    let vp = document.querySelector('meta[name="viewport"]');
    if (!vp) { vp = document.createElement("meta"); vp.name = "viewport"; document.head.appendChild(vp); }
    vp.content = "width=device-width,initial-scale=1,viewport-fit=cover";

    // JSON-LD structured data
    const ldId = "__errand_ld";
    let ld = document.getElementById(ldId);
    if (!ld) { ld = document.createElement("script"); ld.id = ldId; ld.type = "application/ld+json"; document.head.appendChild(ld); }
    ld.textContent = JSON.stringify({
      "@context": "https://schema.org",
      "@type": "WebApplication",
      "name": "Errand",
      "url": "https://errand.ng",
      "description": desc,
      "applicationCategory": "ShoppingApplication",
      "operatingSystem": "Web, Android, iOS",
      "offers": { "@type": "Offer", "price": "0", "priceCurrency": "NGN" },
      "areaServed": { "@type": "City", "name": cityName, "addressCountry": "NG" },
      "aggregateRating": { "@type": "AggregateRating", "ratingValue": "4.8", "reviewCount": "2340" },
    });
  }, [title, description, image, url, cityData?.name]);
}

// ── Enhanced Splash ───────────────────────────────────────────
function EnhancedSplash({ C, onDone }) {
  const [phase, setPhase] = useState(0); // 0=logo, 1=ring, 2=tagline

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 300);
    const t2 = setTimeout(() => setPhase(2), 700);
    // Auto-advance to auth after splash animation completes
    const t3 = setTimeout(() => { if (onDone) onDone(); }, 2000);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, []);

  return (
    <div style={{
      position: "fixed", inset: 0,
      background: `linear-gradient(160deg, #06060F 0%, #0D0A1A 50%, #100812 100%)`,
      display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      overflow: "hidden",
      cursor: "pointer",
    }} onClick={() => { if (onDone) onDone(); }}>
      {/* Ambient radial glow */}
      <div style={{ position: "absolute", top: "30%", left: "50%", transform: "translateX(-50%)", width: 320, height: 320, borderRadius: "50%", background: `radial-gradient(circle, ${C.accent}22 0%, transparent 70%)`, pointerEvents: "none", animation: phase >= 1 ? "pulseGlow 2.4s ease-in-out infinite" : "none" }} />

      {/* Logo mark */}
      <div style={{
        transform: phase === 0 ? "scale(.72) translateY(8px)" : "scale(1) translateY(0)",
        opacity: phase === 0 ? 0 : 1,
        transition: "transform 360ms cubic-bezier(.34,1.56,.64,1), opacity 280ms ease",
      }}>
        <div style={{
          width: 96, height: 96, borderRadius: 28,
          background: `linear-gradient(145deg, ${C.accent}, #FF9500)`,
          display: "flex", alignItems: "center", justifyContent: "center",
          boxShadow: `0 20px 60px ${C.accent}60, 0 0 0 1px rgba(255,255,255,.12) inset`,
        }}>
          <svg width="52" height="52" viewBox="0 0 52 52" fill="none">
            <path d="M12 40 L20 16 L32 28 L40 14" stroke="#fff" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"/>
            <circle cx="40" cy="14" r="5" fill="#fff" opacity=".9"/>
            <circle cx="12" cy="40" r="4" fill="#fff" opacity=".6"/>
          </svg>
        </div>
      </div>

      {/* Brand name */}
      <div style={{
        marginTop: 20,
        opacity: phase >= 2 ? 1 : 0,
        transform: phase >= 2 ? "translateY(0)" : "translateY(8px)",
        transition: "opacity 320ms ease 120ms, transform 320ms cubic-bezier(.34,1.56,.64,1) 120ms",
      }}>
        <div className="disp" style={{ fontSize: 34, color: "#fff", letterSpacing: "-0.05em", textAlign: "center" }}>errand</div>
      </div>

      {/* Subtle loading bar */}
      <div style={{
        position: "absolute", bottom: 48, left: "50%", transform: "translateX(-50%)",
        width: 48, height: 3, borderRadius: 2,
        background: "rgba(255,255,255,.1)",
        overflow: "hidden",
        opacity: phase >= 1 ? 1 : 0,
        transition: "opacity 300ms ease",
      }}>
        <div style={{
          height: "100%", borderRadius: 2,
          background: `linear-gradient(90deg, ${C.accent}, #FF9500)`,
          animation: "loadBar 1.6s ease-in-out infinite",
        }} />
      </div>
    </div>
  );
}


function OfflineBanner() {
  const [offline, setOffline] = useState(false);
  useEffect(() => {
    const on = () => setOffline(false), off = () => setOffline(true);
    window.addEventListener("online", on); window.addEventListener("offline", off);
    return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
  }, []);
  if (!offline) return null;
  return (
    <div style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 9800, background: "#EF4444", padding: "10px 20px", display: "flex", alignItems: "center", gap: 9, justifyContent: "center", fontFamily: "Satoshi,system-ui,sans-serif" }}>
      <span style={{ fontSize: 16 }}>📡</span>
      <span style={{ color: "#fff", fontSize: 13, fontWeight: 600 }}>No internet — some features may be unavailable</span>
    </div>
  );
}

