// ── PromoCode engine ──────────────────────────────────────────
const PROMO_CODES = {
  "ERRAND20":  { type: "pct",   value: 20,   min: 5000,  desc: "20% off orders over ₦5k",        exp: "2026-06-30" },
  "FIRSTBUY":  { type: "flat",  value: 1500, min: 3000,  desc: "₦1,500 off your first order",    exp: "2026-12-31" },
  "FLASH50":   { type: "pct",   value: 50,   min: 8000,  desc: "50% off — flash sale!",           exp: "2026-03-09" },
  "LOYAL500":  { type: "flat",  value: 500,  min: 0,     desc: "₦500 loyalty credit",            exp: "2026-12-31" },
  "PASS30":    { type: "pct",   value: 30,   min: 0,     desc: "30% off with Errand Pass",        exp: "2026-12-31" },
};

function applyPromo(code, subtotal) {
  const p = PROMO_CODES[code?.toUpperCase()?.trim()];
  if (!p) return { valid: false, msg: "Invalid promo code" };
  if (subtotal < p.min) return { valid: false, msg: `Minimum order ₦${p.min.toLocaleString()} required` };
  const discount = p.type === "pct" ? Math.round(subtotal * p.value / 100) : p.value;
  return { valid: true, discount, desc: p.desc, code: code.toUpperCase() };
}

