// ── useAddressBook ────────────────────────────────────────────
function useAddressBook() {
  const [addresses, setAddresses] = useState([
    { id:1, label:"🏠 Home",   address:"14 Admiralty Way, Lekki Phase 1", area:"Lekki",         lat:6.4281, lng:3.4219, default:true  },
    { id:2, label:"🏢 Office", address:"Plot 1684 Sanusi Fafunwa St",     area:"Victoria Island", lat:6.4281, lng:3.4219, default:false },
  ]);
  const add    = (addr) => setAddresses(a => [...a, { ...addr, id: Date.now() }]);
  const remove = (id)   => setAddresses(a => a.filter(x => x.id !== id));
  const setDef = (id)   => setAddresses(a => a.map(x => ({ ...x, default: x.id===id })));
  return { addresses, add, remove, setDef };
}

// ── StoreLocator (full screen with SVG map) ───────────────────
function StoreLocator({ goTo, C }) {
  const toast = useToast();
  const [selected, setSelected] = useState(null);
  const [filter, setFilter] = useState("all");

  // Relative positions on our SVG canvas (400×320)
  const STORE_PINS = [
    { id:1, name:"FoodMart VI",      emoji:"🛒", area:"Victoria Island", x:200, y:140, open:true,  eta:"25 min", dist:"1.2 km"  },
    { id:2, name:"GlowStore Lekki",  emoji:"💄", area:"Lekki",           x:280, y:180, open:true,  eta:"35 min", dist:"2.8 km"  },
    { id:3, name:"TechHub Island",   emoji:"📱", area:"Victoria Island", x:160, y:160, open:true,  eta:"20 min", dist:"0.9 km"  },
    { id:4, name:"FreshFarm Ajah",   emoji:"🌿", area:"Ajah",            x:340, y:220, open:false, eta:"55 min", dist:"5.1 km"  },
    { id:5, name:"HomeNest Ikoyi",   emoji:"🛋️", area:"Ikoyi",           x:130, y:110, open:true,  eta:"40 min", dist:"3.4 km"  },
    { id:6, name:"FoodMart Lekki",   emoji:"🛒", area:"Lekki",           x:310, y:155, open:true,  eta:"30 min", dist:"2.1 km"  },
  ];

  const ZONES = [
    { name:"Victoria Island", color:"rgba(255,87,32,.15)", cx:195, cy:148, rx:70, ry:50 },
    { name:"Lekki",           color:"rgba(0,214,122,.12)", cx:295, cy:175, rx:65, ry:45 },
    { name:"Ikoyi",           color:"rgba(139,92,246,.12)",cx:130, cy:112, rx:55, ry:40 },
  ];

  const FILTERS = ["all","Groceries","Beauty","Tech","Organic","Home"];
  const CAT_MAP  = { "🛒":"Groceries","💄":"Beauty","📱":"Tech","🌿":"Organic","🛋️":"Home" };

  const filtered = filter === "all" ? STORE_PINS : STORE_PINS.filter(s => CAT_MAP[s.emoji] === filter);

  return (
    <div className="screen" style={{ background:C.bg, paddingBottom:80 }}>
      <div style={{ padding:"52px 20px 12px", display:"flex", gap:12, alignItems:"center" }}>
        <Back onClick={() => goTo("stores")} C={C} />
        <div>
          <div className="disp" style={{ fontSize:20, color:C.text }}>Store Locator</div>
          <div style={{ color:C.sub, fontSize:12, marginTop:2 }}>Lagos delivery zones</div>
        </div>
      </div>

      {/* Category filter */}
      <div className="hrow" style={{ padding:"0 20px 12px" }}>
        {FILTERS.map(f => (
          <button key={f} onClick={() => setFilter(f)} style={{ padding:"6px 14px", borderRadius:20, border:"none", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:12.5, cursor:"pointer", background:filter===f?C.accent:C.card, color:filter===f?"#fff":C.sub, flexShrink:0, transition:"all .15s", whiteSpace:"nowrap" }}>{f}</button>
        ))}
      </div>

      {/* SVG Map */}
      <div style={{ margin:"0 20px 14px", background:C.card, border:`1px solid ${C.border}`, borderRadius:16, overflow:"hidden" }}>
        <svg viewBox="0 0 400 280" style={{ width:"100%", display:"block" }}>
          {/* Ocean background */}
          <rect width="400" height="280" fill={C.dark?"#0d1117":"#EEF4FF"} />

          {/* Road grid */}
          {[60,120,180,240].map(x => <line key={x} x1={x} y1="0" x2={x} y2="280" stroke={C.dark?"#1a2030":"#D8E4F0"} strokeWidth="1" />)}
          {[56,112,168,224].map(y => <line key={y} x1="0" y1={y} x2="400" y2={y} stroke={C.dark?"#1a2030":"#D8E4F0"} strokeWidth="1" />)}

          {/* Lagos coastline (simplified) */}
          <path d="M0,250 Q60,240 120,250 Q180,260 240,245 Q300,235 400,248 L400,280 L0,280Z" fill={C.dark?"#0a1628":"#B8D4F0"} opacity="0.8" />

          {/* Delivery zones */}
          {ZONES.map(z => (
            <ellipse key={z.name} cx={z.cx} cy={z.cy} rx={z.rx} ry={z.ry} fill={z.color} stroke="none" />
          ))}

          {/* Zone labels */}
          {ZONES.map(z => (
            <text key={z.name} x={z.cx} y={z.cy-z.ry-6} textAnchor="middle" fontSize="9" fill={C.muted} fontFamily="Satoshi,system-ui,sans-serif">{z.name}</text>
          ))}

          {/* User location */}
          <circle cx="200" cy="155" r="7" fill={C.accent} opacity="0.25" />
          <circle cx="200" cy="155" r="4" fill={C.accent} />
          <circle cx="200" cy="155" r="2" fill="#fff" />

          {/* Store pins */}
          {filtered.map(s => {
            const isSel = selected?.id === s.id;
            return (
              <g key={s.id} onClick={() => setSelected(isSel ? null : s)} style={{ cursor:"pointer" }}>
                <circle cx={s.x} cy={s.y} r={isSel?16:12} fill={s.open?(isSel?C.accent:C.card):C.muted} stroke={isSel?C.accent:C.border} strokeWidth={isSel?2:1} />
                <text x={s.x} y={s.y+5} textAnchor="middle" fontSize="12">{s.emoji}</text>
                {isSel && <text x={s.x} y={s.y-22} textAnchor="middle" fontSize="8.5" fill={C.text} fontFamily="Satoshi,system-ui,sans-serif" fontWeight="700">{s.name}</text>}
              </g>
            );
          })}
        </svg>

        {/* Legend */}
        <div style={{ padding:"10px 14px", borderTop:`1px solid ${C.border}`, display:"flex", gap:16, alignItems:"center" }}>
          <div style={{ display:"flex", alignItems:"center", gap:6 }}>
            <div style={{ width:10, height:10, borderRadius:"50%", background:C.accent }} />
            <span style={{ fontSize:11, color:C.muted }}>You</span>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:6 }}>
            <div style={{ width:10, height:10, borderRadius:"50%", background:C.card, border:`1px solid ${C.border}` }} />
            <span style={{ fontSize:11, color:C.muted }}>Open store</span>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:6 }}>
            <div style={{ width:10, height:10, borderRadius:"50%", background:C.muted }} />
            <span style={{ fontSize:11, color:C.muted }}>Closed</span>
          </div>
        </div>
      </div>

      {/* Selected store card */}
      {selected && (
        <div style={{ margin:"0 20px 14px", background:C.card, border:`1.5px solid ${C.accent}`, borderRadius:14, padding:"14px 15px", animation:"up .2s ease" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:10 }}>
            <div style={{ display:"flex", gap:10 }}>
              <div style={{ width:42, height:42, borderRadius:12, background:C.surface, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22 }}>{selected.emoji}</div>
              <div>
                <div className="disp" style={{ fontSize:15, color:C.text }}>{selected.name}</div>
                <div style={{ color:C.sub, fontSize:12, marginTop:2 }}>{selected.area} · {selected.dist} away</div>
              </div>
            </div>
            <div style={{ fontSize:11, fontWeight:700, color:selected.open?C.green:"#EF4444", background:selected.open?C.greenBg:"rgba(239,68,68,.1)", padding:"3px 9px", borderRadius:7 }}>{selected.open?"Open":"Closed"}</div>
          </div>
          <div style={{ display:"flex", gap:8 }}>
            {[["⏱️","ETA",selected.eta],["📍","Distance",selected.dist],["🛵","Shoppers","3 online"]].map(([ic,l,v]) => (
              <div key={l} style={{ flex:1, background:C.surface, borderRadius:9, padding:"8px", textAlign:"center" }}>
                <div style={{ fontSize:14 }}>{ic}</div>
                <div style={{ color:C.muted, fontSize:10, marginTop:1 }}>{l}</div>
                <div style={{ fontWeight:600, color:C.text, fontSize:12, marginTop:1 }}>{v}</div>
              </div>
            ))}
          </div>
          {selected.open && <Btn C={C} block style={{ marginTop:12 }} onClick={() => { toast(`Opening ${selected.name}…`,"🛒"); goTo("stores"); }}>Shop here →</Btn>}
        </div>
      )}

      {/* Store list */}
      <div style={{ padding:"0 20px", display:"flex", flexDirection:"column", gap:8 }}>
        <div style={{ color:C.muted, fontSize:11, fontWeight:700, letterSpacing:1, marginBottom:4 }}>NEARBY STORES ({filtered.length})</div>
        {filtered.map(s => (
          <div key={s.id} onClick={() => setSelected(selected?.id===s.id?null:s)} className="tap" style={{ background:C.card, border:`1px solid ${selected?.id===s.id?C.accent:C.border}`, borderRadius:13, padding:"11px 13px", display:"flex", alignItems:"center", gap:11, cursor:"pointer" }}>
            <div style={{ fontSize:22 }}>{s.emoji}</div>
            <div style={{ flex:1 }}>
              <div style={{ fontWeight:500, fontSize:13.5, color:C.text }}>{s.name}</div>
              <div style={{ color:C.muted, fontSize:12, marginTop:1 }}>{s.dist} · ETA {s.eta}</div>
            </div>
            <div style={{ fontSize:10, fontWeight:700, color:s.open?C.green:"#EF4444" }}>{s.open?"●":"○"}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── AddressBook screen ────────────────────────────────────────
function AddressBook({ goTo, C }) {
  const toast = useToast();
  const { addresses, add, remove, setDef } = useAddressBook();
  const [adding, setAdding] = useState(false);
  const [draft, setDraft] = useState({ label:"", address:"", area:"" });

  const LABELS = ["🏠 Home","🏢 Office","❤️ Partner's","👪 Parents'","📍 Other"];

  const submit = () => {
    if (!draft.address) return;
    add({ ...draft, label: draft.label || "📍 Address" });
    setDraft({ label:"", address:"", area:"" });
    setAdding(false);
    toast("Address saved ✓","📍","success");
  };

  return (
    <div className="screen" style={{ background:C.bg, paddingBottom:80 }}>
      <div style={{ padding:"52px 20px 14px", display:"flex", gap:12, alignItems:"center" }}>
        <Back onClick={() => goTo("profile")} C={C} />
        <div style={{ flex:1 }}>
          <div className="disp" style={{ fontSize:20, color:C.text }}>Address Book</div>
          <div style={{ color:C.sub, fontSize:12, marginTop:2 }}>{addresses.length} saved addresses</div>
        </div>
        <Btn C={C} sm onClick={() => setAdding(true)}>+ Add</Btn>
      </div>

      <div style={{ padding:"0 20px", display:"flex", flexDirection:"column", gap:10 }}>
        {adding && (
          <div style={{ background:C.card, border:`1.5px solid ${C.accent}`, borderRadius:14, padding:"14px 15px", animation:"up .2s ease" }}>
            <div className="disp" style={{ fontSize:14, color:C.text, marginBottom:12 }}>New address</div>
            <div style={{ display:"flex", gap:7, flexWrap:"wrap", marginBottom:11 }}>
              {LABELS.map(l => (
                <button key={l} onClick={() => setDraft(d=>({...d,label:l}))} style={{ padding:"6px 12px", borderRadius:20, border:`1.5px solid ${draft.label===l?C.accent:C.border}`, background:draft.label===l?C.accentBg:"transparent", color:draft.label===l?C.accent:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer" }}>{l}</button>
              ))}
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:9 }}>
              <Input C={C} placeholder="Street address" value={draft.address} onChange={e => setDraft(d=>({...d,address:e.target.value}))} />
              <Input C={C} placeholder="Area (e.g. Lekki Phase 1)" value={draft.area} onChange={e => setDraft(d=>({...d,area:e.target.value}))} />
            </div>
            <div style={{ display:"flex", gap:8, marginTop:12 }}>
              <Btn C={C} block onClick={submit}>Save address</Btn>
              <button onClick={() => setAdding(false)} style={{ padding:"11px 16px", background:"transparent", border:`1px solid ${C.border}`, borderRadius:12, color:C.sub, cursor:"pointer", fontFamily: "Satoshi,system-ui,sans-serif" }}>Cancel</button>
            </div>
          </div>
        )}

        {addresses.map(addr => (
          <div key={addr.id} style={{ background:C.card, border:`1.5px solid ${addr.default?C.accent:C.border}`, borderRadius:14, padding:"14px 15px" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:8 }}>
              <div>
                <div style={{ display:"flex", alignItems:"center", gap:7, marginBottom:3 }}>
                  <div className="disp" style={{ fontSize:14, color:C.text }}>{addr.label}</div>
                  {addr.default && <div style={{ background:C.accentBg, color:C.accent, fontSize:10, fontWeight:700, padding:"2px 7px", borderRadius:5 }}>DEFAULT</div>}
                </div>
                <div style={{ color:C.sub, fontSize:13, lineHeight:1.4 }}>{addr.address}</div>
                <div style={{ color:C.muted, fontSize:12, marginTop:2 }}>{addr.area}</div>
              </div>
            </div>
            <div style={{ display:"flex", gap:7 }}>
              {!addr.default && <button onClick={() => setDef(addr.id)} style={{ flex:1, padding:"8px", background:"transparent", border:`1px solid ${C.border}`, borderRadius:9, color:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer" }}>Set default</button>}
              <button onClick={() => toast("Address updated","✏️")} style={{ flex:1, padding:"8px", background:"transparent", border:`1px solid ${C.border}`, borderRadius:9, color:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer" }}>Edit</button>
              <button onClick={() => { remove(addr.id); toast("Address removed","🗑️"); }} style={{ flex:1, padding:"8px", background:"transparent", border:`1px solid #EF444433`, borderRadius:9, color:"#EF4444", fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer" }}>Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════
//  LIVE CHAT & SUPPORT
//  In-app chat · AI support bot · Escalation to human agent
// ═══════════════════════════════════════════════════════════════

// ── SupportChat ───────────────────────────────────────────────
function SupportChat({ goTo, C }) {
  const toast = useToast();
  const [mode, setMode] = useState("menu"); // menu | bot | human | ticket
  const [messages, setMessages] = useState([
    { id:1, from:"bot", text:"Hi John! 👋 I'm Emi, your Errand support assistant. How can I help you today?", ts:"Just now" },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [humanQueue, setHumanQueue] = useState(false);
  const [humanConnected, setHumanConnected] = useState(false);
  const [ticketForm, setTicketForm] = useState({ subject:"", body:"", category:"order" });
  const [ticketSent, setTicketSent] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior:"smooth" }); }, [messages]);

  const QUICK_REPLIES = [
    "Where's my order?",
    "I want a refund",
    "Wrong item delivered",
    "How do I use promo codes?",
    "Talk to a human",
  ];

  const sendMessage = async (text) => {
    const userMsg = text || input.trim();
    if (!userMsg) return;
    setInput("");

    const newMsgs = [...messages, { id: Date.now(), from:"user", text: userMsg, ts:"Just now" }];
    setMessages(newMsgs);

    if (userMsg.toLowerCase().includes("human") || userMsg.toLowerCase().includes("agent")) {
      setTimeout(() => {
        setMessages(m => [...m, { id:Date.now()+1, from:"bot", text:"Connecting you to a live agent now. Average wait time: 2 minutes 🧑‍💼", ts:"Just now" }]);
        setHumanQueue(true);
        setTimeout(() => {
          setHumanConnected(true);
          setMessages(m => [...m, { id:Date.now()+2, from:"agent", text:"Hi John, this is Chioma from Errand support! I can see your recent orders. What's the issue today? 😊", ts:"Just now", name:"Chioma A." }]);
        }, 2500);
      }, 800);
      return;
    }

    setLoading(true);
    try {
      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{ "Content-Type":"application/json" },
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:300,
          system:`You are Emi, a friendly Nigerian customer support AI for "Errand" — a Lagos delivery app. Be concise (max 2 sentences), warm, and use Nigerian context where relevant. If asked about orders, mention order tracking. If asked about refunds, explain the 24h policy. Always end with a helpful follow-up question or offer. Use light emojis.`,
          messages: newMsgs.filter(m=>m.from!=="bot"&&m.from!=="agent").map(m => ({ role:"user", content:m.text }))
        })
      });
      const data = await resp.json();
      const reply = data.content?.map(b=>b.text||"").join("") || "Let me look into that for you! Can you share your order number?";
      setMessages(m => [...m, { id:Date.now()+1, from:"bot", text:reply, ts:"Just now" }]);
    } catch {
      setMessages(m => [...m, { id:Date.now()+1, from:"bot", text:"I'm having trouble connecting right now. Would you like me to connect you to a human agent instead? 🙏", ts:"Just now" }]);
    }
    setLoading(false);
  };

  const Avatar = ({ from, name }) => {
    if (from === "user") return <div style={{ width:30, height:30, borderRadius:"50%", background:C.accent, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14, flexShrink:0 }}>😊</div>;
    if (from === "agent") return <div style={{ width:30, height:30, borderRadius:"50%", background:"#8B5CF6", display:"flex", alignItems:"center", justifyContent:"center", fontSize:14, flexShrink:0 }}>👩🏾</div>;
    return <div style={{ width:30, height:30, borderRadius:"50%", background:C.accentBg, border:`1px solid ${C.accentLine}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14, flexShrink:0 }}>🤖</div>;
  };

  if (mode === "ticket") return (
    <div className="screen" style={{ background:C.bg, paddingBottom:80 }}>
      <div style={{ padding:"52px 20px 14px", display:"flex", gap:12, alignItems:"center" }}>
        <Back onClick={() => setMode("menu")} C={C} />
        <div className="disp" style={{ fontSize:20, color:C.text }}>Submit a Ticket</div>
      </div>
      {ticketSent ? (
        <div style={{ padding:"40px 32px", textAlign:"center" }}>
          <div style={{ fontSize:52, marginBottom:16 }}>✅</div>
          <div className="disp" style={{ fontSize:20, color:C.text, marginBottom:8 }}>Ticket submitted!</div>
          <div style={{ color:C.sub, fontSize:14, lineHeight:1.65, marginBottom:24 }}>We'll respond within 2 hours. Check your notifications for updates.</div>
          <div style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:13, padding:"12px 16px", display:"inline-flex", gap:10, alignItems:"center" }}>
            <span style={{ fontSize:18 }}>🎫</span>
            <span style={{ color:C.sub, fontSize:13 }}>Ticket #T-{Math.floor(Math.random()*9000+1000)}</span>
          </div>
          <div style={{ marginTop:24 }}>
            <Btn C={C} block onClick={() => goTo("help")}>Back to Help</Btn>
          </div>
        </div>
      ) : (
        <div style={{ padding:"0 20px", display:"flex", flexDirection:"column", gap:12 }}>
          <div style={{ display:"flex", gap:7, flexWrap:"wrap" }}>
            {[["order","📦 Order"],["payment","💳 Payment"],["shopper","🛵 Shopper"],["account","👤 Account"],["other","💬 Other"]].map(([id,l]) => (
              <button key={id} onClick={() => setTicketForm(t=>({...t,category:id}))} style={{ padding:"7px 13px", borderRadius:20, border:`1.5px solid ${ticketForm.category===id?C.accent:C.border}`, background:ticketForm.category===id?C.accentBg:"transparent", color:ticketForm.category===id?C.accent:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer" }}>{l}</button>
            ))}
          </div>
          <Input C={C} placeholder="Subject — e.g. Wrong item in order #1021" value={ticketForm.subject} onChange={e => setTicketForm(t=>({...t,subject:e.target.value}))} />
          <Input C={C} placeholder="Describe your issue in detail…" value={ticketForm.body} onChange={e => setTicketForm(t=>({...t,body:e.target.value}))} rows={5} />
          <Btn C={C} block onClick={() => { if (!ticketForm.subject) { toast("Please add a subject","❌","error"); return; } setTicketSent(true); }} style={{ padding:"14px" }}>Submit ticket</Btn>
        </div>
      )}
    </div>
  );

  return (
    <div className="screen" style={{ background:C.bg, display:"flex", flexDirection:"column" }}>
      {/* Header */}
      <div style={{ padding:"52px 20px 12px", borderBottom:`1px solid ${C.border}`, flexShrink:0 }}>
        <div style={{ display:"flex", gap:12, alignItems:"center", marginBottom: mode==="bot"||mode==="human" ? 8 : 0 }}>
          <Back onClick={() => mode==="menu" ? goTo("help") : setMode("menu")} C={C} />
          <div style={{ flex:1 }}>
            <div className="disp" style={{ fontSize:18, color:C.text }}>
              {mode==="menu" ? "Support" : mode==="bot" ? "Emi — AI Assistant" : mode==="human" ? "Live Support" : "New Ticket"}
            </div>
            {(mode==="bot"||mode==="human") && (
              <div style={{ display:"flex", alignItems:"center", gap:5, marginTop:2 }}>
                <div style={{ width:7, height:7, borderRadius:"50%", background:C.green, animation:"blink 1.4s ease-in-out infinite" }} />
                <span style={{ color:C.green, fontSize:11, fontWeight:600 }}>
                  {mode==="human" ? (humanConnected?"Connected · Chioma A.":"In queue · ~2 min wait") : "Online · Replies in seconds"}
                </span>
              </div>
            )}
          </div>
          {(mode==="bot"||mode==="human") && (
            <button onClick={() => setMode("ticket")} style={{ background:"none", border:`1px solid ${C.border}`, borderRadius:9, padding:"5px 11px", color:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12, cursor:"pointer" }}>🎫 Ticket</button>
          )}
        </div>
      </div>

      {/* Menu */}
      {mode === "menu" && (
        <div style={{ flex:1, overflowY:"auto", padding:"16px 20px", display:"flex", flexDirection:"column", gap:12 }}>
          {/* Support options */}
          {[
            { icon:"🤖", title:"AI Assistant (Emi)", sub:"Get instant answers — available 24/7", mode:"bot",   color:C.accentBg,  border:C.accentLine },
            { icon:"🧑‍💼", title:"Live Agent",        sub:"Talk to a real person · 8am–10pm daily",mode:"human", color:C.greenBg,   border:C.green+"44" },
            { icon:"🎫", title:"Submit a Ticket",    sub:"For non-urgent issues · Reply in 2h",  mode:"ticket",color:C.card,       border:C.border      },
          ].map(opt => (
            <div key={opt.mode} onClick={() => { setMode(opt.mode); if(opt.mode==="human"){ setMessages([{ id:1, from:"bot", text:"Let me connect you to a live agent. While you wait, can you describe your issue?", ts:"Just now" }]); } }} className="tap" style={{ background:opt.color, border:`1.5px solid ${opt.border}`, borderRadius:16, padding:"16px", cursor:"pointer" }}>
              <div style={{ display:"flex", gap:12, alignItems:"center" }}>
                <div style={{ fontSize:28 }}>{opt.icon}</div>
                <div>
                  <div style={{ fontWeight:700, fontSize:15, color:C.text }}>{opt.title}</div>
                  <div style={{ color:C.sub, fontSize:13, marginTop:2 }}>{opt.sub}</div>
                </div>
                <span style={{ marginLeft:"auto", color:C.muted, fontSize:18 }}>›</span>
              </div>
            </div>
          ))}

          {/* FAQ quick links */}
          <div style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:14, padding:"14px 15px" }}>
            <div className="disp" style={{ fontSize:14, color:C.text, marginBottom:10 }}>Common questions</div>
            {["How do I track my order?","When will I get my refund?","How do I change my delivery address?","Why was my order cancelled?"].map((q,i,arr) => (
              <div key={q} onClick={() => { setMode("bot"); sendMessage(q); }} className="tap" style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 0", borderBottom:i<arr.length-1?`1px solid ${C.border}`:"none", cursor:"pointer" }}>
                <span style={{ fontSize:13.5, color:C.text }}>{q}</span>
                <span style={{ color:C.muted }}>›</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Chat UI (bot or human) */}
      {(mode === "bot" || mode === "human") && (
        <>
          <div style={{ flex:1, overflowY:"auto", padding:"14px 20px", display:"flex", flexDirection:"column", gap:12 }}>
            {messages.map(msg => (
              <div key={msg.id} style={{ display:"flex", gap:9, flexDirection: msg.from==="user" ? "row-reverse" : "row", animation:"up .2s ease" }}>
                <Avatar from={msg.from} name={msg.name} />
                <div style={{ maxWidth:"75%" }}>
                  {msg.from==="agent" && <div style={{ color:"#8B5CF6", fontSize:11, fontWeight:600, marginBottom:3 }}>{msg.name}</div>}
                  <div style={{ background: msg.from==="user" ? C.accent : C.card, border: msg.from==="user" ? "none" : `1px solid ${C.border}`, borderRadius: msg.from==="user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px", padding:"11px 14px", color: msg.from==="user" ? "#fff" : C.text, fontSize:14, lineHeight:1.55 }}>
                    {msg.text}
                  </div>
                  <div style={{ color:C.muted, fontSize:10, marginTop:3, textAlign: msg.from==="user"?"right":"left" }}>{msg.ts}</div>
                </div>
              </div>
            ))}

            {loading && (
              <div style={{ display:"flex", gap:9 }}>
                <div style={{ width:30, height:30, borderRadius:"50%", background:C.accentBg, display:"flex", alignItems:"center", justifyContent:"center" }}>🤖</div>
                <div style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:"18px 18px 18px 4px", padding:"11px 16px" }}>
                  <div style={{ display:"flex", gap:4, alignItems:"center" }}>
                    {[0,1,2].map(i => <div key={i} style={{ width:6, height:6, borderRadius:"50%", background:C.muted, animation:`blink 1.4s ease-in-out infinite ${i*200}ms` }} />)}
                  </div>
                </div>
              </div>
            )}
            <div ref={endRef} />
          </div>

          {/* Quick replies */}
          {messages.length <= 2 && !loading && (
            <div className="hrow" style={{ padding:"0 20px 10px", flexShrink:0 }}>
              {QUICK_REPLIES.map(r => (
                <button key={r} onClick={() => sendMessage(r)} style={{ padding:"7px 13px", background:C.card, border:`1px solid ${C.border}`, borderRadius:20, color:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:"pointer", flexShrink:0, whiteSpace:"nowrap" }}>{r}</button>
              ))}
            </div>
          )}

          {/* Input bar */}
          <div style={{ padding:"10px 16px 28px", borderTop:`1px solid ${C.border}`, display:"flex", gap:10, background:C.surface, flexShrink:0 }}>
            <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key==="Enter"&&sendMessage()} placeholder="Type a message…" style={{ flex:1, background:C.card, border:`1.5px solid ${C.border}`, borderRadius:22, padding:"10px 16px", color:C.text, fontSize:14, outline:"none", fontFamily: "Satoshi,system-ui,sans-serif" }} onFocus={e=>e.target.style.borderColor=C.accent} onBlur={e=>e.target.style.borderColor=C.border} />
            <button onClick={() => sendMessage()} style={{ width:42, height:42, borderRadius:"50%", background: input.trim() ? C.accent : C.border, border:"none", display:"flex", alignItems:"center", justifyContent:"center", cursor: input.trim()?"pointer":"not-allowed", flexShrink:0, transition:"background .15s" }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none"><path d="M22 2L11 13M22 2L15 22L11 13M22 2L2 9L11 13" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
          </div>
        </>
      )}
    </div>
  );
}


