function AdvancedOrdering({ goTo, addToCart, C }) {
  const toast = useToast();
  const [tab, setTab] = useState('scheduled');

  // ── Scheduled Delivery ──────────────────────────────────────
  const [schedDate, setSchedDate] = useState('');
  const [schedTime, setSchedTime] = useState('09:00');
  const [schedNote, setSchedNote] = useState('');
  const [scheduled, setScheduled] = useState([
    { id:1, label:'Weekly groceries', date:'Sat 15 Mar', time:'10:00 AM', items:8, total:18400, status:'upcoming' },
    { id:2, label:'Office snacks',    date:'Mon 17 Mar', time:'08:30 AM', items:5, total:7200,  status:'upcoming' },
  ]);

  const TIME_SLOTS = ['07:00','08:00','09:00','10:00','11:00','12:00','14:00','16:00','18:00','20:00'];

  const addScheduled = () => {
    if (!schedDate) { toast('Pick a date first', '❌', 'error'); return; }
    const d = new Date(schedDate);
    const label = schedNote || 'Scheduled order';
    const dateStr = d.toLocaleDateString('en-NG', { weekday:'short', day:'numeric', month:'short' });
    setScheduled(s => [...s, { id: Date.now(), label, date: dateStr, time: schedTime, items: 3, total: 9600, status: 'upcoming' }]);
    setSchedDate(''); setSchedNote('');
    toast(`Delivery scheduled for ${dateStr} at ${schedTime} ✓`, '📅', 'success');
  };

  // ── Recurring Orders ────────────────────────────────────────
  const [recurring, setRecurring] = useState([
    { id:1, name:'Weekly Grocery Bundle', freq:'Every Monday', items:['🍅 Tomatoes','🍚 Rice 5kg','🥚 Eggs ×12','🍗 Chicken 1kg'], total:9600,  active:true,  next:'Mon 17 Mar' },
    { id:2, name:'Monthly Beauty Restock',freq:'1st of month',  items:['🧴 Vitamin C Serum','☀️ SPF 50'],                        total:13500, active:false, next:'Tue 1 Apr' },
  ]);
  const [addingRecurring, setAddingRecurring] = useState(false);
  const [rDraft, setRDraft] = useState({ name:'', freq:'weekly', items:'' });

  const FREQ_OPTS = [['daily','Every day'],['weekly','Every week'],['biweekly','Every 2 weeks'],['monthly','Every month']];

  const saveRecurring = () => {
    if (!rDraft.name) return;
    setRecurring(r => [...r, { id: Date.now(), name: rDraft.name, freq: FREQ_OPTS.find(f=>f[0]===rDraft.freq)?.[1]||'Weekly', items: rDraft.items.split(',').map(s=>s.trim()).filter(Boolean), total: 0, active: true, next: 'Mon 17 Mar' }]);
    setAddingRecurring(false); setRDraft({ name:'', freq:'weekly', items:'' });
    toast('Recurring order created ✓', '🔄', 'success');
  };

  // ── Bulk Orders ─────────────────────────────────────────────
  const [bulkItems, setBulkItems] = useState([
    { id:1, name:'Basmati Rice 5kg',    emoji:'🍚', unitPrice:3200, qty:10, unit:'bags'  },
    { id:2, name:'Mineral Water 750ml', emoji:'💧', unitPrice:200,  qty:48, unit:'bottles'},
    { id:3, name:'Plastic Cups ×50',    emoji:'🥤', unitPrice:800,  qty:20, unit:'packs' },
  ]);
  const [bulkNote, setBulkNote] = useState('');
  const bulkTotal = bulkItems.reduce((s,i) => s + i.unitPrice * i.qty, 0);
  const bulkDiscount = bulkTotal >= 50000 ? 0.1 : bulkTotal >= 20000 ? 0.05 : 0;

  const updateQty = (id, delta) => setBulkItems(items => items.map(i => i.id===id ? { ...i, qty: Math.max(1, i.qty+delta) } : i));

  return (
    <div className="screen" style={{ background: C.bg, paddingBottom: 80 }}>
      <div style={{ padding: '52px 20px 14px', display: 'flex', gap: 12, alignItems: 'center' }}>
        <Back onClick={() => goTo('home')} C={C} />
        <div>
          <div className="disp" style={{ fontSize: 20, color: C.text }}>Advanced Ordering</div>
          <div style={{ color: C.sub, fontSize: 12, marginTop: 2 }}>Schedule · Repeat · Bulk</div>
        </div>
      </div>

      <div className="hrow" style={{ padding: '0 20px 14px' }}>
        {[['scheduled','📅 Scheduled'],['recurring','🔄 Recurring'],['bulk','📦 Bulk']].map(([id,l]) => (
          <button key={id} onClick={() => setTab(id)} style={{ padding:'7px 16px', borderRadius:20, border:'none', fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:13, cursor:'pointer', background:tab===id?C.accent:C.card, color:tab===id?'#fff':C.sub, flexShrink:0, transition:'all .15s' }}>{l}</button>
        ))}
      </div>

      {/* ── Scheduled tab ── */}
      {tab === 'scheduled' && (
        <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 12 }}>
          {/* Picker */}
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 14, padding: '14px 15px' }}>
            <div className="disp" style={{ fontSize: 14, color: C.text, marginBottom: 12 }}>Schedule a delivery</div>
            <div style={{ display: 'flex', gap: 9, marginBottom: 10 }}>
              <div style={{ flex: 1 }}>
                <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, marginBottom: 5 }}>DATE</div>
                <input type="date" value={schedDate} onChange={e => setSchedDate(e.target.value)} min={new Date().toISOString().split('T')[0]} style={{ width: '100%', background: C.surface, border: `1.5px solid ${C.border}`, borderRadius: 10, padding: '9px 12px', color: C.text, fontSize: 13.5, outline: 'none', fontFamily: "Satoshi,system-ui,sans-serif" }} />
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, marginBottom: 5 }}>TIME SLOT</div>
                <select value={schedTime} onChange={e => setSchedTime(e.target.value)} style={{ width: '100%', background: C.surface, border: `1.5px solid ${C.border}`, borderRadius: 10, padding: '9px 12px', color: C.text, fontSize: 13.5, outline: 'none', fontFamily: "Satoshi,system-ui,sans-serif" }}>
                  {TIME_SLOTS.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
            </div>
            <Input C={C} placeholder="Label (e.g. 'Weekly groceries')" value={schedNote} onChange={e => setSchedNote(e.target.value)} style={{ marginBottom: 11 }} />
            <Btn C={C} block onClick={addScheduled}>📅 Schedule this delivery</Btn>
          </div>

          {/* Upcoming */}
          <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, letterSpacing: 1 }}>UPCOMING DELIVERIES</div>
          {scheduled.map(s => (
            <div key={s.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 13, padding: '12px 14px', display: 'flex', gap: 12, alignItems: 'center' }}>
              <div style={{ width: 42, height: 42, borderRadius: 12, background: C.accentBg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>📅</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: C.text }}>{s.label}</div>
                <div style={{ color: C.sub, fontSize: 12, marginTop: 2 }}>{s.date} at {s.time} · {s.items} items</div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div className="disp" style={{ fontSize: 13, color: C.text }}>₦{s.total.toLocaleString()}</div>
                <button onClick={() => { setScheduled(x => x.filter(r => r.id !== s.id)); toast('Delivery cancelled','🗑️'); }} style={{ background:'none', border:'none', color:'#EF4444', fontSize:12, cursor:'pointer', fontFamily: "Satoshi,system-ui,sans-serif", marginTop:3 }}>Cancel</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── Recurring tab ── */}
      {tab === 'recurring' && (
        <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 11 }}>
          {addingRecurring ? (
            <div style={{ background: C.card, border: `1.5px solid ${C.accent}`, borderRadius: 14, padding: '14px 15px', animation: 'up .2s ease' }}>
              <div className="disp" style={{ fontSize: 14, color: C.text, marginBottom: 12 }}>New recurring order</div>
              <Input C={C} placeholder="Name (e.g. Weekly Groceries)" value={rDraft.name} onChange={e => setRDraft(d=>({...d,name:e.target.value}))} style={{ marginBottom: 10 }} />
              <div style={{ marginBottom: 10 }}>
                <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, marginBottom: 6 }}>FREQUENCY</div>
                <div style={{ display: 'flex', gap: 7, flexWrap: 'wrap' }}>
                  {FREQ_OPTS.map(([id,l]) => (
                    <button key={id} onClick={() => setRDraft(d=>({...d,freq:id}))} style={{ padding:'6px 13px', borderRadius:20, border:`1.5px solid ${rDraft.freq===id?C.accent:C.border}`, background:rDraft.freq===id?C.accentBg:'transparent', color:rDraft.freq===id?C.accent:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize:12.5, cursor:'pointer' }}>{l}</button>
                  ))}
                </div>
              </div>
              <Input C={C} placeholder="Items (comma separated)" value={rDraft.items} onChange={e => setRDraft(d=>({...d,items:e.target.value}))} style={{ marginBottom: 12 }} />
              <div style={{ display:'flex', gap:8 }}>
                <Btn C={C} block onClick={saveRecurring}>Create</Btn>
                <button onClick={() => setAddingRecurring(false)} style={{ padding:'11px 16px', background:'transparent', border:`1px solid ${C.border}`, borderRadius:12, color:C.sub, cursor:'pointer', fontFamily: "Satoshi,system-ui,sans-serif" }}>Cancel</button>
              </div>
            </div>
          ) : (
            <button onClick={() => setAddingRecurring(true)} style={{ width:'100%', padding:'13px', background:'transparent', border:`1.5px dashed ${C.border}`, borderRadius:13, color:C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:14, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
              <span style={{ fontSize:20 }}>+</span> Add recurring order
            </button>
          )}

          {recurring.map(r => (
            <div key={r.id} style={{ background: C.card, border: `1.5px solid ${r.active ? C.green+'33' : C.border}`, borderRadius: 14, padding: '13px 15px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
                <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                  <div style={{ width: 38, height: 38, borderRadius: 11, background: r.active ? C.greenBg : C.card, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>🔄</div>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 14, color: C.text }}>{r.name}</div>
                    <div style={{ color: C.sub, fontSize: 12, marginTop: 1 }}>{r.freq} · Next: {r.next}</div>
                  </div>
                </div>
                <ToggleSwitch on={r.active} onChange={() => { setRecurring(rs => rs.map(x => x.id===r.id ? {...x, active:!x.active} : x)); toast(r.active ? 'Paused' : 'Resumed 🔄'); }} C={C} />
              </div>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginBottom: 10 }}>
                {r.items.map((item,i) => (
                  <span key={i} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 20, padding: '3px 10px', fontSize: 12, color: C.sub }}>{item}</span>
                ))}
              </div>
              {r.total > 0 && <div style={{ color: C.muted, fontSize: 12 }}>Est. ₦{r.total.toLocaleString()}/order</div>}
            </div>
          ))}
        </div>
      )}

      {/* ── Bulk tab ── */}
      {tab === 'bulk' && (
        <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 12 }}>
          {bulkDiscount > 0 && (
            <div style={{ background: C.greenBg, border: `1px solid ${C.green}33`, borderRadius: 12, padding: '10px 14px', display: 'flex', gap: 9, alignItems: 'center' }}>
              <span style={{ fontSize: 18 }}>🎉</span>
              <span style={{ color: C.green, fontSize: 13, fontWeight: 600 }}>{Math.round(bulkDiscount*100)}% bulk discount applied! You save ₦{Math.round(bulkTotal * bulkDiscount).toLocaleString()}</span>
            </div>
          )}
          {!bulkDiscount && (
            <div style={{ background: C.accentBg, border: `1px solid ${C.accentLine}`, borderRadius: 12, padding: '10px 14px', display: 'flex', gap: 9 }}>
              <span style={{ fontSize: 16 }}>💡</span>
              <span style={{ color: C.sub, fontSize: 12.5 }}>Order ₦20k+ for 5% off · ₦50k+ for 10% off</span>
            </div>
          )}

          {bulkItems.map((item, i) => (
            <div key={item.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 13, padding: '13px 14px', display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{ fontSize: 24 }}>{item.emoji}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>{item.name}</div>
                <div style={{ color: C.muted, fontSize: 12, marginTop: 1 }}>₦{item.unitPrice.toLocaleString()} per {item.unit.replace(/s$/,'')}</div>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <button onClick={() => updateQty(item.id, -1)} style={{ width:28, height:28, borderRadius:8, border:`1px solid ${C.border}`, background:C.surface, color:C.text, fontSize:16, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', fontFamily: "Satoshi,system-ui,sans-serif" }}>−</button>
                <div style={{ fontWeight: 700, fontSize: 15, color: C.text, minWidth: 28, textAlign: 'center' }}>{item.qty}</div>
                <button onClick={() => updateQty(item.id, +1)} style={{ width:28, height:28, borderRadius:8, border:'none', background:C.accent, color:'#fff', fontSize:16, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', fontFamily: "Satoshi,system-ui,sans-serif" }}>+</button>
              </div>
              <div className="disp" style={{ fontSize: 13, color: C.text, minWidth: 70, textAlign: 'right' }}>₦{(item.unitPrice*item.qty).toLocaleString()}</div>
            </div>
          ))}

          <Input C={C} placeholder="Special instructions (e.g. for event, restaurant…)" value={bulkNote} onChange={e => setBulkNote(e.target.value)} rows={2} />

          {/* Summary */}
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 13, padding: '13px 15px' }}>
            {[['Subtotal', `₦${bulkTotal.toLocaleString()}`], bulkDiscount ? [`Bulk discount (${Math.round(bulkDiscount*100)}%)`, `-₦${Math.round(bulkTotal*bulkDiscount).toLocaleString()}`] : null, ['Total', `₦${Math.round(bulkTotal*(1-bulkDiscount)).toLocaleString()}`]].filter(Boolean).map(([l,v],i,arr) => (
              <div key={l} style={{ display:'flex', justifyContent:'space-between', padding:'7px 0', borderBottom: i<arr.length-1?`1px solid ${C.border}`:'none' }}>
                <span style={{ color: i===arr.length-1?C.text:C.sub, fontSize:13, fontWeight: i===arr.length-1?700:400 }}>{l}</span>
                <span className={i===arr.length-1?"disp":""} style={{ color: l.includes('discount')?C.green:C.text, fontSize:13 }}>{v}</span>
              </div>
            ))}
          </div>
          <Btn C={C} block style={{ padding: '14px' }} onClick={() => { bulkItems.forEach((item,idx) => { for(let q=0;q<Math.min(item.qty,3);q++) setTimeout(()=>addToCart({id:item.id*100+q, name:item.name, price:item.unitPrice, emoji:item.emoji}), idx*30); }); toast(`Bulk order added to cart! ₦${Math.round(bulkTotal*(1-bulkDiscount)).toLocaleString()}`, '📦', 'success'); }}>📦 Add bulk order to cart</Btn>
        </div>
      )}
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════
//  SOCIAL FEATURES
//  Food feed · Share cart · Store reviews · Follow friends
// ═══════════════════════════════════════════════════════════════

function SocialFeed({ goTo, addToCart, C }) {
  const toast = useToast();
  const [tab, setTab] = useState('feed');
  const [likedPosts, setLikedPosts] = useState(new Set());
  const [following, setFollowing] = useState(new Set([1, 3]));
  const [reviewStore, setReviewStore] = useState(null);
  const [reviewStars, setReviewStars] = useState(0);
  const [reviewText, setReviewText] = useState('');
  const [reviews, setReviews] = useState([
    { id:1, user:'Amaka O.', avatar:'👩🏾', store:'FoodMart', rating:5, text:'Always fresh produce and fast delivery! Amara never disappoints 🌟', time:'2h ago', likes:14 },
    { id:2, user:'Emeka N.', avatar:'👨🏾', store:'TechHub',  rating:4, text:'Got my earbuds same day. Great packaging, only wish prices were lower 😄', time:'5h ago', likes:8 },
    { id:3, user:'Ngozi K.', avatar:'👩🏾‍🦱', store:'GlowStore', rating:5, text:'The vitamin C serum is legit! Skin has been glowing for 2 weeks 🧴✨', time:'Yesterday', likes:31 },
  ]);

  const FEED_POSTS = [
    { id:1, user:'Tunde B.',   avatar:'👨🏿', time:'Just now',  type:'order',  text:"Just ordered jollof rice + chicken from FoodMart 🍛 Can't wait!", items:[{e:'🍛',n:'Jollof Rice'},{e:'🍗',n:'Chicken'}], likes:6,  comments:2  },
    { id:2, user:'Bola A.',    avatar:'👩🏾', time:'15 min',   type:'review', text:'GlowStore just dropped a new SPF 50 tinted moisturiser 😍 Ordered 2!', rating:5, store:'GlowStore', likes:22, comments:7  },
    { id:3, user:'Chioma E.',  avatar:'👩🏾‍🦱',time:'1h ago',   type:'deal',   text:'Flash deal at TechHub — wireless earbuds for ₦21,500 (was ₦45k)! Grab it 🎧', deal:{emoji:'🎧', name:'Wireless Earbuds', price:21500, was:45000}, likes:45, comments:18 },
    { id:4, user:'Funke M.',   avatar:'👩🏾', time:'2h ago',   type:'cart',   text:'Building my weekly shop — who wants to split costs? 👀', cart:[{e:'🍅',n:'Tomatoes'},{e:'🍚',n:'Rice 5kg'},{e:'🥚',n:'Eggs ×12'},{e:'🍗',n:'Chicken'}], likes:11, comments:4  },
    { id:5, user:'Kwame A.',   avatar:'👨🏿', time:'3h ago',   type:'order',  text:'Third time ordering from FreshFarm this month 🌿 The organic produce is unbeatable', items:[{e:'🌿',n:'Organic Veg'},{e:'🍋',n:'Lemon ×6'}], likes:19, comments:3  },
  ];

  const FRIENDS = [
    { id:1, name:'Amaka Osei',   handle:'@amaka',   avatar:'👩🏾',   orders:142, mutual:4 },
    { id:2, name:'Tunde Bello',  handle:'@tunde',   avatar:'👨🏿',   orders:89,  mutual:2 },
    { id:3, name:'Ngozi Chukwu', handle:'@ngozi_k', avatar:'👩🏾‍🦱', orders:201, mutual:6 },
    { id:4, name:'Emeka Nwosu',  handle:'@emeka',   avatar:'👨🏾',   orders:67,  mutual:1 },
  ];

  const STORES_FOR_REVIEW = STORES || [
    { id:1, name:'FoodMart', emoji:'🛒' },
    { id:2, name:'GlowStore',emoji:'💄' },
    { id:3, name:'TechHub',  emoji:'📱' },
  ];

  const toggleLike  = id => setLikedPosts(s => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; });
  const toggleFollow = id => { setFollowing(s => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; }); toast(following.has(id)?'Unfollowed':'Following ✓','👥'); };

  const submitReview = () => {
    if (!reviewStars) { toast('Tap stars to rate', '⭐', 'error'); return; }
    setReviews(r => [{ id: Date.now(), user:'You', avatar:'😊', store: reviewStore?.name||'', rating:reviewStars, text:reviewText||'Great experience!', time:'Just now', likes:0 }, ...r]);
    setReviewStore(null); setReviewStars(0); setReviewText('');
    toast('Review posted! +20 pts 🎉', '⭐', 'success');
  };

  return (
    <div className="screen" style={{ background: C.bg, paddingBottom: 80 }}>
      <div style={{ padding: '52px 20px 14px' }}>
        <div className="disp" style={{ fontSize: 22, color: C.text, marginBottom: 2 }}>Community 🏙️</div>
        <div style={{ color: C.sub, fontSize: 13 }}>What Lagos is ordering today</div>
      </div>

      <div className="hrow" style={{ padding: '0 20px 14px' }}>
        {[['feed','🏙️ Feed'],['reviews','⭐ Reviews'],['friends','👥 Friends']].map(([id,l]) => (
          <button key={id} onClick={() => setTab(id)} style={{ padding:'7px 16px', borderRadius:20, border:'none', fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:13, cursor:'pointer', background:tab===id?C.accent:C.card, color:tab===id?'#fff':C.sub, flexShrink:0, transition:'all .15s' }}>{l}</button>
        ))}
      </div>

      {/* ── Feed ── */}
      {tab === 'feed' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
          {FEED_POSTS.map(post => {
            const liked = likedPosts.has(post.id);
            return (
              <div key={post.id} style={{ background: C.card, borderBottom: `1px solid ${C.border}`, padding: '14px 20px' }}>
                {/* Header */}
                <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 10 }}>
                  <div style={{ width: 38, height: 38, borderRadius: '50%', background: `hsl(${post.id*60+20},45%,${C.dark?38:58}%)`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>{post.avatar}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 700, fontSize: 14, color: C.text }}>{post.user}</div>
                    <div style={{ color: C.muted, fontSize: 12 }}>{post.time}</div>
                  </div>
                  {post.type === 'deal' && <span style={{ background: C.accentBg, color: C.accent, fontSize: 12, fontWeight: 700, padding: '2px 8px', borderRadius: 6 }}>DEAL</span>}
                </div>
                {/* Text */}
                <div style={{ color: C.text, fontSize: 14, lineHeight: 1.55, marginBottom: 10 }}>{post.text}</div>
                {/* Content cards */}
                {post.type === 'order' && post.items && (
                  <div style={{ display: 'flex', gap: 7, marginBottom: 10 }}>
                    {post.items.map((item,i) => (
                      <div key={i} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: '6px 11px', display: 'flex', alignItems: 'center', gap: 6 }}>
                        <span style={{ fontSize: 16 }}>{item.e}</span>
                        <span style={{ fontSize: 12, color: C.sub }}>{item.n}</span>
                      </div>
                    ))}
                  </div>
                )}
                {post.type === 'deal' && post.deal && (
                  <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: '11px 13px', display: 'flex', alignItems: 'center', gap: 11, marginBottom: 10 }}>
                    <div style={{ fontSize: 26 }}>{post.deal.emoji}</div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>{post.deal.name}</div>
                      <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginTop: 2 }}>
                        <span className="disp" style={{ color: C.accent, fontSize: 14 }}>₦{post.deal.price.toLocaleString()}</span>
                        <span style={{ color: C.muted, fontSize: 12, textDecoration: 'line-through' }}>₦{post.deal.was.toLocaleString()}</span>
                      </div>
                    </div>
                    <button onClick={() => { addToCart({ id: post.deal.price, name: post.deal.name, price: post.deal.price, emoji: post.deal.emoji }); toast(`${post.deal.name} added!`, post.deal.emoji, 'success'); }} style={{ background: C.accent, border: 'none', borderRadius: 9, padding: '8px 13px', color: '#fff', fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>Grab it</button>
                  </div>
                )}
                {post.type === 'cart' && post.cart && (
                  <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: '11px 13px', marginBottom: 10 }}>
                    <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, marginBottom: 8 }}>SHARED CART</div>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginBottom: 10 }}>
                      {post.cart.map((item,i) => (
                        <span key={i} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 20, padding: '4px 10px', fontSize: 12, color: C.sub }}>{item.e} {item.n}</span>
                      ))}
                    </div>
                    <button onClick={() => { post.cart.forEach((item,i) => setTimeout(() => addToCart({ id: Date.now()+i, name: item.n, price: 1200, emoji: item.e }), i*40)); toast('Cart items added! 🛒', '✅', 'success'); }} style={{ background: C.accentBg, border: `1px solid ${C.accentLine}`, borderRadius: 9, padding: '7px 14px', color: C.accent, fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>Copy this cart →</button>
                  </div>
                )}
                {/* Actions */}
                <div style={{ display: 'flex', gap: 18, alignItems: 'center' }}>
                  <button onClick={() => toggleLike(post.id)} style={{ display: 'flex', alignItems: 'center', gap: 5, background: 'none', border: 'none', cursor: 'pointer', color: liked ? C.accent : C.muted, fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: liked ? 700 : 400, fontSize: 13 }}>
                    {liked ? '❤️' : '🤍'} {post.likes + (liked ? 1 : 0)}
                  </button>
                  <button style={{ display: 'flex', alignItems: 'center', gap: 5, background: 'none', border: 'none', cursor: 'pointer', color: C.muted, fontFamily: "Satoshi,system-ui,sans-serif", fontSize: 13 }}>💬 {post.comments}</button>
                  <button onClick={() => toast('Link copied! 🔗', '📋')} style={{ display: 'flex', alignItems: 'center', gap: 5, background: 'none', border: 'none', cursor: 'pointer', color: C.muted, fontFamily: "Satoshi,system-ui,sans-serif", fontSize: 13 }}>↗ Share</button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ── Reviews ── */}
      {tab === 'reviews' && (
        <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 12 }}>
          {/* Write review */}
          {!reviewStore ? (
            <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 14, padding: '14px 15px' }}>
              <div className="disp" style={{ fontSize: 14, color: C.text, marginBottom: 11 }}>Review a store</div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8 }}>
                {STORES_FOR_REVIEW.slice(0,6).map(s => (
                  <button key={s.id} onClick={() => setReviewStore(s)} style={{ padding: '11px 8px', background: C.surface, border: `1px solid ${C.border}`, borderRadius: 11, cursor: 'pointer', textAlign: 'center' }}>
                    <div style={{ fontSize: 22, marginBottom: 4 }}>{s.emoji}</div>
                    <div style={{ fontSize: 12, color: C.sub, fontFamily: "Satoshi,system-ui,sans-serif" }}>{s.name}</div>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div style={{ background: C.card, border: `1.5px solid ${C.accent}`, borderRadius: 14, padding: '14px 15px', animation: 'up .2s ease' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 14 }}>
                <div className="disp" style={{ fontSize: 14, color: C.text }}>Review {reviewStore.emoji} {reviewStore.name}</div>
                <button onClick={() => { setReviewStore(null); setReviewStars(0); }} style={{ background: 'none', border: 'none', color: C.muted, fontSize: 20, cursor: 'pointer' }}>×</button>
              </div>
              <div style={{ display: 'flex', gap: 8, marginBottom: 12, justifyContent: 'center' }}>
                {[1,2,3,4,5].map(s => (
                  <button key={s} onClick={() => setReviewStars(s)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: reviewStars >= s ? 32 : 28, filter: reviewStars >= s ? 'none' : 'grayscale(1)', transition: 'all .15s', transform: reviewStars >= s ? 'scale(1.1)' : 'scale(1)' }}>⭐</button>
                ))}
              </div>
              <Input C={C} placeholder="Tell others about your experience…" value={reviewText} onChange={e => setReviewText(e.target.value)} rows={3} style={{ marginBottom: 12 }} />
              <Btn C={C} block onClick={submitReview}>Post review (+20 pts)</Btn>
            </div>
          )}

          {/* Review list */}
          {reviews.map(r => (
            <div key={r.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 13, padding: '13px 14px' }}>
              <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 8 }}>
                <div style={{ width: 36, height: 36, borderRadius: '50%', background: `hsl(${r.id*80},45%,${C.dark?38:58}%)`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18, flexShrink: 0 }}>{r.avatar}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>{r.user} · {r.store}</div>
                  <div style={{ display: 'flex', gap: 1, marginTop: 2 }}>{Array.from({length:5}).map((_,i) => <span key={i} style={{ fontSize: 12, filter: i<r.rating?'none':'grayscale(1)' }}>⭐</span>)}</div>
                </div>
                <div style={{ color: C.muted, fontSize: 12 }}>{r.time}</div>
              </div>
              <div style={{ color: C.sub, fontSize: 13.5, lineHeight: 1.55, marginBottom: 8 }}>{r.text}</div>
              <button onClick={() => toast('Helpful vote recorded ✓','👍')} style={{ background: 'none', border: `1px solid ${C.border}`, borderRadius: 8, padding: '4px 11px', color: C.muted, fontFamily: "Satoshi,system-ui,sans-serif", fontSize: 12, cursor: 'pointer' }}>👍 Helpful ({r.likes})</button>
            </div>
          ))}
        </div>
      )}

      {/* ── Friends ── */}
      {tab === 'friends' && (
        <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 10 }}>
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 13, padding: '11px 14px', display: 'flex', gap: 9, alignItems: 'center' }}>
            <span style={{ fontSize: 16, color: C.muted }}>🔍</span>
            <input placeholder="Find friends by name or @handle…" style={{ flex: 1, background: 'none', border: 'none', color: C.text, fontSize: 14, outline: 'none', fontFamily: "Satoshi,system-ui,sans-serif" }} />
          </div>
          <div style={{ color: C.muted, fontSize: 12, fontWeight: 700, letterSpacing: 1 }}>SUGGESTED FRIENDS</div>
          {FRIENDS.map(f => (
            <div key={f.id} style={{ background: C.card, border: `1.5px solid ${following.has(f.id) ? C.green+'44' : C.border}`, borderRadius: 13, padding: '12px 14px', display: 'flex', gap: 12, alignItems: 'center' }}>
              <div style={{ width: 44, height: 44, borderRadius: '50%', background: `hsl(${f.id*70+30},45%,${C.dark?38:58}%)`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, flexShrink: 0 }}>{f.avatar}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: C.text }}>{f.name}</div>
                <div style={{ color: C.sub, fontSize: 12, marginTop: 1 }}>{f.handle} · {f.orders} orders · {f.mutual} mutual</div>
              </div>
              <button onClick={() => toggleFollow(f.id)} style={{ padding: '7px 14px', background: following.has(f.id) ? C.greenBg : C.accentBg, border: `1.5px solid ${following.has(f.id) ? C.green+'44' : C.accentLine}`, borderRadius: 20, color: following.has(f.id) ? C.green : C.accent, fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: 12.5, cursor: 'pointer' }}>
                {following.has(f.id) ? '✓ Following' : '+ Follow'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}


