//  ORDER CHAT — Shopper ↔ Customer realtime via Supabase
// ══════════════════════════════════════════════════════════════

// Hook: manages a chat channel for a given order
function useOrderChat(orderId) {
  const { user } = useAuth() || {};
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);

  useEffect(() => {
    if (!orderId) return;
    setLoading(true);

    // Load history
    sbDB.select("messages", { filter: `order_id=eq.${orderId}`, order: "created_at.asc", limit: 100 })
      .then(rows => { setMessages(rows || []); setLoading(false); })
      .catch(() => {
        // Graceful fallback: seed with a welcome message
        setMessages([{ id: "welcome", order_id: orderId, user_id: "shopper", sender_role: "shopper", text: "Hi! I'm your shopper Amara. I've confirmed your order ✅", created_at: new Date().toISOString() }]);
        setLoading(false);
      });

    // Subscribe to new messages
    const unsub = sbRealtime.subscribe("messages", (msg) => {
      const rec = msg.payload?.record;
      if (rec?.order_id === orderId) {
        setMessages(p => [...p.filter(m => m.id !== rec.id), rec].sort((a, b) => new Date(a.created_at) - new Date(b.created_at)));
      }
    });
    return unsub;
  }, [orderId]);

  const sendMessage = async (text, mediaUrl = null) => {
    if (!text.trim() && !mediaUrl) return;
    setSending(true);
    const optimistic = { id: `opt_${Date.now()}`, order_id: orderId, user_id: user?.id || "guest", sender_role: "customer", text, media_url: mediaUrl, created_at: new Date().toISOString(), pending: true };
    setMessages(p => [...p, optimistic]);
    try {
      await sbDB.insert("messages", { order_id: orderId, user_id: user?.id || "guest", sender_role: "customer", text, media_url: mediaUrl });
      setMessages(p => p.filter(m => m.id !== optimistic.id));
    } catch {
      setMessages(p => p.map(m => m.id === optimistic.id ? { ...m, failed: true } : m));
    }
    setSending(false);
  };

  return { messages, loading, sending, sendMessage, userId: user?.id };
}

function OrderChat({ goTo, orderId = "demo_order_001", C }) {
  const { messages, loading, sending, sendMessage, userId } = useOrderChat(orderId);
  const [input, setInput] = useState("");
  const [showMedia, setShowMedia] = useState(false);
  const endRef = useRef(null);
  const inputRef = useRef(null);
  const toast = useToast();

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  const QUICK_REPLIES = ["Where are you now? 📍", "Can you get a substitute? 🔄", "Please take a photo 📷", "How long will it take? ⏱️"];

  const send = () => {
    const t = input.trim(); if (!t) return;
    sendMessage(t); setInput("");
    inputRef.current?.focus();
  };

  const SHOPPER = { name: "Amara O.", emoji: "👩🏾", specialty: "Groceries & Fresh Produce", rating: 4.9 };

  return (
    <div className="screen" style={{ background: C.bg, display: "flex", flexDirection: "column", paddingBottom: 0, height: "100vh" }}>
      {/* Header */}
      <div style={{ padding: "52px 20px 12px", borderBottom: `1px solid ${C.border}`, flexShrink: 0, background: C.bg }}>
        <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
          <Back onClick={() => goTo("tracking")} C={C} />
          <div style={{ width: 44, height: 44, borderRadius: 14, background: `linear-gradient(135deg,${C.accent}33,${C.accent}11)`, border: `2px solid ${C.green}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>{SHOPPER.emoji}</div>
          <div style={{ flex: 1 }}>
            <div className="disp" style={{ fontSize: 15, color: C.text }}>{SHOPPER.name}</div>
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 2 }}>
              <div style={{ width: 7, height: 7, borderRadius: "50%", background: C.green }} />
              <span style={{ color: C.green, fontSize: 12, fontWeight: 600 }}>Shopping your order</span>
              <span style={{ color: C.muted, fontSize: 12 }}>· ⭐ {SHOPPER.rating}</span>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => toast("Calling Amara…", "📞")} style={{ width: 36, height: 36, borderRadius: 10, background: C.greenBg, border: `1px solid ${C.green}22`, fontSize: 17, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>📞</button>
            <button onClick={() => goTo("tracking")} style={{ width: 36, height: 36, borderRadius: 10, background: C.card, border: `1px solid ${C.border}`, fontSize: 17, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>🗺️</button>
          </div>
        </div>
      </div>

      {/* Order context banner */}
      <div style={{ background: C.accentBg, borderBottom: `1px solid ${C.accent}22`, padding: "9px 20px", display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
        <span style={{ fontSize: 16 }}>📦</span>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: C.text }}>Order #0893 · FoodMart VI</div>
          <div style={{ fontSize: 12, color: C.sub, marginTop: 1 }}>6 items · ₦12,400 · Est. delivery 3:40 PM</div>
        </div>
        <button onClick={() => goTo("tracking")} style={{ fontSize: 12, color: C.accent, fontWeight: 700, background: "none", border: "none", cursor: "pointer", fontFamily: "Satoshi,system-ui,sans-serif" }}>Track →</button>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: "auto", padding: "14px 20px", display: "flex", flexDirection: "column", gap: 10 }}>
        {loading ? (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {[80, 55, 70].map((w, i) => <Skel key={i} h={36} w={`${w}%`} style={{ alignSelf: i % 2 ? "flex-end" : "flex-start" }} />)}
          </div>
        ) : messages.map((m, i) => {
          const isMe = m.sender_role === "customer" || m.user_id === userId;
          const showAvatar = !isMe && (i === 0 || messages[i - 1]?.sender_role !== m.sender_role);
          const time = new Date(m.created_at).toLocaleTimeString("en-NG", { hour: "2-digit", minute: "2-digit" });
          return (
            <div key={m.id} style={{ display: "flex", flexDirection: "column", alignItems: isMe ? "flex-end" : "flex-start", gap: 3 }}>
              {showAvatar && !isMe && (
                <div style={{ fontSize: 12, color: C.muted, marginLeft: 6, marginBottom: 2 }}>{SHOPPER.name}</div>
              )}
              {m.media_url && (
                <img src={m.media_url} alt="media" style={{ maxWidth: 220, borderRadius: 12, border: `1px solid ${C.border}` }} />
              )}
              {m.text && (
                <div style={{ background: isMe ? C.accent : C.card, color: isMe ? "#fff" : C.text, borderRadius: isMe ? "16px 16px 4px 16px" : "16px 16px 16px 4px", padding: "10px 14px", fontSize: 14, maxWidth: "80%", border: !isMe ? `1px solid ${C.border}` : "none", lineHeight: 1.5, opacity: m.pending ? 0.6 : 1, position: "relative" }}>
                  {m.text}
                  {m.failed && <span style={{ fontSize: 12, color: "#EF4444", display: "block", marginTop: 4 }}>⚠ Failed to send · Tap to retry</span>}
                </div>
              )}
              <div style={{ fontSize: 12, color: C.muted, paddingLeft: 4, paddingRight: 4 }}>
                {time}{isMe && (m.pending ? " · Sending…" : m.failed ? " · Failed" : " · Sent ✓")}
              </div>
            </div>
          );
        })}
        <div ref={endRef} />
      </div>

      {/* Quick replies */}
      {messages.length < 4 && (
        <div style={{ padding: "0 20px 10px", display: "flex", gap: 7, overflowX: "auto", flexShrink: 0 }}>
          {QUICK_REPLIES.map(r => (
            <button key={r} onClick={() => { sendMessage(r); }} style={{ padding: "7px 12px", background: C.card, border: `1px solid ${C.border}`, borderRadius: 20, color: C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontSize: 12, cursor: "pointer", whiteSpace: "nowrap", flexShrink: 0 }}>{r}</button>
          ))}
        </div>
      )}

      {/* Input bar */}
      <div style={{ padding: "10px 20px 32px", borderTop: `1px solid ${C.border}`, background: C.bg, display: "flex", gap: 9, alignItems: "center", flexShrink: 0 }}>
        <button onClick={() => setShowMedia(v => !v)} style={{ width: 40, height: 40, borderRadius: 12, background: C.card, border: `1px solid ${C.border}`, fontSize: 18, cursor: "pointer", flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>📎</button>
        <input ref={inputRef} value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()} placeholder="Message your shopper…" style={{ flex: 1, background: C.card, border: `1.5px solid ${C.border}`, borderRadius: 22, padding: "10px 16px", color: C.text, fontSize: 14, outline: "none", fontFamily: "Satoshi,system-ui,sans-serif", transition: "border .15s" }} onFocus={e => e.target.style.borderColor = C.accent} onBlur={e => e.target.style.borderColor = C.border} />
        <button onClick={send} disabled={!input.trim() || sending} style={{ width: 42, height: 42, borderRadius: "50%", background: input.trim() ? C.accent : C.border, border: "none", display: "flex", alignItems: "center", justifyContent: "center", cursor: input.trim() ? "pointer" : "not-allowed", flexShrink: 0, transition: "background .15s", fontSize: 18 }}>
          {sending ? <span style={{ width: 16, height: 16, border: "2px solid rgba(255,255,255,.4)", borderTopColor: "#fff", borderRadius: "50%", animation: "spin .7s linear infinite", display: "inline-block" }} /> : "➤"}
        </button>
      </div>
    </div>
  );
}

