// ══════════════════════════════════════════════════════════════
//  WALLET V2 — Supabase transactions · Paystack withdraw
// ══════════════════════════════════════════════════════════════

function useWallet(userId) {
  const [balance, setBalance]   = useState(null);
  const [txns,    setTxns]      = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    if (!userId) { setLoading(false); return; }
    // Load balance + transactions from Supabase
    Promise.all([
      sbDB.select("profiles",             { filter: `id=eq.${userId}`, limit: 1 }),
      sbDB.select("wallet_transactions",  { filter: `user_id=eq.${userId}`, order: "created_at.desc", limit: 50 }),
    ]).then(([profiles, txns]) => {
      setBalance(profiles?.[0]?.wallet_balance ?? 24500);   // fallback demo balance
      setTxns(txns?.length ? txns : TXNS.map((t,i) => ({   // fallback demo txns
        id: `demo_${i}`, user_id: userId, label: t.label, amount: t.amount,
        icon: t.icon, type: t.cr ? "credit" : "debit", status: "completed",
        created_at: new Date(Date.now() - i * 86400000).toISOString(),
      })));
      setLoading(false);
    }).catch(() => {
      setBalance(24500); setTxns(TXNS.map((t,i) => ({ id:`d${i}`, label:t.label, amount:t.amount, icon:t.icon, type:t.cr?"credit":"debit", status:"completed", created_at:new Date().toISOString() })));
      setLoading(false);
    });

    // Realtime: new transaction credited/debited
    const unsub = sbRealtime.subscribe("wallet_transactions", msg => {
      const rec = msg.payload?.record;
      if (!rec || rec.user_id !== userId) return;
      if (msg.payload?.eventType === "INSERT") {
        setTxns(p => [rec, ...p]);
        setBalance(b => b + rec.amount); // amount is signed (+/-)
      }
    });
    return unsub;
  }, [userId]);

  const credit = async (amount, label, icon = "💳") => {
    await sbDB.insert("wallet_transactions", { user_id: userId, amount: Math.abs(amount), type: "credit", label, icon, status: "completed" });
    await sbDB.update("profiles", { wallet_balance: (balance || 0) + Math.abs(amount) }, `id=eq.${userId}`);
    setBalance(b => (b||0) + Math.abs(amount));
  };

  const debit = async (amount, label, icon = "💸") => {
    if ((balance || 0) < amount) throw new Error("Insufficient balance");
    await sbDB.insert("wallet_transactions", { user_id: userId, amount: -Math.abs(amount), type: "debit", label, icon, status: "completed" });
    await sbDB.update("profiles", { wallet_balance: (balance||0) - Math.abs(amount) }, `id=eq.${userId}`);
    setBalance(b => (b||0) - Math.abs(amount));
  };

  return { balance, txns, loading, credit, debit };
}

function WalletV2({ goTo, C }) {
  const { user } = useAuth() || {};
  const { balance, txns, loading, credit, debit } = useWallet(user?.id || "guest");
  const toast  = useToast();
  const [sheet,  setSheet]  = useState(null); // "topup"|"send"|"withdraw"
  const [amount, setAmount] = useState("");
  const [bank,   setBank]   = useState("");
  const [acct,   setAcct]   = useState("");
  const [acctName,setAcctName] = useState("");
  const [verifying, setVerifying] = useState(false);
  const [acting,  setActing] = useState(false);
  const [filter,  setFilter] = useState("all"); // all|credit|debit
  const { initPay } = usePaystack();

  const BANKS = ["Access Bank","Zenith Bank","GTBank","First Bank","UBA","Fidelity Bank","Polaris Bank","Kuda Bank","Opay","PalmPay","Moniepoint"];

  const verifyAccount = async () => {
    if (!acct || acct.length !== 10 || !bank) return;
    setVerifying(true);
    // Call Paystack Resolve Account API (via our Next.js proxy)
    try {
      const r = await fetch(`/api/paystack/resolve-account?account_number=${acct}&bank_code=${bank}`, { headers: { "Content-Type": "application/json" } });
      const d = await r.json();
      setAcctName(d.data?.account_name || "Okafor Amara Chidinma");
    } catch {
      setAcctName("Okafor Amara Chidinma"); // demo fallback
    }
    setVerifying(false);
  };
  useEffect(() => { if (acct.length === 10 && bank) verifyAccount(); }, [acct, bank]);

  const doTopUp = () => {
    const amt = Number(amount);
    if (!amt || amt < 100) { toast("Minimum top-up is ₦100","⚠️"); return; }
    setActing(true);
    initPay({
      email: user?.email || "guest@errand.ng",
      amount: amt,
      orderId: `topup_${Date.now()}`,
      metadata: { type: "wallet_topup" },
      onSuccess: async (ref) => {
        await credit(amt, "Wallet Top-up", "💳");
        toast(`₦${amt.toLocaleString()} added to wallet ✓`, "✅", "success");
        _pushBus.emit({ title: "Wallet funded! 💳", body: `₦${amt.toLocaleString()} added to your Errand wallet.`, icon: "💳" });
        setSheet(null); setAmount(""); setActing(false);
      },
      onClose: () => { setActing(false); toast("Top-up cancelled","ℹ️"); },
    });
  };

  const doWithdraw = async () => {
    const amt = Number(amount);
    if (!amt || amt < 500) { toast("Minimum withdrawal ₦500","⚠️"); return; }
    if ((balance||0) < amt) { toast("Insufficient balance","⚠️"); return; }
    if (!acctName) { toast("Please verify your account number","⚠️"); return; }
    setActing(true);
    try {
      // Call Paystack Transfer API via Next.js API route
      await fetch("/api/paystack/transfer", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify({ amount: amt, bank, account_number: acct, account_name: acctName, user_id: user?.id }) });
      await debit(amt, `Withdrawal to ${bank}`, "🏦");
      toast(`₦${amt.toLocaleString()} sent to ${acctName} ✓`, "🏦", "success");
      _pushBus.emit({ title: "Withdrawal processing 🏦", body: `₦${amt.toLocaleString()} is on its way to your bank.`, icon: "🏦" });
      setSheet(null); setAmount(""); setAcct(""); setBank(""); setAcctName("");
    } catch (e) {
      toast(e.message || "Withdrawal failed","⚠️");
    }
    setActing(false);
  };

  const doSend = async () => {
    const amt = Number(amount);
    if (!amt || amt < 50) { toast("Minimum send ₦50","⚠️"); return; }
    try {
      await debit(amt, "Wallet Transfer", "↗️");
      toast(`₦${amt.toLocaleString()} sent ✓`, "✅", "success");
      setSheet(null); setAmount("");
    } catch (e) { toast(e.message,"⚠️"); }
  };

  const filtered = filter === "all" ? txns : txns.filter(t => t.type === filter);
  const totalIn  = txns.filter(t => t.type==="credit").reduce((s,t) => s+Math.abs(t.amount), 0);
  const totalOut = txns.filter(t => t.type==="debit").reduce((s,t) => s+Math.abs(t.amount), 0);

  return (
    <div className="screen" style={{ background:C.bg, paddingBottom:80 }}>
      <div style={{ padding:"52px 20px 16px", display:"flex", gap:12, alignItems:"center" }}>
        <Back onClick={() => goTo("profile")} C={C} />
        <div className="disp" style={{ fontSize:20, color:C.text }}>Wallet</div>
      </div>

      {/* Balance card */}
      <div style={{ margin:"0 20px 18px", background:`linear-gradient(135deg,${C.accent},#FF9500)`, borderRadius:20, padding:"24px 22px 22px", position:"relative", overflow:"hidden", boxShadow:`0 12px 40px ${C.accentGlow}` }}>
        <div style={{ position:"absolute", top:-28, right:-28, width:110, height:110, borderRadius:"50%", background:"rgba(255,255,255,.07)" }} />
        <div style={{ position:"absolute", bottom:-22, left:-22, width:80, height:80, borderRadius:"50%", background:"rgba(255,255,255,.05)" }} />
        <div style={{ color:"rgba(255,255,255,.7)", fontSize:12, marginBottom:6, fontWeight:500 }}>Available Balance</div>
        {loading ? <div style={{ height:44, width:160, borderRadius:10, background:"rgba(255,255,255,.15)", marginBottom:20 }} />
          : <div className="disp" style={{ fontSize:36, color:"#fff", marginBottom:20 }}>₦{(balance||0).toLocaleString()}</div>}
        <div style={{ display:"flex", gap:8 }}>
          {[["topup","+ Top up"],["withdraw","⬇ Withdraw"],["send","↗ Send"],["methods","💳 Cards"]].map(([id,l])=>(
            <button key={id} onClick={()=>{ if(id==="methods"){goTo("payments");return;} setSheet(sheet===id?null:id); setAmount(""); setAcct(""); setBank(""); setAcctName(""); }}
              style={{ flex:1, padding:"9px 4px", background:sheet===id?"rgba(255,255,255,.3)":"rgba(255,255,255,.15)", border:"1px solid rgba(255,255,255,.2)", borderRadius:10, color:"#fff", cursor:"pointer", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:11.5, transition:"all .18s" }}>{l}</button>
          ))}
        </div>
      </div>

      {/* Stats strip */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, margin:"0 20px 16px" }}>
        {[["Total in","₦"+totalIn.toLocaleString(),C.green,C.greenBg],["Total out","₦"+totalOut.toLocaleString(),C.accent,C.accentBg]].map(([l,v,col,bg])=>(
          <div key={l} style={{ background:bg, border:`1px solid ${col}22`, borderRadius:14, padding:"14px 16px" }}>
            <div style={{ fontSize:11.5, color:col, fontWeight:700, marginBottom:4 }}>{l}</div>
            <div className="disp" style={{ fontSize:18, color:col }}>{loading?"—":v}</div>
          </div>
        ))}
      </div>

      {/* Action sheet */}
      {sheet && (
        <div style={{ margin:"0 20px 16px", background:C.card, border:`1px solid ${C.border}`, borderRadius:16, padding:18, animation:"up .25s ease" }}>
          <div className="disp" style={{ fontSize:16, color:C.text, marginBottom:14 }}>
            {sheet==="topup"?"Top up wallet":sheet==="withdraw"?"Withdraw to bank":"Send money"}
          </div>

          {/* Quick amounts */}
          <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginBottom:12 }}>
            {(sheet==="topup"?[1000,2000,5000,10000]:[500,1000,2000,5000]).map(a=>(
              <button key={a} onClick={()=>setAmount(String(a))} style={{ padding:"7px 14px", borderRadius:9, border:`1.5px solid ${amount===String(a)?C.accent:C.border}`, background:amount===String(a)?C.accentBg:"transparent", color:amount===String(a)?C.accent:C.sub, cursor:"pointer", fontSize:13, fontWeight:600, fontFamily: "Satoshi,system-ui,sans-serif" }}>₦{a.toLocaleString()}</button>
            ))}
          </div>
          <Input C={C} placeholder="Enter amount (₦)" value={amount} onChange={e=>setAmount(e.target.value.replace(/\D/,""))} style={{ marginBottom:12 }} />

          {/* Withdraw: bank details */}
          {sheet==="withdraw" && (
            <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:12 }}>
              <select value={bank} onChange={e=>setBank(e.target.value)} style={{ width:"100%", background:C.surface, border:`1.5px solid ${C.border}`, borderRadius:12, padding:"11px 14px", color:bank?C.text:C.muted, fontSize:14, fontFamily: "Satoshi,system-ui,sans-serif", outline:"none" }}>
                <option value="">Select bank…</option>
                {BANKS.map(b=><option key={b} value={b}>{b}</option>)}
              </select>
              <Input C={C} placeholder="10-digit account number" value={acct} onChange={e=>setAcct(e.target.value.slice(0,10).replace(/\D/,""))} />
              {verifying && <div style={{ fontSize:12.5, color:C.muted }}>Verifying account…</div>}
              {acctName && !verifying && (
                <div style={{ background:C.greenBg, border:`1px solid ${C.green}33`, borderRadius:10, padding:"9px 13px", fontSize:13, fontWeight:600, color:C.green }}>✓ {acctName}</div>
              )}
            </div>
          )}

          <Btn C={C} block onClick={sheet==="topup"?doTopUp:sheet==="withdraw"?doWithdraw:doSend} disabled={acting||!amount}>
            {acting ? <><span style={{ width:16, height:16, border:"2px solid rgba(255,255,255,.4)", borderTopColor:"#fff", borderRadius:"50%", animation:"spin .7s linear infinite", display:"inline-block", marginRight:8 }} />Processing…</> : sheet==="topup" ? `Add ₦${Number(amount||0).toLocaleString()}` : sheet==="withdraw" ? `Withdraw ₦${Number(amount||0).toLocaleString()}` : `Send ₦${Number(amount||0).toLocaleString()}`}
          </Btn>
        </div>
      )}

      {/* Transactions */}
      <div style={{ padding:"0 20px" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div className="disp" style={{ fontSize:16, color:C.text }}>Transactions</div>
          <div style={{ display:"flex", gap:6 }}>
            {[["all","All"],["credit","In"],["debit","Out"]].map(([id,l])=>(
              <button key={id} onClick={()=>setFilter(id)} style={{ padding:"5px 11px", borderRadius:18, border:"none", fontFamily: "Satoshi,system-ui,sans-serif", fontWeight:600, fontSize:12, cursor:"pointer", background:filter===id?C.accent:C.card, color:filter===id?"#fff":C.sub }}>{l}</button>
            ))}
          </div>
        </div>

        {loading ? [1,2,3,4].map(i=><SkelRow key={i} C={C} />) : filtered.length===0 ? (
          <div style={{ textAlign:"center", padding:"40px 0", color:C.muted }}>No transactions yet</div>
        ) : filtered.map((t,i) => (
          <div key={t.id||i} style={{ display:"flex", alignItems:"center", gap:13, padding:"12px 0", borderBottom:`1px solid ${C.border}` }}>
            <div style={{ width:42, height:42, borderRadius:13, background:t.type==="credit"?C.greenBg:C.accentBg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:20, flexShrink:0 }}>{t.icon||"💰"}</div>
            <div style={{ flex:1 }}>
              <div style={{ fontWeight:500, fontSize:14, color:C.text }}>{t.label}</div>
              <div style={{ display:"flex", gap:8, marginTop:2 }}>
                <div style={{ color:C.muted, fontSize:12 }}>{new Date(t.created_at).toLocaleDateString("en-NG",{month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"})}</div>
                <div style={{ fontSize:11, padding:"1px 7px", borderRadius:8, background:t.status==="completed"?C.greenBg:C.goldBg, color:t.status==="completed"?C.green:C.gold, fontWeight:700 }}>{t.status||"completed"}</div>
              </div>
            </div>
            <div className="disp" style={{ fontSize:15, color:t.type==="credit"?C.green:C.accent }}>{t.type==="credit"?"+":"−"}₦{Math.abs(t.amount).toLocaleString()}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════
//  ADMIN PANEL — Users · Orders · Stores · Payouts
// ══════════════════════════════════════════════════════════════

function useAdminData() {
  const [users,  setUsers]  = useState([]);
  const [orders, setOrders] = useState([]);
  const [stores, setStores] = useState([]);
  const [payouts,setPayouts]= useState([]);
  const [stats,  setStats]  = useState(null);
  const [loading,setLoading]= useState(true);

  useEffect(() => {
    Promise.all([
      sbDB.select("profiles",            { limit:50, order:"created_at.desc" }),
      sbDB.select("orders",              { limit:50, order:"created_at.desc" }),
      sbDB.select("stores",              { limit:20 }),
      sbDB.select("wallet_transactions", { filter:"type=eq.debit&label=like.*Withdrawal*", limit:30, order:"created_at.desc" }),
    ]).then(([u,o,s,p]) => {
      const _u = u?.length ? u : DEMO_USERS;
      const _o = o?.length ? o : DEMO_ORDERS;
      const _s = s?.length ? s : DEMO_STORES;
      const _p = p?.length ? p : DEMO_PAYOUTS;
      setUsers(_u); setOrders(_o); setStores(_s); setPayouts(_p);
      setStats({
        users:   _u.length,
        orders:  _o.length,
        revenue: _o.reduce((s,o)=>s+(o.total||0),0),
        pending: _o.filter(o=>o.status==="pending").length,
        avgOrder:_o.length ? Math.round(_o.reduce((s,o)=>s+(o.total||0),0)/_o.length) : 0,
      });
      setLoading(false);
    }).catch(() => {
      setUsers(DEMO_USERS); setOrders(DEMO_ORDERS); setStores(DEMO_STORES); setPayouts(DEMO_PAYOUTS);
      setStats({ users:8, orders:12, revenue:284600, pending:3, avgOrder:23716 });
      setLoading(false);
    });

    // Realtime order stream
    const unsub = sbRealtime.subscribe("orders", msg => {
      const rec = msg.payload?.record; if (!rec) return;
      if (msg.payload?.eventType==="INSERT") setOrders(p=>[rec,...p]);
      if (msg.payload?.eventType==="UPDATE") setOrders(p=>p.map(o=>o.id===rec.id?rec:o));
    });
    return unsub;
  }, []);

  const updateOrderStatus = async (id, status) => {
    await sbDB.update("orders", { status }, `id=eq.${id}`);
    setOrders(p=>p.map(o=>o.id===id?{...o,status}:o));
    // Notify customer
    serverSendPush(id, { title:`Order ${status}`, body:`Your order is now: ${status}`, tag:`order-${id}` });
  };

  const approvePayout = async (payout) => {
    await sbDB.update("wallet_transactions", { status:"completed" }, `id=eq.${payout.id}`);
    setPayouts(p=>p.map(x=>x.id===payout.id?{...x,status:"completed"}:x));
  };

  const suspendUser = async (userId, suspended) => {
    await sbDB.update("profiles", { suspended }, `id=eq.${userId}`);
    setUsers(p=>p.map(u=>u.id===userId?{...u,suspended}:u));
  };

  return { users, orders, stores, payouts, stats, loading, updateOrderStatus, approvePayout, suspendUser };
}

