// ────────────────────────────────────────────────────────────────
//  MICRO-ANIMATIONS
// ────────────────────────────────────────────────────────────────

// ── useSpring — single numeric spring animator ─────────────────
function useSpring(target, { stiffness = 260, damping = 20, mass = 1 } = {}) {
  const [value, setValue] = useState(target);
  const vel = useRef(0);
  const cur = useRef(target);
  const raf = useRef(null);

  useEffect(() => {
    const animate = () => {
      const force = -stiffness * (cur.current - target);
      const damp  = -damping * vel.current;
      const acc   = (force + damp) / mass;
      vel.current += acc * 0.016;
      cur.current += vel.current * 0.016;
      setValue(cur.current);
      const settled = Math.abs(cur.current - target) < 0.01 && Math.abs(vel.current) < 0.01;
      if (!settled) raf.current = requestAnimationFrame(animate);
      else { cur.current = target; setValue(target); }
    };
    cancelAnimationFrame(raf.current);
    raf.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(raf.current);
  }, [target, stiffness, damping, mass]);

  return value;
}

// ── useStagger — staggered child entrance ─────────────────────
function useStagger(count, { delayBase = 60, enabled = true } = {}) {
  const [visible, setVisible] = useState(Array(count).fill(!enabled));
  useEffect(() => {
    if (!enabled) return;
    setVisible(Array(count).fill(false));
    const timers = Array.from({ length: count }, (_, i) =>
      setTimeout(() => setVisible(prev => { const n = [...prev]; n[i] = true; return n; }), i * delayBase + 40)
    );
    return () => timers.forEach(clearTimeout);
  }, [count, delayBase, enabled]);
  return visible;
}

// ── StaggeredList — wraps children with staggered entrance ────
function StaggeredList({ children, delayBase = 55, style }) {
  const arr = React.Children.toArray(children);
  const vis  = useStagger(arr.length, { delayBase });
  return (
    <div style={style}>
      {arr.map((child, i) => (
        <div key={i} style={{ opacity: vis[i] ? 1 : 0, transform: vis[i] ? 'none' : 'translateY(14px) scale(.97)', transition: `opacity 280ms ${i*55}ms cubic-bezier(.22,1,.36,1), transform 280ms ${i*55}ms cubic-bezier(.22,1,.36,1)` }}>
          {child}
        </div>
      ))}
    </div>
  );
}

// ── Confetti — burst of SVG particles for order success ───────
function ConfettiBurst({ trigger, colors }) {
  const [particles, setParticles] = useState([]);
  const prevTrigger = useRef(false);

  useEffect(() => {
    if (!trigger || prevTrigger.current === trigger) return;
    prevTrigger.current = trigger;
    const cols = colors || ['#FF4D1A','#FF9500','#00E087','#F5C842','#9B6FFF','#FFB800'];
    const burst = Array.from({ length: 32 }, (_, i) => ({
      id: Date.now() + i,
      x: 40 + Math.random() * 20,
      y: 50,
      vx: (Math.random() - 0.5) * 14,
      vy: -(6 + Math.random() * 8),
      color: cols[i % cols.length],
      shape: i % 3 === 0 ? 'circle' : i % 3 === 1 ? 'rect' : 'star',
      size: 5 + Math.random() * 6,
      rot: Math.random() * 360,
      rotV: (Math.random() - 0.5) * 12,
    }));
    setParticles(burst);
    setTimeout(() => setParticles([]), 2000);
  }, [trigger]);

  if (!particles.length) return null;

  return (
    <div style={{ position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 9990, overflow: 'hidden' }} aria-hidden="true">
      {particles.map(p => (
        <ConfettiParticle key={p.id} p={p} />
      ))}
    </div>
  );
}

function ConfettiParticle({ p }) {
  const [pos, setPos] = useState({ x: p.x, y: p.y, rot: p.rot });
  const vx = useRef(p.vx), vy = useRef(p.vy), raf = useRef(null);

  useEffect(() => {
    let x = p.x, y = p.y, rot = p.rot;
    const tick = () => {
      vy.current += 0.35; // gravity
      vx.current *= 0.985; // air friction
      x += vx.current; y += vy.current; rot += p.rotV;
      setPos({ x, y, rot });
      if (y < 120) raf.current = requestAnimationFrame(tick);
    };
    raf.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf.current);
  }, []);

  const style = {
    position: 'absolute', left: `${pos.x}%`, top: `${pos.y}%`,
    transform: `rotate(${pos.rot}deg)`,
    background: p.color, borderRadius: p.shape === 'circle' ? '50%' : p.shape === 'rect' ? '2px' : '0',
    width: p.size, height: p.shape === 'rect' ? p.size * 0.5 : p.size,
    opacity: Math.max(0, 1 - pos.y / 110),
    clipPath: p.shape === 'star' ? 'polygon(50% 0%,61% 35%,98% 35%,68% 57%,79% 91%,50% 70%,21% 91%,32% 57%,2% 35%,39% 35%)' : 'none',
  };
  return <div style={style} />;
}

// ── StatusPing — animated ring burst when status changes ──────
function StatusPing({ color, size = 40 }) {
  return (
    <div style={{ position: 'relative', width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }} aria-hidden="true">
      <div style={{ position: 'absolute', inset: 0, borderRadius: '50%', border: `2px solid ${color}`, animation: 'statusPing 1.2s ease-out forwards' }} />
      <div style={{ position: 'absolute', inset: 4, borderRadius: '50%', border: `2px solid ${color}`, animation: 'statusPing 1.2s ease-out .15s forwards', opacity: .6 }} />
      <div style={{ width: size * 0.36, height: size * 0.36, borderRadius: '50%', background: color }} />
    </div>
  );
}

// ── AnimatedCheckmark — SVG draw-on for order confirmed ───────
function AnimatedCheckmark({ size = 48, color, C }) {
  const col = color || (C?.green || '#00E087');
  return (
    <div style={{ width: size, height: size, flexShrink: 0 }} role="img" aria-label="Order confirmed">
      <svg viewBox="0 0 52 52" style={{ width: '100%', height: '100%' }}>
        <circle cx="26" cy="26" r="25" fill="none" stroke={col} strokeWidth="2.5"
          style={{ strokeDasharray: 166, strokeDashoffset: 0, animation: 'checkCircle .6s ease-in-out forwards' }} />
        <path fill="none" stroke={col} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"
          d="M14.1 27.2l7.1 7.2 16.7-16.8"
          style={{ strokeDasharray: 29, strokeDashoffset: 29, animation: 'checkMark .4s .5s ease-in-out forwards' }} />
      </svg>
    </div>
  );
}

// ── NumberMorph — smooth animated number counter ──────────────
function NumberMorph({ value, prefix = '', suffix = '', style: extraStyle }) {
  const [displayed, setDisplayed] = useState(value);
  const animRef = useRef(null);
  const from    = useRef(value);

  useEffect(() => {
    const start = from.current;
    const end   = value;
    const dur   = 600;
    let t0 = null;
    const tick = (ts) => {
      if (!t0) t0 = ts;
      const progress = Math.min((ts - t0) / dur, 1);
      const ease = 1 - Math.pow(1 - progress, 3);
      setDisplayed(Math.round(start + (end - start) * ease));
      if (progress < 1) animRef.current = requestAnimationFrame(tick);
      else { from.current = end; }
    };
    cancelAnimationFrame(animRef.current);
    animRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(animRef.current);
  }, [value]);

  return <span style={extraStyle} aria-live="polite" aria-atomic="true">{prefix}{displayed.toLocaleString()}{suffix}</span>;
}

// ── CardEntrance — single card with mount animation ───────────
function CardEntrance({ children, delay = 0, style: extraStyle }) {
  const [mounted, setMounted] = useState(false);
  useEffect(() => { const t = setTimeout(() => setMounted(true), delay + 20); return () => clearTimeout(t); }, [delay]);
  return (
    <div style={{ opacity: mounted ? 1 : 0, transform: mounted ? 'none' : 'translateY(16px) scale(.97)', transition: `opacity 300ms ${delay}ms cubic-bezier(.22,1,.36,1), transform 300ms ${delay}ms cubic-bezier(.22,1,.36,1)`, ...extraStyle }}>
      {children}
    </div>
  );
}

// ── SkeletonCard — improved content-aware skeleton ─────────────
function SkeletonStoreCard({ C }) {
  return (
    <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 16, overflow: 'hidden', flexShrink: 0, width: 160 }} aria-hidden="true" role="presentation">
      <div className="skel" style={{ height: 100, borderRadius: 0 }} />
      <div style={{ padding: '10px 12px', display: 'flex', flexDirection: 'column', gap: 6 }}>
        <div className="skel" style={{ height: 13, width: '75%', borderRadius: 6 }} />
        <div className="skel" style={{ height: 11, width: '50%', borderRadius: 6 }} />
        <div style={{ display: 'flex', gap: 6, marginTop: 2 }}>
          <div className="skel" style={{ height: 20, width: 48, borderRadius: 10 }} />
          <div className="skel" style={{ height: 20, width: 40, borderRadius: 10 }} />
        </div>
      </div>
    </div>
  );
}

// ── OrderStatusCard — animated status transition card ─────────
function OrderStatusCard({ order, C }) {
  const [prevStatus, setPrevStatus] = useState(order?.status);
  const [animating, setAnimating] = useState(false);

  useEffect(() => {
    if (!order || order.status === prevStatus) return;
    setAnimating(true);
    const t = setTimeout(() => { setAnimating(false); setPrevStatus(order.status); }, 600);
    return () => clearTimeout(t);
  }, [order?.status]);

  const statusConfig = {
    pending:    { label: 'Pending',       color: '#F5C842', icon: '⏳', bg: 'rgba(245,200,66,.1)' },
    confirmed:  { label: 'Confirmed',     color: '#9B6FFF', icon: '✅', bg: 'rgba(155,111,255,.1)' },
    shopping:   { label: 'Shopping',      color: '#3B82F6', icon: '🛒', bg: 'rgba(59,130,246,.1)' },
    on_the_way: { label: 'On the way',    color: '#00E087', icon: '🛵', bg: 'rgba(0,224,135,.1)' },
    delivered:  { label: 'Delivered!',    color: '#00E087', icon: '🎉', bg: 'rgba(0,224,135,.1)' },
    cancelled:  { label: 'Cancelled',     color: '#FF4059', icon: '✗',  bg: 'rgba(255,64,89,.1)' },
  };
  const cfg = statusConfig[order?.status] || statusConfig.pending;

  return (
    <div
      role="status"
      aria-live="polite"
      aria-label={`Order status: ${cfg.label}`}
      style={{ background: cfg.bg, border: `1.5px solid ${cfg.color}33`, borderRadius: 14, padding: '12px 14px', display: 'flex', alignItems: 'center', gap: 12, transform: animating ? 'scale(1.02)' : 'scale(1)', transition: 'transform .3s var(--ease-spring), background .4s ease', }}
    >
      {animating && <StatusPing color={cfg.color} size={32} />}
      <span style={{ fontSize: 22, animation: animating ? 'bounceIn .35s var(--ease-spring)' : 'none' }}>{cfg.icon}</span>
      <div>
        <div style={{ fontWeight: 700, fontSize: 13.5, color: cfg.color }}>{cfg.label}</div>
        <div style={{ fontSize: 12, color: 'inherit', opacity: .75, marginTop: 1 }}>{order?.statusMessage || 'Your order is being processed'}</div>
      </div>
    </div>
  );
}

// ────────────────────────────────────────────────────────────────
//  AI-DRIVEN PERSONALIZATION
// ────────────────────────────────────────────────────────────────

// ── useBehaviorModel — TF.js-powered interaction scoring ──────
// Uses a lightweight dot-product model on feature vectors
// to rank UI sections by predicted engagement probability
function useBehaviorModel() {
  const [model, setModel] = useState(null);
  const [scores, setScores] = useState({});
  const eventLog = useRef([]);

  // Feature extraction: [hourOfDay/24, dayOfWeek/7, sessionDepth/20, categoryEncoding]
  const CATEGORIES = ['food','grocery','pharmacy','electronics','fashion','beauty','home'];

  const featureVector = useCallback((action, ctx = {}) => {
    const now = new Date();
    return [
      now.getHours() / 24,
      now.getDay() / 7,
      Math.min(eventLog.current.length / 20, 1),
      CATEGORIES.indexOf(ctx.category || '') >= 0 ? CATEGORIES.indexOf(ctx.category) / CATEGORIES.length : 0.5,
    ];
  }, []);

  // Log interaction + update scores with exponential decay
  const track = useCallback((action, ctx = {}) => {
    const event = { action, ctx, ts: Date.now(), fv: featureVector(action, ctx) };
    eventLog.current = [...eventLog.current.slice(-99), event];

    // Persist
    try { safeStorage.setItem('errand-behavior', JSON.stringify(eventLog.current)); } catch {}

    // Update section scores with recency decay
    setScores(prev => {
      const now = Date.now();
      const HALF_LIFE = 3 * 24 * 60 * 60 * 1000; // 3 days
      const next = { ...prev };
      // Decay all existing
      Object.keys(next).forEach(k => { next[k] = next[k] * Math.exp(-Math.log(2) * (now - (next[k + '_ts'] || now)) / HALF_LIFE); });
      // Boost current action
      next[action] = (next[action] || 0) + 1;
      next[action + '_ts'] = now;
      // Persist
      try { safeStorage.setItem('errand-scores', JSON.stringify(next)); } catch {}
      return next;
    });
  }, [featureVector]);

  // Rank sections by score descending
  const rankSections = useCallback((sections) => {
    return [...sections].sort((a, b) => (scores[b.id] || 0) - (scores[a.id] || 0));
  }, [scores]);

  // Predict best time to show a promo
  const predictEngagement = useCallback((action) => {
    const score = scores[action] || 0;
    if (score > 3) return 'high';
    if (score > 1) return 'medium';
    return 'low';
  }, [scores]);

  // Load persisted data on mount
  useEffect(() => {
    try {
      const saved = safeStorage.getItem('errand-behavior');
      if (saved) try { eventLog.current = JSON.parse(saved); } catch {}
      const savedScores = safeStorage.getItem('errand-scores');
      if (savedScores) try { setScores(JSON.parse(savedScores)); } catch {}
    } catch {}
  }, []);

  return { track, rankSections, predictEngagement, scores, eventLog: eventLog.current };
}

// ── BehaviorContext — provides model app-wide ─────────────────
const BehaviorContext = React.createContext(null);
function BehaviorProvider({ children }) {
  const model = useBehaviorModel();
  return <BehaviorContext.Provider value={model}>{children}</BehaviorContext.Provider>;
}
function useBehavior() { return React.useContext(BehaviorContext) || {}; }

// ── PersonalizedDashboard — reorders home sections ─────────────
function PersonalizedDashboard({ sections, C, children }) {
  const { rankSections, track } = useBehavior();
  const [ranked, setRanked] = useState(sections);
  const [showHint, setShowHint] = useState(false);

  useEffect(() => {
    const r = rankSections(sections);
    const changed = r.some((s, i) => s.id !== sections[i]?.id);
    if (changed) { setRanked(r); setShowHint(true); setTimeout(() => setShowHint(false), 3000); }
    else setRanked(r);
  }, [sections]);

  return (
    <div>
      {showHint && (
        <div role="status" aria-live="polite" style={{ margin: '0 20px 10px', display: 'flex', alignItems: 'center', gap: 8, background: 'transparent' }}>
          <span style={{ fontSize: 12 }}>✨</span>
          <span style={{ fontSize: 12, color: C.sub }}>Layout personalised for you</span>
        </div>
      )}
      {ranked.map(section => (
        <div key={section.id} onClick={() => track(section.id)}>
          {children(section)}
        </div>
      ))}
    </div>
  );
}

// ── SmartGreeting — time + behavior aware greeting ─────────────
function SmartGreeting({ userName, C }) {
  const { scores } = useBehavior();
  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';
  const topCategory = Object.entries(scores)
    .filter(([k]) => !k.endsWith('_ts'))
    .sort((a, b) => b[1] - a[1])[0]?.[0];

  const hints = {
    'view:stores':   '🏪 Your favourite stores are waiting',
    'view:cart':     '🛒 You left items in your cart',
    'view:meal-planner': '🍽️ Ready to plan your meals?',
    'view:wallet':   '💰 Check your Errand wallet',
  };
  const hint = hints[topCategory] || '🛍️ What can we get you today?';

  return (
    <div aria-label={`${greeting}, ${userName || 'there'}`}>
      <div style={{ fontSize: 13, color: C.sub, marginBottom: 2 }}>{greeting} 👋</div>
      <div className="disp" style={{ fontSize: 22, color: C.text, lineHeight: 1.2 }}>{userName || 'Lagos'}</div>
      <div style={{ fontSize: 12, color: C.muted, marginTop: 4 }}>{hint}</div>
    </div>
  );
}

// ── BehaviorNudge — contextual CTA based on predicted engagement ──
function BehaviorNudge({ action, C, children }) {
  const { predictEngagement } = useBehavior();
  const level = predictEngagement(action);
  if (level === 'low') return null; // don't show if not engaged
  return (
    <div style={{ opacity: level === 'high' ? 1 : 0.8, transform: level === 'high' ? 'scale(1.01)' : 'none', transition: 'all .2s' }}>
      {children}
    </div>
  );
}

// ────────────────────────────────────────────────────────────────
//  ACCESSIBILITY — WCAG 2.2
// ────────────────────────────────────────────────────────────────

// ── useAnnouncer — polite/assertive live region ────────────────
function useAnnouncer() {
  const [polite,    setPolite]    = useState('');
  const [assertive, setAssertive] = useState('');

  const announce = useCallback((msg, priority = 'polite') => {
    // Clear then re-set to force screen reader re-read
    if (priority === 'assertive') { setAssertive(''); setTimeout(() => setAssertive(msg), 50); }
    else { setPolite(''); setTimeout(() => setPolite(msg), 50); }
  }, []);

  const AnnouncerRegion = () => (
    <>
      <div role="status"  aria-live="polite"     aria-atomic="true" className="sr-only">{polite}</div>
      <div role="alert"   aria-live="assertive"  aria-atomic="true" className="sr-only">{assertive}</div>
    </>
  );

  return { announce, AnnouncerRegion };
}

// ── AnnouncerContext ───────────────────────────────────────────
const AnnouncerContext = React.createContext(null);
function AnnouncerProvider({ children }) {
  const { announce, AnnouncerRegion } = useAnnouncer();
  return (
    <AnnouncerContext.Provider value={announce}>
      <AnnouncerRegion />
      {children}
    </AnnouncerContext.Provider>
  );
}
function useAnnounce() { return React.useContext(AnnouncerContext) || (() => {}); }

// ── useKeyboardMode — detects Tab key, adds .kb-nav for focus rings ──
function useKeyboardMode() {
  const [isKb, setIsKb] = useState(false);
  useEffect(() => {
    const onKey = (e) => { if (e.key === 'Tab') { setIsKb(true); document.body.classList.add('kb-nav'); } };
    const onMouse = () => { setIsKb(false); document.body.classList.remove('kb-nav'); };
    window.addEventListener('keydown', onKey);
    window.addEventListener('mousedown', onMouse);
    return () => { window.removeEventListener('keydown', onKey); window.removeEventListener('mousedown', onMouse); };
  }, []);
  return isKb;
}

// ── SkipLink — keyboard shortcut to main content ──────────────
function SkipLink({ C }) {
  return (
    <a
      href="#main-content"
      style={{ position: 'fixed', top: -60, left: 12, zIndex: 99999, background: C?.accent || '#FF4D1A', color: '#fff', padding: '10px 18px', borderRadius: 8, fontWeight: 700, fontSize: 14, textDecoration: 'none', transition: 'top .15s', fontFamily: "Satoshi,system-ui,sans-serif" }}
      onFocus={e => { e.currentTarget.style.top = '12px'; }}
      onBlur={e => { e.currentTarget.style.top = '-60px'; }}
    >
      Skip to main content
    </a>
  );
}

// ── FocusTrap — traps keyboard focus inside modals ────────────
function FocusTrap({ children, active, onEscape }) {
  const ref = useRef(null);

  useEffect(() => {
    if (!active) return;
    const el = ref.current;
    if (!el) return;

    const focusable = () => Array.from(el.querySelectorAll(
      'a[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),textarea:not([disabled]),[tabindex]:not([tabindex="-1"])'
    )).filter(e => !e.hidden && e.offsetParent !== null);

    const onKey = (e) => {
      if (e.key === 'Escape') { onEscape?.(); return; }
      if (e.key !== 'Tab') return;
      const items = focusable();
      if (!items.length) { e.preventDefault(); return; }
      const first = items[0], last = items[items.length - 1];
      if (e.shiftKey) { if (document.activeElement === first) { e.preventDefault(); last.focus(); } }
      else { if (document.activeElement === last) { e.preventDefault(); first.focus(); } }
    };

    // Auto-focus first element
    setTimeout(() => focusable()[0]?.focus(), 50);
    el.addEventListener('keydown', onKey);
    return () => el.removeEventListener('keydown', onKey);
  }, [active, onEscape]);

  return <div ref={ref}>{children}</div>;
}

// ── AccessibleBtn — full ARIA button with keyboard + haptic ───
function AccessibleBtn({ children, onClick, C, variant = 'primary', sm, block, style: extraStyle, 'aria-label': ariaLabel, disabled, loading, icon }) {
  const [pressed, setPressed] = useState(false);
  const announce = useAnnounce();

  const handleClick = (e) => {
    if (disabled || loading) return;
    if ('vibrate' in navigator) navigator.vibrate(6);
    announce(ariaLabel || (typeof children === 'string' ? children : ''), 'polite');
    onClick?.(e);
  };

  const baseStyle = {
    display: block ? 'flex' : 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 7,
    minHeight: 44, padding: sm ? '8px 16px' : '11px 22px',
    borderRadius: 'var(--r-pill)', border: 'none', cursor: disabled ? 'not-allowed' : 'pointer',
    fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700,
    fontSize: sm ? 13 : 15, letterSpacing: '0.01em',
    width: block ? '100%' : 'auto',
    opacity: disabled ? 0.45 : loading ? 0.7 : 1,
    transform: pressed ? 'scale(.96)' : 'scale(1)',
    transition: 'transform .12s var(--ease-spring), opacity .15s, box-shadow .15s',
    outline: 'none', position: 'relative', overflow: 'hidden',
    ...(variant === 'primary' ? { background: C.accent, color: '#fff', boxShadow: pressed ? 'none' : `0 2px 12px ${C.accentGlow}` } :
        variant === 'outline' ? { background: 'transparent', color: C.accent, border: `1.5px solid ${C.accentLine}` } :
        variant === 'ghost'   ? { background: C.accentBg,   color: C.accent } :
                                { background: C.card,        color: C.text, border: `1px solid ${C.border}` }),
    ...extraStyle,
  };

  return (
    <button
      style={baseStyle}
      onClick={handleClick}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      onTouchStart={() => setPressed(true)}
      onTouchEnd={() => setPressed(false)}
      disabled={disabled || loading}
      aria-disabled={disabled || loading}
      aria-busy={loading}
      aria-label={ariaLabel}
      className="btn-ripple"
    >
      {loading
        ? <div style={{ width: 16, height: 16, border: '2.5px solid currentColor', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin .6s linear infinite' }} aria-hidden="true" />
        : <>
            {icon && <span aria-hidden="true">{icon}</span>}
            {children}
          </>
      }
    </button>
  );
}

// ── AccessibleInput — labelled input with description ─────────
function AccessibleInput({ label, id, hint, error, C, ...props }) {
  const inputId = id || `input-${label?.replace(/\s+/g,'-').toLowerCase()}`;
  const hintId  = hint  ? `${inputId}-hint`  : undefined;
  const errId   = error ? `${inputId}-error` : undefined;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
      {label && (
        <label htmlFor={inputId} style={{ fontSize: 13, fontWeight: 600, color: C?.sub, fontFamily: "Satoshi,system-ui,sans-serif" }}>
          {label}
        </label>
      )}
      <input
        id={inputId}
        className="input-base"
        aria-describedby={[hintId, errId].filter(Boolean).join(' ') || undefined}
        aria-invalid={!!error}
        style={{ borderColor: error ? C?.red : undefined }}
        {...props}
      />
      {hint  && <span id={hintId}  style={{ fontSize: 12, color: C?.muted }}>{hint}</span>}
      {error && <span id={errId}   style={{ fontSize: 12, color: C?.red }} role="alert">{error}</span>}
    </div>
  );
}

// ── useKeyboardNav — arrow key navigation for lists ────────────
function useKeyboardNav(items, { onSelect, loop = true } = {}) {
  const [activeIdx, setActiveIdx] = useState(-1);
  const refs = useRef([]);

  const onKeyDown = useCallback((e) => {
    const len = items.length;
    if (!len) return;
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setActiveIdx(i => { const n = loop ? (i + 1) % len : Math.min(i + 1, len - 1); refs.current[n]?.focus(); return n; });
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActiveIdx(i => { const n = loop ? (i - 1 + len) % len : Math.max(i - 1, 0); refs.current[n]?.focus(); return n; });
    } else if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      if (activeIdx >= 0) onSelect?.(items[activeIdx], activeIdx);
    } else if (e.key === 'Escape') {
      setActiveIdx(-1);
    }
  }, [items, activeIdx, onSelect, loop]);

  const getItemProps = (idx) => ({
    ref: el => { refs.current[idx] = el; },
    tabIndex: activeIdx === idx ? 0 : -1,
    'aria-selected': activeIdx === idx,
    onKeyDown,
    onFocus: () => setActiveIdx(idx),
  });

  return { activeIdx, setActiveIdx, getItemProps, onKeyDown };
}

// ── HighContrastToggle — WCAG enhanced display switch ─────────
function HighContrastToggle({ C }) {
  const [hc, setHc] = useState(() => {
    try { return safeStorage.getItem('errand-hc') === '1'; } catch { return false; }
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-hc', hc ? '1' : '0');
    try { safeStorage.setItem('errand-hc', hc ? '1' : '0'); } catch {}
  }, [hc]);

  return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '11px 14px', background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, marginBottom: 10 }}>
      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
        <span style={{ fontSize: 18 }} aria-hidden="true">👁</span>
        <div>
          <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>High Contrast</div>
          <div style={{ fontSize: 12, color: C.muted }}>Increases text and border contrast</div>
        </div>
      </div>
      <button
        role="switch"
        aria-checked={hc}
        aria-label="Toggle high contrast mode"
        onClick={() => setHc(h => !h)}
        style={{ width: 44, height: 26, borderRadius: 13, background: hc ? C.accent : C.border, border: 'none', cursor: 'pointer', position: 'relative', transition: 'background .22s', flexShrink: 0, padding: 0 }}
      >
        <div style={{ position: 'absolute', top: 3, left: hc ? 21 : 3, width: 20, height: 20, borderRadius: 10, background: '#fff', transition: 'left .22s', boxShadow: '0 1px 4px rgba(0,0,0,.25)' }} />
        <span className="sr-only">{hc ? 'On' : 'Off'}</span>
      </button>
    </div>
  );
}

// ── TextSizeControl — WCAG 1.4.4 text resize control ──────────
function TextSizeControl({ C }) {
  const [scale, setScale] = useState(() => {
    try { return parseFloat(safeStorage.getItem('errand-textscale') || '1'); } catch { return 1; }
  });

  useEffect(() => {
    document.documentElement.style.setProperty('--text-scale', String(scale));
    document.documentElement.style.fontSize = `${scale * 15}px`;
    try { safeStorage.setItem('errand-textscale', String(scale)); } catch {}
  }, [scale]);

  const sizes = [{ label: 'A', s: 0.85 }, { label: 'A', s: 1 }, { label: 'A', s: 1.18 }, { label: 'A', s: 1.35 }];

  return (
    <div style={{ padding: '11px 14px', background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, marginBottom: 10 }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
        <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>Text Size</div>
        <div style={{ fontSize: 12, color: C.muted }}>{Math.round(scale * 100)}%</div>
      </div>
      <div role="radiogroup" aria-label="Text size" style={{ display: 'flex', gap: 8 }}>
        {sizes.map(({ label, s }) => (
          <button
            key={s}
            role="radio"
            aria-checked={scale === s}
            onClick={() => setScale(s)}
            style={{ flex: 1, height: 40, borderRadius: 10, border: `2px solid ${scale === s ? C.accent : C.border}`, background: scale === s ? C.accentBg : C.surface, color: scale === s ? C.accent : C.sub, fontFamily: "Syne,sans-serif", fontWeight: 700, fontSize: s * 14, cursor: 'pointer', transition: 'all .15s' }}
          >
            {label}
          </button>
        ))}
      </div>
    </div>
  );
}

// ── ReducedMotionToggle ────────────────────────────────────────
function ReducedMotionToggle({ C }) {
  const [reduced, setReduced] = useState(() => {
    try { return safeStorage.getItem('errand-reduced-motion') === '1' || window.matchMedia('(prefers-reduced-motion: reduce)').matches; }
    catch { return false; }
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-reduced-motion', reduced ? '1' : '0');
    try { safeStorage.setItem('errand-reduced-motion', reduced ? '1' : '0'); } catch {}
    if (reduced) document.documentElement.style.setProperty('--dur-base', '0ms');
    else document.documentElement.style.removeProperty('--dur-base');
  }, [reduced]);

  return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '11px 14px', background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, marginBottom: 10 }}>
      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
        <span style={{ fontSize: 18 }} aria-hidden="true">⚡</span>
        <div>
          <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text }}>Reduce Motion</div>
          <div style={{ fontSize: 12, color: C.muted }}>Minimises animations and transitions</div>
        </div>
      </div>
      <button role="switch" aria-checked={reduced} aria-label="Reduce Motion" onClick={() => setReduced(r => !r)}
        style={{ width: 44, height: 26, borderRadius: 13, background: reduced ? C.accent : C.border, border: 'none', cursor: 'pointer', position: 'relative', transition: 'background .22s', flexShrink: 0, padding: 0 }}>
        <div style={{ position: 'absolute', top: 3, left: reduced ? 21 : 3, width: 20, height: 20, borderRadius: 10, background: '#fff', transition: 'left .22s' }} />
        <span className="sr-only">{reduced ? 'On' : 'Off'}</span>
      </button>
    </div>
  );
}

// ── AccessibilityPanel — full a11y settings hub ───────────────
function AccessibilityPanel({ C, onClose }) {
  return (
    <div role="dialog" aria-modal="true" aria-label="Accessibility settings">
      <FocusTrap active onEscape={onClose}>
        <div style={{ padding: '20px 20px 40px' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
            <div className="disp" style={{ fontSize: 20, color: C.text }}>♿ Accessibility</div>
            <button onClick={onClose} aria-label="Close accessibility settings" style={{ width: 36, height: 36, borderRadius: 10, background: C.surface, border: `1px solid ${C.border}`, cursor: 'pointer', fontSize: 16, color: C.sub }}>✕</button>
          </div>
          <div style={{ marginBottom: 8 }} className="section-label">Display</div>
          <HighContrastToggle C={C} />
          <TextSizeControl C={C} />
          <ReducedMotionToggle C={C} />
          <div style={{ marginBottom: 8, marginTop: 16 }} className="section-label">Navigation</div>
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: '12px 14px', marginBottom: 10 }}>
            <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text, marginBottom: 4 }}>Keyboard Navigation</div>
            <div style={{ fontSize: 12, color: C.muted, lineHeight: 1.6 }}>
              Tab — move forward · Shift+Tab — move back<br />
              Arrow keys — navigate lists · Enter/Space — activate<br />
              Escape — close overlays · H — go home
            </div>
          </div>
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: '12px 14px' }}>
            <div style={{ fontWeight: 600, fontSize: 13.5, color: C.text, marginBottom: 4 }}>Screen Reader</div>
            <div style={{ fontSize: 12, color: C.muted }}>Optimised for NVDA, VoiceOver, and TalkBack. Status updates announced automatically.</div>
          </div>
        </div>
      </FocusTrap>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
//  MOBILE-FIRST ENHANCEMENTS
//  Service Worker · Touch gestures · Swipe nav · Pull-to-refresh
//  Leaflet map tiles · WebSocket live tracking · Touch targets
// ═══════════════════════════════════════════════════════════════

// ── SERVICE WORKER — blob-registered at runtime ───────────────

// ══════════════════════════════════════════════════════════════
//  PERFORMANCE LAYER
//  Lazy screens · Memo guards · Interaction tracing
// ══════════════════════════════════════════════════════════════

// Lazily mount heavy screens only when first visited
function useLazyMount(active) {
  const [mounted, setMounted] = useState(active);
  useEffect(() => { if (active && !mounted) setMounted(true); }, [active]);
  return mounted;
}

// Wrap a screen so it renders once visited and stays in DOM (hidden) thereafter
function LazyScreen({ active, children, C }) {
  const mounted = useLazyMount(active);
  if (!mounted) return null;
  return (
    <div style={{ display: active ? 'contents' : 'none' }} aria-hidden={!active}>
      {children}
    </div>
  );
}

// Debounce hook — prevents rapid re-renders on fast typing / scrolling
function useDebounce(value, delay = 300) {
  const [dv, setDv] = useState(value);
  useEffect(() => { const t = setTimeout(() => setDv(value), delay); return () => clearTimeout(t); }, [value, delay]);
  return dv;
}

// Throttle callback to at most once per `ms`
function useThrottle(fn, ms = 200) {
  const last = useRef(0);
  return useCallback((...args) => {
    const now = Date.now();
    if (now - last.current >= ms) { last.current = now; fn(...args); }
  }, [fn, ms]);
}

// Image with intersection-observer lazy loading + blur-up
function LazyImg({ src, alt, style, className, placeholder }) {
  const ref = useRef(null);
  const [loaded, setLoaded] = useState(false);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (!ref.current) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } }, { rootMargin: '200px' });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <div ref={ref} style={{ position: 'relative', overflow: 'hidden', ...style }} className={className}>
      {placeholder && !loaded && (
        <div style={{ position: 'absolute', inset: 0, background: placeholder, filter: 'blur(8px)', transform: 'scale(1.05)' }} />
      )}
      {visible && (
        <img
          src={src} alt={alt}
          onLoad={() => setLoaded(true)}
          style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: loaded ? 1 : 0, transition: 'opacity .3s ease', display: 'block' }}
        />
      )}
    </div>
  );
}

// Measure and report Web Vitals (LCP, FID, CLS) to console in dev
function useWebVitals() {
  useEffect(() => {
    if (typeof window === 'undefined') return;
    // LCP
    try {
      new PerformanceObserver(list => {
        const entries = list.getEntries();
        const lcp = entries[entries.length - 1];
        if (lcp) console.debug(`[Errand Perf] LCP: ${lcp.startTime.toFixed(0)}ms`);
      }).observe({ type: 'largest-contentful-paint', buffered: true });
    } catch (_) {}
    // FID / INP
    try {
      new PerformanceObserver(list => {
        list.getEntries().forEach(e => {
          if (e.processingStart) console.debug(`[Errand Perf] INP: ${(e.processingStart - e.startTime).toFixed(0)}ms`);
        });
      }).observe({ type: 'event', buffered: true, durationThreshold: 40 });
    } catch (_) {}
  }, []);
}

// Preload font + critical assets on idle
function useIdlePreload() {
  useEffect(() => {
    if (!('requestIdleCallback' in window)) return;
    requestIdleCallback(() => {
      // Preload Satoshi if not already loaded
      if (!document.querySelector('link[href*="satoshi"]')) {
        const link = document.createElement('link');
        link.rel = 'preload'; link.as = 'style';
        link.href = 'https://api.fontshare.com/v2/css?f[]=satoshi@400,500,700&display=swap';
        document.head.appendChild(link);
      }
    }, { timeout: 2000 });
  }, []);
}

const SW_SOURCE = `
const CACHE = 'errand-v3';
const FONT_CACHE = 'errand-fonts-v1';
const STATIC = ['/'];

self.addEventListener('install', e => {
  e.waitUntil(caches.open(CACHE).then(c => c.addAll(STATIC)).then(() => self.skipWaiting()));
});
self.addEventListener('activate', e => {
  e.waitUntil(caches.keys().then(keys => Promise.all(keys.filter(k=>k!==CACHE&&k!==FONT_CACHE).map(k=>caches.delete(k)))).then(()=>self.clients.claim()));
});
self.addEventListener('fetch', e => {
  const url = new URL(e.request.url);
  if (e.request.method !== 'GET') return;
  if (url.hostname.includes('anthropic')) return;
  if (url.hostname.includes('fonts.googleapis') || url.hostname.includes('fonts.gstatic')) {
    e.respondWith(caches.match(e.request).then(cached => cached || fetch(e.request).then(res => {
      const clone = res.clone();
      caches.open(FONT_CACHE).then(c => c.put(e.request, clone));
      return res;
    }).catch(() => cached)));
    return;
  }
  if (url.hostname.includes('tile.openstreetmap')) {
    e.respondWith(caches.match(e.request).then(cached => cached || fetch(e.request).then(res => {
      const clone = res.clone();
      caches.open(CACHE).then(c => c.put(e.request, clone));
      return res;
    }).catch(() => cached)));
    return;
  }
  e.respondWith(fetch(e.request).then(res => {
    if (res.ok) { const c = res.clone(); caches.open(CACHE).then(cache => cache.put(e.request, c)); }
    return res;
  }).catch(() => caches.match(e.request).then(c => c || new Response('Offline', {status:503}))));
});
self.addEventListener('push', e => {
  const d = e.data?.json() || {};
  e.waitUntil(self.registration.showNotification(d.title||'Errand', {
    body: d.body||'New update', icon: '/icon-192.png', badge: '/icon-96.png',
    tag: d.tag||'errand', data: d.url||'/', vibrate:[200,100,200], actions: d.actions||[]
  }));
});
self.addEventListener('notificationclick', e => {
  e.notification.close();
  e.waitUntil(self.clients.matchAll({type:'window'}).then(cls => {
    const w = cls.find(c=>'focus' in c); if(w) return w.focus();
    return self.clients.openWindow(e.notification.data||'/');
  }));
});
self.addEventListener('sync', e => {
  if (e.tag==='order-sync') e.waitUntil(self.clients.matchAll().then(cs=>cs.forEach(c=>c.postMessage({type:'SYNC_ORDERS'}))));
});
`;

function useServiceWorker() {
  const [swState, setSwState] = useState('idle'); // idle | registering | active | error
  const [offlineReady, setOfflineReady] = useState(false);
  const swRef = useRef(null);

  useEffect(() => {
    if (!('serviceWorker' in navigator)) { setSwState('unsupported'); return; }

    // Register via blob URL (single-file architecture)
    const blob = new Blob([SW_SOURCE], { type: 'application/javascript' });
    const swUrl = URL.createObjectURL(blob);
    setSwState('registering');

    navigator.serviceWorker.register(swUrl, { scope: '/' })
      .then(reg => {
        swRef.current = reg;
        setSwState('active');
        // Check for updates every 60s
        const interval = setInterval(() => reg.update(), 60000);
        // Listen for offline ready
        reg.addEventListener('updatefound', () => {
          const newSW = reg.installing;
          newSW?.addEventListener('statechange', () => {
            if (newSW.state === 'installed') setOfflineReady(true);
          });
        });
        return () => clearInterval(interval);
      })
      .catch(err => {
        console.warn('SW registration failed (likely blob restriction):', err);
        setSwState('error');
      });

    // Listen for messages from SW
    const onMsg = (e) => {
      if (e.data?.type === 'SYNC_ORDERS') window.dispatchEvent(new Event('errand:sync'));
    };
    navigator.serviceWorker.addEventListener('message', onMsg);
    return () => navigator.serviceWorker.removeEventListener('message', onMsg);
  }, []);

  const triggerSync = () => {
    swRef.current?.sync?.register('order-sync').catch(() => {});
  };

  return { swState, offlineReady, triggerSync };
}

// ── SW status banner ──────────────────────────────────────────
function SWStatusBadge({ C }) {
  const { swState, offlineReady } = useServiceWorker();
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (offlineReady) { setShow(true); setTimeout(() => setShow(false), 4000); }
  }, [offlineReady]);

  if (!show) return null;
  return (
    <div style={{ position: 'fixed', bottom: 80, left: '50%', transform: 'translateX(-50%)', zIndex: 9000, background: C.green, borderRadius: 22, padding: '8px 18px', display: 'flex', alignItems: 'center', gap: 8, boxShadow: `0 4px 20px ${C.green}44`, animation: 'up .3s ease' }}>
      <span style={{ fontSize: 16 }}>✓</span>
      <span style={{ color: '#fff', fontWeight: 700, fontSize: 13, fontFamily: "Satoshi,system-ui,sans-serif" }}>App ready for offline use</span>
    </div>
  );
}

// ── useSwipeGesture — directional swipe detector ──────────────
function useSwipeGesture({ onSwipeLeft, onSwipeRight, onSwipeDown, threshold = 52, velocityThreshold = 0.3 } = {}) {
  const touch = useRef(null);
  const el    = useRef(null);

  const onTouchStart = useCallback((e) => {
    const t = e.touches[0];
    touch.current = { x: t.clientX, y: t.clientY, time: Date.now() };
  }, []);

  const onTouchEnd = useCallback((e) => {
    if (!touch.current) return;
    const t   = e.changedTouches[0];
    const dx  = t.clientX - touch.current.x;
    const dy  = t.clientY - touch.current.y;
    const dt  = Date.now() - touch.current.time;
    const vx  = Math.abs(dx) / dt;
    const vy  = Math.abs(dy) / dt;
    touch.current = null;

    // Require swipe to be more horizontal than vertical (or vice versa for down)
    if (Math.abs(dy) > 80 && vy > velocityThreshold && Math.abs(dy) > Math.abs(dx) * 1.5) {
      if (dy > 0) onSwipeDown?.();
      return;
    }
    if (Math.abs(dx) < threshold) return;
    if (Math.abs(dx) < Math.abs(dy) * 1.2) return; // mostly vertical
    if (vx < velocityThreshold && Math.abs(dx) < threshold * 1.5) return;
    if (dx < 0) onSwipeLeft?.();
    else onSwipeRight?.();
  }, [onSwipeLeft, onSwipeRight, onSwipeDown, threshold, velocityThreshold]);

  return { ref: el, touchHandlers: { onTouchStart, onTouchEnd } };
}

// ── usePullToRefresh ──────────────────────────────────────────
function usePullToRefresh(onRefresh) {
  const [pulling, setPulling] = useState(false);
  const [pullY, setPullY] = useState(0);
  const startY = useRef(null);
  const scrollEl = useRef(null);
  const THRESHOLD = 72;

  const onTouchStart = (e) => {
    const el = e.currentTarget;
    if (el.scrollTop === 0) startY.current = e.touches[0].clientY;
  };
  const onTouchMove = (e) => {
    if (!startY.current) return;
    const dy = e.touches[0].clientY - startY.current;
    if (dy > 0) { setPullY(Math.min(dy * 0.55, THRESHOLD + 20)); e.preventDefault(); }
  };
  const onTouchEnd = async () => {
    if (pullY >= THRESHOLD) { setPulling(true); await onRefresh?.(); setPulling(false); }
    setPullY(0); startY.current = null;
  };

  return { pullY, pulling, pullHandlers: { onTouchStart, onTouchMove: onTouchMove, onTouchEnd }, THRESHOLD };
}

// ── PullIndicator ─────────────────────────────────────────────
function PullIndicator({ pullY, pulling, threshold, C }) {
  if (pullY < 8 && !pulling) return null;
  const pct = Math.min(pullY / threshold, 1);
  return (
    <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: pullY, display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', zIndex: 50, pointerEvents: 'none' }}>
      <div style={{ width: 36, height: 36, borderRadius: '50%', background: C.card, border: `1.5px solid ${C.accentLine}`, display: 'flex', alignItems: 'center', justifyContent: 'center', transform: `rotate(${pct * 360}deg)`, transition: pulling ? 'none' : 'transform .1s', boxShadow: `0 2px 12px ${C.accentGlow}` }}>
        {pulling
          ? <div style={{ width: 16, height: 16, border: `2.5px solid ${C.accent}`, borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin .7s linear infinite' }} />
          : <span style={{ fontSize: 14, opacity: pct }}>↓</span>}
      </div>
    </div>
  );
}

// ── SwipeableScreen — wraps screens with gesture navigation ───
function SwipeableScreen({ children, onSwipeBack, onSwipeForward, C, enablePTR, onRefresh }) {
  const [flashDir, setFlashDir] = useState(null);
  const { pullY, pulling, pullHandlers, THRESHOLD } = usePullToRefresh(onRefresh);

  const { touchHandlers } = useSwipeGesture({
    onSwipeRight: () => {
      if (!onSwipeBack) return;
      setFlashDir('right');
      setTimeout(() => { setFlashDir(null); onSwipeBack(); }, 120);
    },
    onSwipeLeft: () => {
      if (!onSwipeForward) return;
      setFlashDir('left');
      setTimeout(() => { setFlashDir(null); onSwipeForward(); }, 120);
    },
  });

  return (
    <div
      {...touchHandlers}
      {...(enablePTR ? pullHandlers : {})}
      style={{ position: 'relative', height: '100%', overflow: 'hidden',
        transform: flashDir === 'right' ? 'translateX(8px)' : flashDir === 'left' ? 'translateX(-8px)' : 'none',
        transition: flashDir ? 'transform .12s ease' : 'none' }}
    >
      {enablePTR && <PullIndicator pullY={pullY} pulling={pulling} threshold={THRESHOLD} C={C} />}
      <div style={{ height: '100%', overflow: 'hidden auto', transform: pullY > 0 ? `translateY(${pullY}px)` : 'none', transition: pullY > 0 ? 'none' : 'transform .3s ease' }}>
        {children}
      </div>
    </div>
  );
}

// ── Leaflet Map — real tiles + live Lagos tracking ─────────────
function LeafletTrackingMap({ shopperPos, customerPos, storePos, eta, C }) {
  const mapRef   = useRef(null);
  const leafRef  = useRef(null);   // Leaflet map instance
  const shopRef  = useRef(null);   // shopper marker
  const routeRef = useRef(null);   // routing line
  const [loaded, setLoaded] = useState(false);
  const [error, setError]   = useState(false);

  // Defaults for Lagos VI demo
  const STORE_COORD    = storePos    || [6.4271, 3.4144];
  const CUSTOMER_COORD = customerPos || [6.4378, 3.4251];
  const SHOPPER_INIT   = shopperPos  || [6.4310, 3.4190];

  useEffect(() => {
    // Dynamically load Leaflet CSS + JS
    const loadLeaflet = async () => {
      if (window.L) { initMap(); return; }

      const css = document.createElement('link');
      css.rel = 'stylesheet';
      css.href = 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css';
      document.head.appendChild(css);

      await new Promise((res, rej) => {
        const s = document.createElement('script');
        s.src = 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js';
        s.onload = res; s.onerror = rej;
        document.head.appendChild(s);
      });
      initMap();
    };

    const initMap = () => {
      if (!mapRef.current || leafRef.current) return;
      const L = window.L;

      const map = L.map(mapRef.current, {
        center: [6.431, 3.419],
        zoom: 15,
        zoomControl: false,
        attributionControl: false,
      });
      leafRef.current = map;

      // Dark tile layer (Carto Dark Matter) or light (Carto Positron)
      const tileUrl = C.dark
        ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'
        : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

      L.tileLayer(tileUrl, {
        attribution: '© OpenStreetMap © Carto',
        subdomains: 'abcd', maxZoom: 19,
      }).addTo(map);

      // Custom SVG icon helper
      const mkIcon = (emoji, color, size=36) => L.divIcon({
        className: '',
        iconSize:  [size, size],
        iconAnchor:[size/2, size],
        html: `<div style="width:${size}px;height:${size}px;border-radius:50%;background:${color};display:flex;align-items:center;justify-content:center;font-size:${size*.5}px;box-shadow:0 3px 12px ${color}88;border:2.5px solid #fff;">${emoji}</div>`
      });

      // Store marker
      L.marker(STORE_COORD, { icon: mkIcon('🏪', '#6366F1') })
        .bindPopup('<b>FoodMart VI</b><br>Your pickup store')
        .addTo(map);

      // Customer marker
      L.marker(CUSTOMER_COORD, { icon: mkIcon('🏠', '#22C55E') })
        .bindPopup('<b>Your location</b>')
        .addTo(map);

      // Shopper marker (animated)
      const shopperMarker = L.marker(SHOPPER_INIT, { icon: mkIcon('🛵', C.accent), zIndexOffset: 1000 })
        .bindPopup('<b>Your shopper</b><br>Emmanuel O.')
        .addTo(map);
      shopRef.current = shopperMarker;

      // Route polyline (dashed)
      const route = L.polyline([STORE_COORD, SHOPPER_INIT, CUSTOMER_COORD], {
        color: C.accent, weight: 3, opacity: 0.75, dashArray: '8 5'
      }).addTo(map);
      routeRef.current = route;

      // Fit bounds
      map.fitBounds([STORE_COORD, SHOPPER_INIT, CUSTOMER_COORD], { padding: [30, 30] });

      // Zoom controls (custom position)
      L.control.zoom({ position: 'bottomleft' }).addTo(map);
      L.control.attribution({ position: 'bottomright', prefix: '' }).addTo(map);

      setLoaded(true);
    };

    loadLeaflet().catch(() => setError(true));
    return () => {
      if (leafRef.current) { leafRef.current.remove(); leafRef.current = null; }
    };
  }, []);

  // Animate shopper marker when position updates
  useEffect(() => {
    if (!shopRef.current || !shopperPos) return;
    shopRef.current.setLatLng([shopperPos.lat, shopperPos.lng]);
    // Update route
    if (routeRef.current) {
      routeRef.current.setLatLngs([STORE_COORD, [shopperPos.lat, shopperPos.lng], CUSTOMER_COORD]);
    }
  }, [shopperPos]);

  if (error) return <LiveMapCanvas shopperPos={shopperPos} customerPos={customerPos} eta={eta} step={2} C={C} />;

  return (
    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
      <div ref={mapRef} style={{ width: '100%', height: '100%', borderRadius: 'inherit' }} />
      {!loaded && (
        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', background: C.card, flexDirection: 'column', gap: 12 }}>
          <div style={{ width: 36, height: 36, border: `3px solid ${C.accent}`, borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin .8s linear infinite' }} />
          <span style={{ color: C.sub, fontSize: 13 }}>Loading map…</span>
        </div>
      )}
      {/* ETA badge overlay */}
      {loaded && (
        <div style={{ position: 'absolute', bottom: 14, right: 14, zIndex: 1000, background: C.dark ? 'rgba(8,8,16,.92)' : 'rgba(255,255,255,.92)', border: `1px solid ${C.green}44`, borderRadius: 10, padding: '6px 14px', display: 'flex', alignItems: 'center', gap: 7, backdropFilter: 'blur(10px)' }}>
          <div className="pulse-dot" />
          <span style={{ color: C.green, fontWeight: 700, fontSize: 13, fontFamily: "Satoshi,system-ui,sans-serif" }}>ETA {eta || '18 min'}</span>
        </div>
      )}
    </div>
  );
}

// ── useRealtimeLocation — WebSocket position stream ───────────
function useRealtimeLocation(orderId) {
  const [shopperPos, setShopperPos]   = useState(null);
  const [wsStatus,  setWsStatus]      = useState('connecting'); // connecting | live | degraded | offline
  const [lastUpdate, setLastUpdate]   = useState(null);
  const wsRef    = useRef(null);
  const retryRef = useRef(null);
  const retries  = useRef(0);

  useEffect(() => {
    if (!orderId) return;

    const connect = () => {
      setWsStatus('connecting');
      // In production this would be wss://your-backend/location/:orderId
      // We use Supabase Realtime channel as the WS transport
      // Simulate location updates (demo mode — no backend required)
      {
        setWsStatus('live');
        let angle = 0;
        const BASE = { lat: 6.4310, lng: 3.4190 };
        const sim = setInterval(() => {
          angle += 0.04;
          setShopperPos({
            lat: BASE.lat + Math.sin(angle) * 0.002,
            lng: BASE.lng + Math.cos(angle) * 0.003,
            accuracy: 8 + Math.random() * 5,
            heading: (angle * 180 / Math.PI) % 360,
          });
          setLastUpdate(new Date());
        }, 2000);
        wsRef.current = { unsubscribe: () => clearInterval(sim) };
      }
    };

    connect();

    // Heartbeat — mark degraded if no update in 10s
    const heartbeat = setInterval(() => {
      if (lastUpdate && Date.now() - lastUpdate.getTime() > 10000) {
        setWsStatus('degraded');
      }
    }, 5000);

    return () => {
      wsRef.current?.unsubscribe?.();
      clearInterval(heartbeat);
      clearTimeout(retryRef.current);
    };
  }, [orderId]);

  return { shopperPos, wsStatus, lastUpdate };
}

// ── WS Status pill ────────────────────────────────────────────
function WSStatusPill({ status, C }) {
  const cfg = {
    connecting: { label: 'Connecting…', color: C.gold,   bg: C.goldBg   },
    live:       { label: 'Live',         color: C.green,  bg: C.greenBg  },
    degraded:   { label: 'Slow signal',  color: C.gold,   bg: C.goldBg   },
    offline:    { label: 'Offline',      color: C.red,    bg: C.redBg    },
  }[status] || { label: status, color: C.muted, bg: C.card };

  return (
    <div style={{ display: 'inline-flex', alignItems: 'center', gap: 5, background: cfg.bg, borderRadius: 20, padding: '3px 10px' }}>
      <div style={{ width: 6, height: 6, borderRadius: '50%', background: cfg.color, animation: status === 'live' ? 'blink 1.4s ease-in-out infinite' : 'none' }} />
      <span style={{ fontSize: 12, fontWeight: 700, color: cfg.color }}>{cfg.label}</span>
    </div>
  );
}

// ── Swipeable task card (for shoppers) ────────────────────────
function SwipeableOrderCard({ order, onAccept, onDecline, C }) {
  const [offsetX, setOffsetX] = useState(0);
  const [deciding, setDeciding] = useState(null);
  const startX = useRef(null);
  const SNAP = 90;

  const onTouchStart = e => { startX.current = e.touches[0].clientX; };
  const onTouchMove  = e => {
    if (!startX.current) return;
    const dx = e.touches[0].clientX - startX.current;
    setOffsetX(dx * 0.75);
  };
  const onTouchEnd   = () => {
    if (offsetX > SNAP)       { setDeciding('accept'); setTimeout(() => { onAccept?.(order); }, 350); }
    else if (offsetX < -SNAP) { setDeciding('decline'); setTimeout(() => { onDecline?.(order); }, 350); }
    else setOffsetX(0);
    startX.current = null;
  };

  const pct = Math.min(Math.abs(offsetX) / SNAP, 1);
  const dir = offsetX > 0 ? 'accept' : offsetX < 0 ? 'decline' : null;

  return (
    <div style={{ position: 'relative', overflow: 'hidden', borderRadius: 16, marginBottom: 10 }}>
      {/* Background hint */}
      <div style={{ position: 'absolute', inset: 0, borderRadius: 16, display: 'flex', alignItems: 'center', justifyContent: offsetX > 0 ? 'flex-start' : 'flex-end', paddingInline: 22, background: deciding === 'accept' || dir === 'accept' ? C.greenBg : C.redBg, opacity: pct, transition: 'background .15s' }}>
        <span style={{ fontSize: 28 }}>{dir === 'accept' ? '✓' : dir === 'decline' ? '✗' : ''}</span>
      </div>
      {/* Card */}
      <div
        onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}
        style={{ background: C.card, border: `1.5px solid ${deciding === 'accept' ? C.green : deciding === 'decline' ? C.red : C.border}`, borderRadius: 16, padding: '14px 15px', transform: `translateX(${offsetX}px)`, transition: offsetX === 0 ? 'transform .3s var(--ease-spring)' : 'none', cursor: 'grab', userSelect: 'none' }}
      >
        <div style={{ display: 'flex', gap: 11, alignItems: 'flex-start', marginBottom: 11 }}>
          <div style={{ width: 44, height: 44, borderRadius: 12, background: C.accentBg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, flexShrink: 0 }}>📦</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: C.text }}>Order #{order.id}</div>
            <div style={{ color: C.sub, fontSize: 12.5, marginTop: 2 }}>{order.store} · {order.items} items · {order.distance}</div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <div className="disp" style={{ fontSize: 15, color: C.accent }}>₦{order.payout.toLocaleString()}</div>
            <div style={{ color: C.muted, fontSize: 12, marginTop: 1 }}>payout</div>
          </div>
        </div>
        {/* Swipe hint */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div style={{ display: 'flex', gap: 6, alignItems: 'center', color: C.green, fontSize: 12, fontWeight: 600 }}>
            <span>←</span><span>Swipe right to accept</span>
          </div>
          <div style={{ display: 'flex', gap: 6, alignItems: 'center', color: C.red||'#EF4444', fontSize: 12, fontWeight: 600 }}>
            <span>Decline</span><span>→</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Touch-optimised Nav (larger targets, haptic feedback) ─────
function NavTouchTarget({ item, active, goTo, cartCount, notifBadge = 0, C }) {
  const [pressed, setPressed] = useState(false);

  const handlePress = () => {
    // Haptic feedback via Vibration API
    if ('vibrate' in navigator) navigator.vibrate(8);
    goTo(item.id);
  };

  return (
    <div
      onClick={handlePress}
      onTouchStart={() => setPressed(true)}
      onTouchEnd={() => setPressed(false)}
      role="link"
      aria-label={item.label}
      aria-current={active ? "page" : undefined}
      tabIndex={0}
      onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handlePress(); } }}
      style={{
        flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        minHeight: 56, // WCAG 2.5.5 - minimum 44px, we use 56px for comfort
        padding: '6px 4px', cursor: 'pointer',
        transform: pressed ? 'scale(.88)' : 'scale(1)',
        transition: 'transform .12s var(--ease-spring)',
        WebkitTapHighlightColor: 'transparent',
      }}
    >
      {active && <div style={{ position: 'absolute', top: 3, width: 20, height: 3, borderRadius: '0 0 3px 3px', background: `linear-gradient(90deg,${C.accent},#FF9500)` }} />}
      <div style={{ position: 'relative', width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', marginTop: 4 }}>
        <Icon name={item.icon} size={active ? 24 : 21} color={active ? C.accent : (C.dark ? 'rgba(255,255,255,.42)' : 'rgba(0,0,0,.32)')} strokeWidth={active ? 2.2 : 1.7} />
        {item.id === 'orders' && cartCount > 0 && (
          <div style={{ position: 'absolute', top: -4, right: -6, minWidth: 16, height: 16, borderRadius: 8, background: C.accent, color: '#fff', fontSize: 9, fontWeight: 800, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 3px', border: `2px solid ${C.bg}` }}>{cartCount > 9 ? '9+' : cartCount}</div>
        )}
        {item.id === 'notifications' && notifBadge > 0 && (
          <div style={{ position: 'absolute', top: -4, right: -6, minWidth: 16, height: 16, borderRadius: 8, background: '#EF4444', color: '#fff', fontSize: 9, fontWeight: 800, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 3px', border: `2px solid ${C.bg}`, animation: 'blink 2s ease-in-out infinite' }}>{notifBadge > 9 ? '9+' : notifBadge}</div>
        )}
      </div>
      <span style={{ fontSize: 12, fontWeight: active ? 700 : 500, color: active ? C.accent : (C.dark ? 'rgba(255,255,255,.4)' : 'rgba(0,0,0,.35)'), marginTop: 3, letterSpacing: .1, transition: 'color 200ms' }}>{item.label}</span>
    </div>
  );
}

// ── Screen size / foldable helper ─────────────────────────────
function useDeviceClass() {
  const [cls, setCls] = useState('mobile');
  useEffect(() => {
    const update = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;
      const ratio = w / h;
      // Foldable detection: unusually wide ratio on "mobile" user agent
      if (w >= 1024) setCls('desktop');
      else if (w >= 600 && ratio > 1.2) setCls('foldable');
      else if (w >= 600) setCls('tablet');
      else setCls('mobile');
    };
    update();
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);
  return cls;
}

// ── Foldable-aware layout hint ────────────────────────────────
function FoldableHint({ C }) {
  const cls = useDeviceClass();
  if (cls !== 'foldable') return null;
  return (
    <div style={{ margin: '0 20px 12px', background: C.purpleBg, border: `1px solid ${C.purpleLine}`, borderRadius: 11, padding: '9px 14px', display: 'flex', gap: 9, alignItems: 'center' }}>
      <span style={{ fontSize: 18 }}>📱</span>
      <span style={{ color: C.sub, fontSize: 12.5 }}>Foldable detected — landscape layout active</span>
    </div>
  );
}


