// ─────────────────────────────────────────────────────────────
//  1. MICRO-ANIMATIONS
// ─────────────────────────────────────────────────────────────

// ── useCountUp — animated number counter ─────────────────────
function useCountUp(target, { duration = 900, delay = 0, enabled = true } = {}) {
  const [value, setValue] = useState(0);
  const raf = useRef(null);

  useEffect(() => {
    if (!enabled) { setValue(target); return; }
    let start = null;
    const from = 0;
    const t = setTimeout(() => {
      const step = (ts) => {
        if (!start) start = ts;
        const p = Math.min((ts - start) / duration, 1);
        // Ease out expo
        const ease = p === 1 ? 1 : 1 - Math.pow(2, -10 * p);
        setValue(Math.round(from + (target - from) * ease));
        if (p < 1) raf.current = requestAnimationFrame(step);
      };
      raf.current = requestAnimationFrame(step);
    }, delay);
    return () => { clearTimeout(t); cancelAnimationFrame(raf.current); };
  }, [target, duration, delay, enabled]);

  return value;
}

// ── AnimatedNumber — drop-in counter display ─────────────────
function AnimatedNumber({ value, prefix = '', suffix = '', decimals = 0, C, style }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  const count = useCountUp(value, { enabled: visible, duration: 1100 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVisible(true); io.disconnect(); } }, { threshold: 0.3 });
    io.observe(el);
    return () => io.disconnect();
  }, []);

  const display = decimals > 0 ? (count / Math.pow(10, decimals)).toFixed(decimals) : count.toLocaleString();
  return (
    <span ref={ref} style={style}>{prefix}{display}{suffix}</span>
  );
}

// ── useStagger — staggered child reveal ──────────────────────
function StaggerList({ children, delayBase = 55, C }) {
  const items = React.Children.toArray(children);
  const visible = useStagger(items.length, { delayBase });
  return (
    <div>
      {items.map((child, i) => (
        <div key={i} style={{
          opacity:   visible[i] ? 1 : 0,
          transform: visible[i] ? 'none' : 'translateY(14px) scale(.985)',
          transition: `opacity 280ms ${i * delayBase}ms var(--ease-out), transform 280ms ${i * delayBase}ms var(--ease-out)`,
        }}>
          {child}
        </div>
      ))}
    </div>
  );
}

// ── StatusTransition — animated order status badge ───────────
function StatusTransition({ status, prev, C }) {
  const [animating, setAnimating] = useState(false);
  const [displayed, setDisplayed] = useState(status);

  useEffect(() => {
    if (status === displayed) return;
    setAnimating(true);
    const t = setTimeout(() => { setDisplayed(status); setAnimating(false); }, 260);
    return () => clearTimeout(t);
  }, [status]);

  const cfg = {
    pending:    { label: 'Pending',     color: '#F59E0B', bg: 'rgba(245,158,11,.1)',  icon: '🕐' },
    confirmed:  { label: 'Confirmed',   color: C.green,   bg: C.greenBg,              icon: '✓'  },
    shopping:   { label: 'Shopping',    color: C.accent,  bg: C.accentBg,             icon: '🛒'  },
    on_the_way: { label: 'On the way',  color: C.purple,  bg: C.purpleBg,             icon: '🛵'  },
    delivered:  { label: 'Delivered',   color: C.green,   bg: C.greenBg,              icon: '🎉'  },
    cancelled:  { label: 'Cancelled',   color: C.red,     bg: C.redBg,                icon: '✗'   },
  };
  const d = cfg[displayed] || cfg.pending;

  return (
    <div style={{
      display: 'inline-flex', alignItems: 'center', gap: 6,
      background: d.bg, border: `1px solid ${d.color}33`, borderRadius: 20,
      padding: '5px 12px',
      opacity: animating ? 0 : 1,
      transform: animating ? 'scale(.88) translateY(4px)' : 'scale(1) translateY(0)',
      transition: 'opacity 200ms var(--ease-out), transform 200ms var(--ease-spring)',
    }}
      role="status" aria-live="polite" aria-label={`Order status: ${d.label}`}
    >
      <span style={{ fontSize: 13 }}>{d.icon}</span>
      <span style={{ fontSize: 12.5, fontWeight: 700, color: d.color }}>{d.label}</span>
    </div>
  );
}

// ── CardEntrance — card with pop-in animation on mount ────────
function SkeletonToContent({ loading, skeleton, children }) {
  return (
    <div style={{ position: 'relative' }}>
      <div style={{ opacity: loading ? 1 : 0, transition: 'opacity 250ms', pointerEvents: loading ? 'auto' : 'none', position: loading ? 'static' : 'absolute', inset: 0 }}>
        {skeleton}
      </div>
      <div style={{ opacity: loading ? 0 : 1, transition: 'opacity 280ms 60ms var(--ease-out)' }}>
        {children}
      </div>
    </div>
  );
}

// ── Ripple — programmatic ripple on any element ───────────────
function RippleContainer({ children, color = 'rgba(255,255,255,.18)', style }) {
  const [ripples, setRipples] = useState([]);
  const addRipple = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const id = Date.now();
    setRipples(r => [...r, { x, y, id }]);
    setTimeout(() => setRipples(r => r.filter(rr => rr.id !== id)), 600);
  };
  return (
    <div style={{ position: 'relative', overflow: 'hidden', ...style }} onClick={addRipple}>
      {children}
      {ripples.map(r => (
        <span key={r.id} style={{
          position: 'absolute', left: r.x - 20, top: r.y - 20,
          width: 40, height: 40, borderRadius: '50%',
          background: color, pointerEvents: 'none',
          animation: 'rippleOut .55s var(--ease-out) forwards',
        }} />
      ))}
    </div>
  );
}

// ── MorphButton — morphs between states with animation ────────
function MorphButton({ states, currentState, onPress, C, style }) {
  // states = { idle: {label,icon,bg}, loading: {...}, done: {...} }
  const [animOut, setAnimOut] = useState(false);
  const [displayed, setDisplayed] = useState(currentState);

  useEffect(() => {
    if (currentState === displayed) return;
    setAnimOut(true);
    setTimeout(() => { setDisplayed(currentState); setAnimOut(false); }, 180);
  }, [currentState]);

  const s = states[displayed] || states.idle;
  return (
    <button onClick={onPress} className="btn-ripple"
      style={{
        display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 7,
        padding: '12px 24px', borderRadius: 13, border: 'none', cursor: 'pointer',
        background: s.bg || C.accent, color: s.color || '#fff',
        fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: 14.5,
        transition: 'background .3s var(--ease-out), box-shadow .2s',
        boxShadow: `0 4px 20px ${C.accentGlow}`,
        opacity: animOut ? 0 : 1, transform: animOut ? 'scale(.94)' : 'scale(1)',
        ...style,
      }}
    >
      {s.icon && <span style={{ fontSize: 15, transition: 'transform .3s var(--ease-spring)', transform: animOut ? 'scale(0)' : 'scale(1)' }}>{s.icon}</span>}
      {s.label}
    </button>
  );
}

// ─────────────────────────────────────────────────────────────
//  2. AI PERSONALISATION
// ─────────────────────────────────────────────────────────────

// ── usePersonalization — lightweight frequency + recency model ─
// No TF.js required — pure JS heuristic that mimics TF.js output
// (TF.js would be overkill for this signal; keep bundle lean)
function usePersonalization() {
  const [model, setModel] = useState(() => {
    try {
      const saved = safeStorage.getItem('errand-pdata');
      try { return saved ? JSON.parse(saved) : { events: [], scores: {} }; } catch { return { events: [], scores: {} }; }
    } catch { return { events: [], scores: {} }; }
  });

  // Track an interaction event
  const track = useCallback((action, context = {}) => {
    setModel(prev => {
      const now = Date.now();
      const event = { action, context, ts: now };
      // Keep last 200 events
      const events = [...prev.events.slice(-199), event];

      // Score = recency-weighted frequency
      // Decay factor: events older than 7 days lose weight
      const DECAY_MS = 7 * 24 * 60 * 60 * 1000;
      const scores = {};
      events.forEach(e => {
        const age = now - e.ts;
        const weight = Math.exp(-age / DECAY_MS);
        const key = e.action + (e.context.category ? ':' + e.context.category : '');
        scores[key] = (scores[key] || 0) + weight;
      });

      const next = { events, scores };
      try { safeStorage.setItem('errand-pdata', JSON.stringify(next)); } catch {}
      return next;
    });
  }, []);

  // Get top N actions by score
  const topActions = useCallback((n = 5) => {
    return Object.entries(model.scores)
      .sort((a, b) => b[1] - a[1])
      .slice(0, n)
      .map(([key, score]) => ({ key, score }));
  }, [model.scores]);

  // Score a single action (for ranking lists)
  const score = useCallback((action, category) => {
    const key = action + (category ? ':' + category : '');
    return model.scores[key] || 0;
  }, [model.scores]);

  // Suggest widget ordering based on visit frequency
  const widgetOrder = useCallback((widgets) => {
    return [...widgets].sort((a, b) => score(b.action, b.category) - score(a.action, a.category));
  }, [score]);

  // Clear all data
  const reset = useCallback(() => {
    setModel({ events: [], scores: {} });
    try { safeStorage.removeItem('errand-pdata'); } catch {}
  }, []);

  return { track, topActions, score, widgetOrder, reset, model };
}

