// ── LiveRegion — ARIA live region announcer ───────────────────
const LiveRegionContext = React.createContext(null);
function LiveRegionProvider({ children }) {
  const [msg, setMsg] = useState('');
  const announce = useCallback((text, priority = 'polite') => {
    setMsg(''); // Clear first to re-trigger
    setTimeout(() => setMsg(text), 50);
  }, []);
  return (
    <LiveRegionContext.Provider value={{ announce }}>
      {children}
      {/* Polite region (non-interrupting) */}
      <div aria-live="polite" aria-atomic="true" className="sr-only">{msg}</div>
      {/* Assertive region (screen reader interrupts) */}
      <div aria-live="assertive" aria-atomic="true" className="sr-only" id="a11y-assertive" />
    </LiveRegionContext.Provider>
  );
}
function useHighContrast() {
  const [hc, setHc] = useState(() => {
    try { return safeStorage.getItem('errand-hc') === 'true'; } catch { return false; }
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-hc', hc ? 'on' : 'off');
    try { safeStorage.setItem('errand-hc', hc); } catch {}
  }, [hc]);

  // Detect system preference
  useEffect(() => {
    const mq = window.matchMedia('(prefers-contrast: more)');
    if (mq.matches) setHc(true);
    const h = (e) => { if (e.matches) setHc(true); };
    mq.addEventListener('change', h);
    return () => mq.removeEventListener('change', h);
  }, []);

  return [hc, setHc];
}

// ── A11yContext — provides announce + high-contrast ───────────
const A11yContext = React.createContext(null);
function A11yProvider({ children }) {
  const [hc, setHc] = useHighContrast();
  useEffect(() => {
    if (hc) document.documentElement.setAttribute('data-high-contrast', '');
    else document.documentElement.removeAttribute('data-high-contrast');
  }, [hc]);
  return (
    <A11yContext.Provider value={{ hc, setHc }}>
      <LiveRegionProvider>
        {children}
      </LiveRegionProvider>
    </A11yContext.Provider>
  );
}
function useA11y() { return React.useContext(A11yContext) || {}; }

// ── AccessibleCard — semantic card with full keyboard support ─
function AccessibleCard({ children, onClick, label, description, C, style, tag = 'div' }) {
  const [focused, setFocused] = useState(false);
  const announce = useAnnounce();

  const handleClick = (e) => {
    onClick?.(e);
    if (label) announce(label);
  };

  const Tag = onClick ? 'button' : tag;
  return (
    <Tag
      onClick={handleClick}
      onFocus={() => setFocused(true)}
      onBlur={() => setFocused(false)}
      onKeyDown={e => { if ((e.key === 'Enter' || e.key === ' ') && onClick) { e.preventDefault(); handleClick(e); } }}
      aria-label={label}
      aria-describedby={description ? `desc-${label?.replace(/\s/g,'-')}` : undefined}
      style={{
        display: 'block', width: '100%', textAlign: 'left',
        background: C.card, border: `1.5px solid ${focused ? C.accent : C.border}`,
        borderRadius: 16, cursor: onClick ? 'pointer' : 'default',
        outline: 'none',
        boxShadow: focused ? `0 0 0 3px ${C.accentBg}, 0 0 0 1px ${C.accent}` : 'none',
        transition: 'border-color .15s, box-shadow .15s',
        ...style,
      }}
    >
      {description && <span id={`desc-${label?.replace(/\s/g,'-')}`} className="sr-only">{description}</span>}
      {children}
    </Tag>
  );
}

// ── FocusTrap — traps keyboard focus in modals/sheets ─────────
function useKeyboardList(count, onSelect) {
  const [focused, setFocused] = useState(-1);

  const onKeyDown = (e) => {
    if (e.key === 'ArrowDown')  { e.preventDefault(); setFocused(f => Math.min(f + 1, count - 1)); }
    if (e.key === 'ArrowUp')    { e.preventDefault(); setFocused(f => Math.max(f - 1, 0)); }
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); if (focused >= 0) onSelect(focused); }
    if (e.key === 'Home')       { e.preventDefault(); setFocused(0); }
    if (e.key === 'End')        { e.preventDefault(); setFocused(count - 1); }
    if (e.key === 'Escape')     { setFocused(-1); }
  };

  return { focusedIndex: focused, onKeyDown, setFocused };
}

function useVoiceCommands(commands) {
  // commands = [{ phrases: ['go home', 'home screen'], action: () => goTo('home') }]
  const [listening, setListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [supported, setSupported] = useState(false);
  const recog = useRef(null);

  useEffect(() => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { setSupported(false); return; }
    setSupported(true);

    const r = new SR();
    r.continuous  = false;
    r.interimResults = true;
    r.lang = 'en-NG'; // Nigerian English

    r.onresult = (e) => {
      const t = Array.from(e.results).map(r => r[0].transcript.toLowerCase()).join(' ');
      setTranscript(t);
      if (e.results[e.results.length - 1].isFinal) {
        const matched = commands.find(c => c.phrases.some(p => t.includes(p.toLowerCase())));
        if (matched) { matched.action(); setTranscript(''); }
      }
    };
    r.onend  = () => setListening(false);
    r.onerror = () => setListening(false);
    recog.current = r;
  }, [commands]);

  const start = () => {
    if (!recog.current || listening) return;
    recog.current.start();
    setListening(true);
  };
  const stop = () => {
    recog.current?.stop();
    setListening(false);
  };

  return { listening, transcript, supported, start, stop };
}

function VoiceButton({ goTo, C }) {
  const [expanded, setExpanded] = useState(false);
  const announce = useAnnounce();

  const cmds = [
    { phrases: ['go home', 'home', 'main screen'], action: () => { goTo('home'); announce('Going home'); setExpanded(false); } },
    { phrases: ['open cart', 'my cart', 'checkout'], action: () => { goTo('cart'); announce('Opening cart'); setExpanded(false); } },
    { phrases: ['track order', 'where is my order', 'tracking'], action: () => { goTo('tracking'); announce('Opening tracking'); setExpanded(false); } },
    { phrases: ['wallet', 'open wallet', 'my balance'], action: () => { goTo('wallet'); announce('Opening wallet'); setExpanded(false); } },
    { phrases: ['stores', 'browse stores', 'shop'], action: () => { goTo('stores'); announce('Opening stores'); setExpanded(false); } },
    { phrases: ['help', 'support', 'contact'], action: () => { goTo('support'); announce('Opening support'); setExpanded(false); } },
    { phrases: ['rewards', 'my points', 'points'], action: () => { goTo('rewards'); announce('Opening rewards'); setExpanded(false); } },
  ];

  const { listening, transcript, supported, start, stop } = useVoiceCommands(cmds);

  if (!supported) return null;

  return (
    <div style={{ position: 'fixed', bottom: 84, left: 20, zIndex: 250 }}>
      {/* Transcript bubble */}
      {transcript && (
        <div style={{ position: 'absolute', bottom: '110%', left: 0, background: C.card, border: `1px solid ${C.border}`, borderRadius: 10, padding: '7px 12px', fontSize: 12.5, color: C.text, whiteSpace: 'nowrap', boxShadow: 'var(--shadow-md)', marginBottom: 6 }}>
          <span style={{ color: C.muted }}>Heard: </span>{transcript}
        </div>
      )}
      {/* Commands hint */}
      {expanded && !listening && (
        <div style={{ position: 'absolute', bottom: '110%', left: 0, background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: '11px 14px', boxShadow: 'var(--shadow-lg)', minWidth: 200, marginBottom: 6, animation: 'scaleIn .18s var(--ease-spring)' }}>
          <div style={{ fontWeight: 700, fontSize: 12, color: C.text, marginBottom: 8 }}>Voice Commands</div>
          {cmds.slice(0, 5).map(c => (
            <div key={c.phrases[0]} style={{ fontSize: 12, color: C.sub, padding: '3px 0', borderBottom: `1px solid ${C.border}` }}>
              "{c.phrases[0]}"
            </div>
          ))}
          <div style={{ fontSize: 12, color: C.muted, marginTop: 7 }}>Say a command after pressing mic</div>
        </div>
      )}
      {/* Mic button */}
      <button
        onClick={() => { if (listening) stop(); else { setExpanded(false); start(); } }}
        onContextMenu={e => { e.preventDefault(); setExpanded(ex => !ex); }}
        aria-label={listening ? 'Stop voice command' : 'Start voice command (hold for help)'}
        aria-pressed={listening}
        style={{
          width: 44, height: 44, borderRadius: '50%', cursor: 'pointer',
          background: listening ? C.red || '#EF4444' : C.card,
          boxShadow: listening ? `0 0 0 6px ${C.red || '#EF4444'}22, var(--shadow-md)` : 'var(--shadow-md)',
          border: `1.5px solid ${listening ? (C.red || '#EF4444') : C.border}`,
          display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18,
          transition: 'all .2s var(--ease-spring)',
          animation: listening ? 'pulseRing 1s ease-out infinite' : 'none',
        }}
      >
        {listening ? '⏹' : '🎤'}
      </button>
    </div>
  );
}

// ── A11ySettings — accessibility control panel in Settings ────
function A11ySettings({ C }) {
  const { hc, setHc } = useA11y();
  const [fontSize, setFontSize] = useState(() => {
    try { return safeStorage.getItem('errand-fontsize') || 'base'; } catch { return 'base'; }
  });
  const [reduceMotion, setReduceMotion] = useState(() => {
    return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-fontsize', fontSize);
    try { safeStorage.setItem('errand-fontsize', fontSize); } catch {}
  }, [fontSize]);

  useEffect(() => {
    document.documentElement.setAttribute('data-reduce-motion', reduceMotion ? 'on' : 'off');
  }, [reduceMotion]);

  const options = [
    { id: 'sm',   label: 'Small',   px: '13px' },
    { id: 'base', label: 'Normal',  px: '15px' },
    { id: 'lg',   label: 'Large',   px: '17px' },
    { id: 'xl',   label: 'X-Large', px: '19px' },
  ];

  return (
    <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 16, padding: '14px 15px', marginBottom: 14 }}
      role="region" aria-label="Accessibility settings">
      <div className="disp" style={{ fontSize: 14, color: C.text, marginBottom: 14 }}>♿ Accessibility</div>

      {/* High contrast */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14, padding: '10px 12px', background: C.surface, borderRadius: 10 }}>
        <div>
          <div style={{ fontWeight: 600, fontSize: 13, color: C.text }}>High contrast</div>
          <div style={{ fontSize: 12, color: C.muted, marginTop: 2 }}>Increases colour contrast for readability</div>
        </div>
        <ToggleSwitch on={hc} onChange={() => setHc(h => !h)} C={C} label="Toggle high contrast mode" />
      </div>

      {/* Reduce motion */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14, padding: '10px 12px', background: C.surface, borderRadius: 10 }}>
        <div>
          <div style={{ fontWeight: 600, fontSize: 13, color: C.text }}>Reduce motion</div>
          <div style={{ fontSize: 12, color: C.muted, marginTop: 2 }}>Minimises animations and transitions</div>
        </div>
        <ToggleSwitch on={reduceMotion} onChange={() => setReduceMotion(m => !m)} C={C} label="Toggle reduced motion" />
      </div>

      {/* Font size */}
      <div style={{ padding: '10px 12px', background: C.surface, borderRadius: 10 }}>
        <div style={{ fontWeight: 600, fontSize: 13, color: C.text, marginBottom: 10 }}>Text size</div>
        <div style={{ display: 'flex', gap: 7 }} role="radiogroup" aria-label="Text size options">
          {options.map(o => (
            <button key={o.id} onClick={() => setFontSize(o.id)}
              role="radio" aria-checked={fontSize === o.id}
              aria-label={`${o.label} text`}
              style={{ flex: 1, padding: '8px 0', borderRadius: 9, border: `1.5px solid ${fontSize === o.id ? C.accent : C.border}`, background: fontSize === o.id ? C.accentBg : C.card, color: fontSize === o.id ? C.accent : C.sub, fontFamily: "Satoshi,system-ui,sans-serif", fontWeight: 700, fontSize: parseInt(o.px) - 2, cursor: 'pointer', transition: 'all .15s' }}>
              {o.label}
            </button>
          ))}
        </div>
      </div>

      {/* WCAG info */}
      <div style={{ marginTop: 10, padding: '8px 12px', background: C.greenBg, border: `1px solid ${C.greenLine}`, borderRadius: 9, display: 'flex', gap: 8, alignItems: 'center' }}>
        <span style={{ fontSize: 14 }}>✓</span>
        <span style={{ fontSize: 12, color: C.green, fontWeight: 600 }}>WCAG 2.2 AA compliant · Keyboard navigable · Screen reader friendly</span>
      </div>
    </div>
  );
}

