// useSpring — custom spring physics (no Framer Motion needed)
function useStaggeredList(items, { delayPerItem = 55, startDelay = 0 } = {}) {
  const [visible, setVisible] = useState([]);
  useEffect(() => {
    if (!items?.length) return;
    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReduced) { setVisible(items.map((_, i) => i)); return; }
    setVisible([]);
    const timers = items.map((_, i) =>
      setTimeout(() => setVisible(v => [...v, i]), startDelay + i * delayPerItem)
    );
    return () => timers.forEach(clearTimeout);
  }, [JSON.stringify(items?.map(i => i?.id || i))]);
  return visible;
}

// AnimatedNumber — smooth rolling counter with spring

const STATUS_CONFIG = {
  pending:    { color: '#F5C842', bg: 'rgba(245,200,66,.1)',  icon: '⏳', label: 'Pending'    },
  confirmed:  { color: '#9B6FFF', bg: 'rgba(155,111,255,.1)', icon: '✓',  label: 'Confirmed'  },
  picked_up:  { color: '#3B9EFF', bg: 'rgba(59,158,255,.1)',  icon: '🛵', label: 'Picked up'  },
  in_transit: { color: '#FF9500', bg: 'rgba(255,149,0,.1)',   icon: '📦', label: 'In transit' },
  delivered:  { color: '#00E087', bg: 'rgba(0,224,135,.1)',   icon: '✅', label: 'Delivered'  },
  cancelled:  { color: '#FF4059', bg: 'rgba(255,64,89,.1)',   icon: '✗',  label: 'Cancelled'  },
};

function StatusMorph({ status, size = 'md' }) {
  const cfg = STATUS_CONFIG[status] || STATUS_CONFIG.pending;
  const [prev, setPrev] = useState(status);
  const [animating, setAnimating] = useState(false);

  useEffect(() => {
    if (status === prev) return;
    setAnimating(true);
    setTimeout(() => { setPrev(status); setAnimating(false); }, 260);
  }, [status]);

  const sz = size === 'sm' ? { pad: '3px 9px', fs: 11, iconFs: 12 }
           : size === 'lg' ? { pad: '7px 16px', fs: 14, iconFs: 18 }
           : { pad: '4px 12px', fs: 12, iconFs: 14 };

  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 5,
      padding: sz.pad, borderRadius: 100, fontWeight: 700, fontSize: sz.fs,
      background: cfg.bg, color: cfg.color, border: `1px solid ${cfg.color}33`,
      transform: animating ? 'scale(.88)' : 'scale(1)',
      opacity: animating ? 0 : 1,
      transition: 'transform .14s var(--ease-spring), opacity .14s, background .3s, color .3s',
      fontFamily: "Satoshi,system-ui,sans-serif",
    }}>
      <span style={{ fontSize: sz.iconFs }}>{cfg.icon}</span>
      {cfg.label}
    </span>
  );
}

// CardEntrance — entrance animation wrapper for list items

function MorphingIcon({ icon, size = 20, style }) {
  const [current, setCurrent] = useState(icon);
  const [popping, setPopping] = useState(false);

  useEffect(() => {
    if (icon === current) return;
    setPopping(true);
    setTimeout(() => { setCurrent(icon); setPopping(false); }, 140);
  }, [icon]);

  return (
    <span style={{
      display: 'inline-block', fontSize: size,
      transform: popping ? 'scale(0)' : 'scale(1)',
      transition: 'transform .14s var(--ease-spring)',
      ...style,
    }}>{current}</span>
  );
}

// PageTransition — choreographed page header entrance
function PageHeader({ title, subtitle, icon, C, children, action }) {
  const [in_, setIn] = useState(false);
  useEffect(() => { const t = setTimeout(() => setIn(true), 30); return () => clearTimeout(t); }, []);

  return (
    <div style={{ padding: '52px 20px 18px', position: 'relative', overflow: 'hidden' }}>
      {/* Subtle mesh accent behind header */}
      <div style={{ position: 'absolute', top: -40, right: -20, width: 180, height: 180, borderRadius: '50%', background: C.accentGlow, filter: 'blur(60px)', opacity: 0.35, pointerEvents: 'none' }} />
      <div style={{ position: 'relative', opacity: in_ ? 1 : 0, transform: in_ ? 'none' : 'translateY(10px)', transition: 'opacity .35s var(--ease-out), transform .35s var(--ease-out)' }}>
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 12 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            {icon && (
              <div style={{ width: 44, height: 44, borderRadius: 14, background: C.accentBg, border: `1px solid ${C.accentLine}`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, flexShrink: 0 }}>{icon}</div>
            )}
            <div>
              <h1 className="disp" style={{ fontSize: 22, color: C.text, margin: 0, lineHeight: 1.2 }}>{title}</h1>
              {subtitle && <p style={{ fontSize: 13, color: C.sub, marginTop: 3, margin: 0 }}>{subtitle}</p>}
            </div>
          </div>
          {action}
        </div>
        {children}
      </div>
    </div>
  );
}

// ────────────────────────────────────────────────────────────────
//  2. AI PERSONALIZATION ENGINE (TF.js-style heuristic)
// ────────────────────────────────────────────────────────────────

// PersonalizedDashboard — reorders widgets by ML-scored behavior
function BehaviorTracker({ action, category, children }) {
  const { track } = usePersonalization() || {};
  return React.cloneElement(React.Children.only(children), {
    onClick: (e) => {
      track?.(action, { category, ts: Date.now() });
      children.props.onClick?.(e);
    }
  });
}

// useAdaptiveLayout — suggests layout density based on behavior
function useAdaptiveLayout() {
  const { model } = usePersonalization() || {};
  const [density, setDensity] = useState('comfortable'); // compact | comfortable | spacious

  useEffect(() => {
    if (!model?.events?.length) return;
    // If user scrolls fast through lists, suggest compact
    const browseEvents = model.events.filter(e => e.action === 'browse');
    if (browseEvents.length > 10) setDensity('compact');
    // If user spends time on single items, suggest spacious
    else if (browseEvents.length < 3) setDensity('spacious');
    else setDensity('comfortable');
  }, [model?.events?.length]);

  const spacing = { compact: { card: 8, gap: 8 }, comfortable: { card: 14, gap: 12 }, spacious: { card: 18, gap: 16 } }[density];
  return { density, spacing };
}

