//  3. WCAG 2.2 ACCESSIBILITY UPGRADES
// ────────────────────────────────────────────────────────────────

// Skip-to-main link (WCAG 2.4.1)

const AccessibleSheet = ({ open, onClose, title, children, C, maxH, describedBy }) => {
  const firstFocusRef = useRef(null);
  const prevFocus     = useRef(null);

  useEffect(() => {
    if (open) {
      prevFocus.current = document.activeElement;
      setTimeout(() => firstFocusRef.current?.focus(), 50);
    } else {
      prevFocus.current?.focus();
    }
  }, [open]);

  useEffect(() => {
    if (!open) return;
    const onKey = (e) => { if (e.key === 'Escape') onClose?.(); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  return (
    <div
      role="dialog" aria-modal="true"
      aria-label={title || 'Dialog'}
      aria-describedby={describedBy}
      style={{ position: 'fixed', inset: 0, zIndex: 600, background: 'rgba(0,0,0,.55)', backdropFilter: 'blur(6px)', WebkitBackdropFilter: 'blur(6px)' }}
      onClick={e => { if (e.target === e.currentTarget) onClose?.(); }}
    >
      <FocusTrap active={open}>
        <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, background: C.dark ? 'rgba(12,12,26,.98)' : C.surface, backdropFilter: 'blur(32px) saturate(180%)', WebkitBackdropFilter: 'blur(32px) saturate(180%)', borderRadius: '22px 22px 0 0', padding: `16px 20px calc(env(safe-area-inset-bottom,20px) + 20px)`, boxShadow: `0 -8px 48px rgba(0,0,0,.35), 0 -1px 0 ${C.accent}20`, maxHeight: maxH || '90vh', overflowY: 'auto', animation: 'slideUp .28s var(--ease-out)' }}>
          {/* Drag handle */}
          <div style={{ width: 36, height: 4, borderRadius: 2, background: C.muted, margin: '0 auto 16px', opacity: 0.5 }} aria-hidden="true" />
          {title && (
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 18 }}>
              <h2 ref={firstFocusRef} tabIndex={-1} className="disp" style={{ fontSize: 18, color: C.text, margin: 0, outline: 'none' }}>{title}</h2>
              <button onClick={onClose} aria-label="Close dialog"
                style={{ width: 32, height: 32, borderRadius: '50%', background: C.card, border: `1px solid ${C.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', fontSize: 16, color: C.sub }}>✕</button>
            </div>
          )}
          {children}
        </div>
      </FocusTrap>
    </div>
  );
};

// EnhancedTabBar — tabs with aria-selected, keyboard nav
function EnhancedTabBar({ tabs, active, onChange, C }) {
  const tabRefs = useRef([]);

  const onKeyDown = (e, i) => {
    if (e.key === 'ArrowRight') { const next = (i + 1) % tabs.length; onChange(tabs[next].id); tabRefs.current[next]?.focus(); }
    if (e.key === 'ArrowLeft')  { const prev = (i - 1 + tabs.length) % tabs.length; onChange(tabs[prev].id); tabRefs.current[prev]?.focus(); }
    if (e.key === 'Home')       { onChange(tabs[0].id); tabRefs.current[0]?.focus(); }
    if (e.key === 'End')        { const last = tabs.length-1; onChange(tabs[last].id); tabRefs.current[last]?.focus(); }
  };

  return (
    <div role="tablist" aria-label="Navigation tabs"
      style={{ display: 'flex', background: C.surface, borderRadius: 12, padding: 4, gap: 2 }}>
      {tabs.map((tab, i) => {
        const isActive = active === tab.id;
        return (
          <button
            key={tab.id}
            ref={el => tabRefs.current[i] = el}
            role="tab"
            aria-selected={isActive}
            aria-controls={`tabpanel-${tab.id}`}
            id={`tab-${tab.id}`}
            tabIndex={isActive ? 0 : -1}
            onClick={() => onChange(tab.id)}
            onKeyDown={e => onKeyDown(e, i)}
            style={{
              flex: 1, padding: '8px 12px', borderRadius: 9, border: 'none', cursor: 'pointer',
              background: isActive ? C.card : 'transparent',
              color: isActive ? C.text : C.sub,
              fontWeight: isActive ? 700 : 400, fontSize: 13,
              fontFamily: "Satoshi,system-ui,sans-serif",
              boxShadow: isActive ? '0 1px 6px rgba(0,0,0,.1)' : 'none',
              transition: 'all .18s var(--ease-out)',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
            }}
          >
            {tab.icon && <span aria-hidden="true" style={{ fontSize: 15 }}>{tab.icon}</span>}
            {tab.label}
            {tab.badge && <span style={{ minWidth: 18, height: 18, borderRadius: 9, background: C.accent, color: '#fff', fontSize: 12, fontWeight: 800, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 4px' }} aria-label={`${tab.badge} items`}>{tab.badge}</span>}
          </button>
        );
      })}
    </div>
  );
}

// EnhancedAccordion — with aria-expanded, smooth height animation
function EnhancedAccordion({ title, children, C, defaultOpen = false, icon }) {
  const [open, setOpen] = useState(defaultOpen);
  const [height, setHeight] = useState(defaultOpen ? 'auto' : 0);
  const contentRef = useRef(null);
  const id = useRef(`acc-${Math.random().toString(36).slice(2)}`);

  const toggle = () => {
    if (!open) {
      setHeight(contentRef.current?.scrollHeight || 0);
      setOpen(true);
      setTimeout(() => setHeight('auto'), 300);
    } else {
      setHeight(contentRef.current?.scrollHeight || 0);
      requestAnimationFrame(() => setHeight(0));
      setTimeout(() => setOpen(false), 300);
    }
  };

  return (
    <div style={{ borderRadius: 12, border: `1px solid ${C.border}`, overflow: 'hidden', marginBottom: 8 }}>
      <button
        onClick={toggle}
        aria-expanded={open}
        aria-controls={id.current}
        style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 16px', background: C.card, border: 'none', cursor: 'pointer', fontFamily: "Satoshi,system-ui,sans-serif", color: C.text }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {icon && <span aria-hidden="true">{icon}</span>}
          <span style={{ fontWeight: 600, fontSize: 14 }}>{title}</span>
        </div>
        <span aria-hidden="true" style={{ fontSize: 12, color: C.muted, transform: open ? 'rotate(180deg)' : 'none', transition: 'transform .25s var(--ease-out)' }}>▼</span>
      </button>
      <div
        id={id.current}
        ref={contentRef}
        role="region"
        aria-labelledby={`${id.current}-btn`}
        style={{ height: typeof height === 'number' ? height : undefined, overflow: 'hidden', transition: 'height .3s var(--ease-out)' }}
      >
        <div style={{ padding: '0 16px 16px' }}>{children}</div>
      </div>
    </div>
  );
}

