// Staggered list: wraps children so each fades in with delay


function StatusChip({ status, C }) {
  const [prev, setPrev]   = useState(status);
  const [anim, setAnim]   = useState(false);

  useEffect(() => {
    if (status !== prev) { setAnim(true); setTimeout(() => { setPrev(status); setAnim(false); }, 300); }
  }, [status, prev]);

  const cfg = {
    pending:    { label: 'Pending',     emoji: '🕐', color: C.gold,  bg: C.goldBg   },
    confirmed:  { label: 'Confirmed',   emoji: '✓',  color: C.green, bg: C.greenBg  },
    shopping:   { label: 'Shopping',    emoji: '🛒', color: C.accent,bg: C.accentBg },
    on_the_way: { label: 'On the way',  emoji: '🛵', color: C.accent,bg: C.accentBg },
    delivered:  { label: 'Delivered',   emoji: '🎉', color: C.green, bg: C.greenBg  },
    cancelled:  { label: 'Cancelled',   emoji: '✗',  color: C.red,   bg: C.redBg    },
  }[status] || { label: status, emoji: '•', color: C.sub, bg: C.card };

  return (
    <div
      role="status"
      aria-label={`Order status: ${cfg.label}`}
      aria-live="polite"
      style={{
        display: 'inline-flex', alignItems: 'center', gap: 5,
        background: cfg.bg, borderRadius: 20, padding: '4px 11px',
        border: `1px solid ${cfg.color}33`,
        transform: anim ? 'scale(1.12)' : 'scale(1)',
        opacity:   anim ? 0 : 1,
        transition: 'transform 150ms var(--ease-spring), opacity 150ms',
      }}
    >
      <span style={{ fontSize: 13 }}>{cfg.emoji}</span>
      <span style={{ fontSize: 12, fontWeight: 700, color: cfg.color }}>{cfg.label}</span>
    </div>
  );
}

// Ripple effect hook — generates ripple on pointer down
function useRipple(color = 'rgba(255,255,255,.25)') {
  const [ripples, setRipples] = useState([]);
  const fire = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x    = (e.touches?.[0]?.clientX ?? e.clientX) - rect.left;
    const y    = (e.touches?.[0]?.clientY ?? e.clientY) - rect.top;
    const id   = Date.now();
    setRipples(r => [...r, { id, x, y }]);
    setTimeout(() => setRipples(r => r.filter(r => r.id !== id)), 600);
  };
  const RippleLayer = () => (
    <>
      {ripples.map(r => (
        <span key={r.id} style={{
          position: 'absolute', left: r.x, top: r.y,
          width: 6, height: 6, borderRadius: '50%',
          background: color, pointerEvents: 'none',
          transform: 'translate(-50%,-50%) scale(0)',
          animation: 'rippleOut 600ms var(--ease-out) forwards',
        }} />
      ))}
    </>
  );
  return { fire, RippleLayer };
}

// Card with enter animation, hover lift, and ripple
function AnimCard({ children, C, onClick, style, ariaLabel, role = 'article', delay = 0, href }) {
  const { fire, RippleLayer } = useRipple(C.dark ? 'rgba(255,255,255,.07)' : 'rgba(0,0,0,.04)');
  const [hovered, setHovered] = useState(false);
  const Tag = href ? 'a' : 'div';

  return (
    <Tag
      role={onClick ? 'button' : role}
      aria-label={ariaLabel}
      tabIndex={onClick ? 0 : undefined}
      onKeyDown={onClick ? (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onClick(e); } } : undefined}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onPointerDown={fire}
      onClick={onClick}
      href={href}
      style={{
        position: 'relative', overflow: 'hidden',
        background: C.card, border: `1px solid ${hovered && onClick ? C.accentLine : C.border}`,
        borderRadius: 16, cursor: onClick ? 'pointer' : 'default',
        transform: hovered && onClick ? 'translateY(-2px)' : 'none',
        boxShadow: hovered && onClick ? `0 6px 24px ${C.accentGlow}` : 'none',
        transition: 'transform 200ms var(--ease-out), box-shadow 200ms var(--ease-out), border-color 150ms',
        animation: `staggerIn 320ms cubic-bezier(.22,1,.36,1) ${delay}ms both`,
        textDecoration: 'none', color: 'inherit',
        ...style,
      }}
    >
      <RippleLayer />
      {children}
    </Tag>
  );
}

// Page-level transition wrapper with stagger context
function PageEnter({ children, style }) {
  return (
    <div style={{ animation: 'pageEnter 280ms cubic-bezier(.22,1,.36,1) both', ...style }}>
      {children}
    </div>
  );
}

// Progress bar with smooth fill animation
function AnimProgress({ value, max = 100, color, bg, height = 6, C, label }) {
  const pct = Math.min((value / max) * 100, 100);
  return (
    <div
      role="progressbar"
      aria-valuenow={value}
      aria-valuemax={max}
      aria-label={label}
      style={{ background: bg || C.border, borderRadius: 99, height, overflow: 'hidden' }}
    >
      <div style={{
        height: '100%', borderRadius: 99,
        background: color || C.accent,
        width: `${pct}%`,
        transition: 'width 600ms cubic-bezier(.22,1,.36,1)',
      }} />
    </div>
  );
}

// Skeleton → content morph (fades skeleton out, content in)
function ContentReveal({ loading, skeleton, children, style }) {
  return (
    <div style={{ position: 'relative', ...style }}>
      <div style={{ opacity: loading ? 1 : 0, transition: 'opacity 220ms', position: loading ? 'relative' : 'absolute', inset: 0, pointerEvents: loading ? 'auto' : 'none' }}>{skeleton}</div>
      <div style={{ opacity: loading ? 0 : 1, transition: 'opacity 280ms 80ms', position: loading ? 'absolute' : 'relative', inset: 0, pointerEvents: loading ? 'none' : 'auto' }}>{children}</div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════
//  2. AI PERSONALIZATION — TF.js-backed with heuristic fallback
// ══════════════════════════════════════════════════════════════

// Lightweight Matrix Factorization using TF.js (loaded async)
// Falls back to existing heuristic model if TF.js unavailable
function useTFPersonalization() {
  const [tfReady, setTfReady]       = useState(false);
  const [tfModel, setTfModel]       = useState(null);
  const { track = () => {}, topActions = () => [], score = () => 0, widgetOrder = (x) => x, model: hModel } = useP13n() || {};

  // Load TF.js async (CDN)
  useEffect(() => {
    if (window.tf) { setTfReady(true); return; }
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/@tensorflow/tfjs@4.17.0/dist/tf.min.js';
    s.async = true;
    s.onload = () => {
      setTfReady(true);
      // Build a tiny embedding model for action preference scoring
      buildEmbeddingModel();
    };
    document.head.appendChild(s);
  }, []);

  const buildEmbeddingModel = () => {
    if (!window.tf) return;
    const tf = window.tf;
    // User-item dot-product model: 8-dim embeddings for 32 actions
    const userEmb  = tf.variable(tf.randomNormal([1, 8]));
    const itemEmb  = tf.variable(tf.randomNormal([32, 8]));
    // Store for later scoring
    window.__errandTF = { userEmb, itemEmb, tf };
    setTfModel({ userEmb, itemEmb });
  };

  // Score action importance using TF (or fallback)
  const aiScore = useCallback((action, category) => {
    if (tfReady && window.__errandTF) {
      try {
        const { tf, userEmb, itemEmb } = window.__errandTF;
        // Hash action to item index
        const idx = Math.abs([...`${action}${category}`].reduce((h, c) => (h * 31 + c.charCodeAt(0)) | 0, 0)) % 32;
        const item = itemEmb.slice([idx, 0], [1, 8]);
        const dot  = tf.sum(tf.mul(userEmb, item)).dataSync()[0];
        // Blend TF score with heuristic score
        const hScore = score(action, category);
        return (dot + 1) * 0.5 + hScore * 2; // normalize
      } catch { return score(action, category); }
    }
    return score(action, category);
  }, [tfReady, score]);

  // Update TF embeddings when user interacts
  const aiTrack = useCallback((action, context = {}) => {
    track(action, context);
    if (tfReady && window.__errandTF) {
      try {
        const { tf, userEmb, itemEmb } = window.__errandTF;
        const idx = Math.abs([...(action + (context.category||''))].reduce((h,c) => (h*31 + c.charCodeAt(0))|0, 0)) % 32;
        const lr  = 0.01;
        // Positive signal: nudge user embedding toward this item
        const item = itemEmb.slice([idx,0],[1,8]);
        const grad = tf.sub(item, userEmb).mul(lr);
        userEmb.assign(tf.add(userEmb, grad));
      } catch {}
    }
  }, [tfReady, track]);

  // Rank a list by AI scores
  const aiRank = useCallback((items, getKey = (i) => `${i.id}`) => {
    return [...items].sort((a, b) => {
      const sa = aiScore(getKey(a), a.category);
      const sb = aiScore(getKey(b), b.category);
      return sb - sa;
    });
  }, [aiScore]);

  // Generate dashboard layout recommendations
  const dashboardLayout = useCallback(() => {
    const tops = topActions(8);
    const hasOrders   = tops.some(t => t.key.includes('order'));
    const hasStores   = tops.some(t => t.key.includes('store'));
    const hasShopper  = tops.some(t => t.key.includes('shopper') || t.key.includes('tracking'));
    const hasWallet   = tops.some(t => t.key.includes('wallet') || t.key.includes('pay'));
    const hasRewards  = tops.some(t => t.key.includes('reward') || t.key.includes('gamif'));

    // Suggest featured widget
    if (hasOrders && hasShopper) return 'tracking_first';
    if (hasStores) return 'stores_first';
    if (hasWallet) return 'wallet_first';
    if (hasRewards) return 'rewards_first';
    return 'default';
  }, [topActions]);

  return { aiScore, aiTrack, aiRank, dashboardLayout, tfReady, heuristicModel: hModel };
}

// Context
const AIPersonContext = React.createContext(null);
function AIPersonProvider({ children }) {
  const value = useTFPersonalization();
  return <AIPersonContext.Provider value={value}>{children}</AIPersonContext.Provider>;
}
function useAI() { return React.useContext(AIPersonContext) || {}; }

// Personalized section header — shows "Based on your activity" badge
function PersonalizedHeader({ label, C, style }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12, ...style }}>
      <span style={{ fontWeight: 700, fontSize: 15, color: C.text }}>{label}</span>
      <div style={{ display: 'inline-flex', alignItems: 'center', gap: 4, background: C.purpleBg, border: `1px solid ${C.purpleLine}`, borderRadius: 10, padding: '2px 8px' }}>
        <span style={{ fontSize: 12 }}>✦</span>
        <span style={{ fontSize: 12, fontWeight: 700, color: C.purple }}>AI</span>
      </div>
    </div>
  );
}

// AI Insight card — surfaces patterns from the model
function AIInsightCard({ C, goTo }) {
  const { topActions, dashboardLayout, tfReady } = useAI();
  const tops = topActions(3);
  if (!tops.length) return null;

  const layout = dashboardLayout();
  const msgs = {
    tracking_first: { icon: '🛵', text: 'You track orders often — Tracking is pinned to your quick actions.' },
    stores_first:   { icon: '🏪', text: 'You shop at stores frequently — Store suggestions are prioritised for you.' },
    wallet_first:   { icon: '💰', text: 'You manage payments often — Wallet summary is shown first.' },
    rewards_first:  { icon: '🏆', text: 'You love rewards! Your streak and challenges are pinned to Home.' },
    default:        { icon: '✨', text: 'Your Home screen adapts to your most-used features automatically.' },
  };
  const msg = msgs[layout] || msgs.default;

  return (
    <div style={{ background: C.purpleBg, border: `1px solid ${C.purpleLine}`, borderRadius: 14, padding: '11px 14px', marginBottom: 14, display: 'flex', gap: 11, alignItems: 'flex-start' }}
      role="note" aria-label="AI personalisation insight">
      <span style={{ fontSize: 22 }}>{msg.icon}</span>
      <div style={{ flex: 1 }}>
        <div style={{ fontWeight: 700, fontSize: 12, color: C.purple, marginBottom: 3, display: 'flex', alignItems: 'center', gap: 5 }}>
          <span>AI Personalisation</span>
          {tfReady && <span style={{ fontSize: 12, background: C.green, color: '#fff', borderRadius: 6, padding: '1px 5px', fontWeight: 800 }}>TF.js</span>}
        </div>
        <div style={{ fontSize: 12.5, color: C.sub, lineHeight: 1.5 }}>{msg.text}</div>
      </div>
    </div>
  );
}

