// Skip-to-content link — first focusable element, sr-only until focused
function SkipToContent() {
  return (
    <a
      href="#main-content"
      style={{
        position: 'fixed', top: 8, left: 8, zIndex: 99999,
        background: '#000', color: '#fff',
        padding: '10px 18px', borderRadius: 8, fontWeight: 700, fontSize: 14,
        transform: 'translateY(-120%)', transition: 'transform .2s',
        fontFamily: "Satoshi,system-ui,sans-serif", textDecoration: 'none',
      }}
      onFocus={e  => { e.currentTarget.style.transform = 'none'; }}
      onBlur={e   => { e.currentTarget.style.transform = 'translateY(-120%)'; }}
    >
      Skip to main content
    </a>
  );
}

// Screen-reader live region — announces dynamic content changes
function useLiveAnnounce() {
  const [msg, setMsg] = useState('');
  const announce = useCallback((text, politeness = 'polite') => {
    setMsg('');
    requestAnimationFrame(() => setMsg(text));
  }, []);
  const LiveRegion = () => (
    <div aria-live="polite" aria-atomic="true" className="sr-only"
      style={{ position: 'absolute', width: 1, height: 1, overflow: 'hidden', clip: 'rect(0,0,0,0)', whiteSpace: 'nowrap' }}>
      {msg}
    </div>
  );
  return { announce, LiveRegion };
}

// Keyboard-navigable list (arrow keys + Home/End + Enter/Space)
function KeyboardList({ items, renderItem, C, style, getLabel, onSelect }) {
  const [focused, setFocused] = useState(-1);
  const listRef = useRef(null);

  const onKeyDown = (e) => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setFocused(f => Math.min(f + 1, items.length - 1)); }
    if (e.key === 'ArrowUp')   { e.preventDefault(); setFocused(f => Math.max(f - 1, 0)); }
    if (e.key === 'Home')      { e.preventDefault(); setFocused(0); }
    if (e.key === 'End')       { e.preventDefault(); setFocused(items.length - 1); }
    if ((e.key === 'Enter' || e.key === ' ') && focused >= 0) { e.preventDefault(); onSelect?.(items[focused], focused); }
  };

  useEffect(() => {
    if (focused >= 0) listRef.current?.children[focused]?.focus();
  }, [focused]);

  return (
    <div ref={listRef} role="listbox" aria-label="Item list" onKeyDown={onKeyDown} style={style}>
      {items.map((item, i) => (
        <div key={i} role="option" aria-selected={focused === i} tabIndex={focused === i ? 0 : -1}
          aria-label={getLabel?.(item) || String(item)}
          onFocus={() => setFocused(i)}
          onBlur={() => setFocused(-1)}
          style={{ outline: 'none' }}>
          {renderItem(item, i, focused === i)}
        </div>
      ))}
    </div>
  );
}

// Accessible modal / dialog wrapper
function A11yDialog({ open, onClose, title, children, C }) {
  const dialogRef = useRef(null);
  const prevFocus = useRef(null);

  useEffect(() => {
    if (open) {
      prevFocus.current = document.activeElement;
      requestAnimationFrame(() => dialogRef.current?.focus());
    } else {
      prevFocus.current?.focus();
    }
  }, [open]);

  // Trap focus inside dialog
  const trapFocus = (e) => {
    if (!dialogRef.current) return;
    const focusable = dialogRef.current.querySelectorAll('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])');
    const first = focusable[0], last = focusable[focusable.length - 1];
    if (e.key === 'Tab') {
      if (e.shiftKey) { if (document.activeElement === first) { e.preventDefault(); last?.focus(); } }
      else            { if (document.activeElement === last)  { e.preventDefault(); first?.focus(); } }
    }
    if (e.key === 'Escape') onClose?.();
  };

  if (!open) return null;
  return (
    <>
      <div onClick={onClose} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.55)', zIndex: 4998, animation: 'fadeIn 150ms' }} aria-hidden="true" />
      <div ref={dialogRef} role="dialog" aria-modal="true" aria-labelledby="dialog-title"
        tabIndex={-1} onKeyDown={trapFocus}
        style={{ position: 'fixed', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', zIndex: 4999, width: 'min(92vw,440px)', background: C.card, border: `1px solid ${C.border}`, borderRadius: 20, padding: '22px 20px', animation: 'scaleIn 200ms var(--ease-spring)', outline: 'none' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <h2 id="dialog-title" style={{ fontSize: 17, fontWeight: 700, color: C.text, fontFamily: "Syne,sans-serif" }}>{title}</h2>
          <button onClick={onClose} aria-label="Close dialog" style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, width: 34, height: 34, cursor: 'pointer', color: C.sub, fontSize: 18, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>×</button>
        </div>
        {children}
      </div>
    </>
  );
}

// High-contrast token overlay — patches C when HC is active
function withHighContrast(C, hcActive) {
  if (!hcActive) return C;
  return {
    ...C,
    text:    C.dark ? '#FFFFFF' : '#000000',
    sub:     C.dark ? '#CCCCCC' : '#222222',
    muted:   C.dark ? '#999999' : '#444444',
    border:  C.dark ? '#FFFFFF' : '#000000',
    accent:  C.dark ? '#FFD700' : '#0057B8',
    accentBg:C.dark ? 'rgba(255,215,0,.18)' : 'rgba(0,87,184,.12)',
    accentLine:C.dark ? 'rgba(255,215,0,.5)' : 'rgba(0,87,184,.5)',
    card:    C.dark ? '#0D0D0D' : '#FFFFFF',
    surface: C.dark ? '#1A1A1A' : '#F8F8F8',
    green:   C.dark ? '#00FF88' : '#007A3D',
    gold:    C.dark ? '#FFD700' : '#8B6914',
    red:     C.dark ? '#FF6B6B' : '#CC0000',
  };
}

// Voice command integration (Web Speech API)

function A11yToggle({ value, onChange, label, C }) {
  return (
    <button
      role="switch"
      aria-checked={value}
      aria-label={label}
      onClick={() => onChange(!value)}
      style={{
        width: 44, height: 26, borderRadius: 13,
        background: value ? C.accent : C.border,
        border: 'none', cursor: 'pointer',
        position: 'relative', transition: 'background .22s',
        flexShrink: 0,
      }}
    >
      <div style={{
        position: 'absolute', top: 3, left: value ? 21 : 3,
        width: 20, height: 20, borderRadius: 10, background: '#fff',
        transition: 'left .22s var(--ease-spring)',
        boxShadow: '0 1px 4px rgba(0,0,0,.2)',
      }} />
      <span className="sr-only">{label}: {value ? 'on' : 'off'}</span>
    </button>
  );
}

// ARIA-enhanced accordion for FAQ / Help sections
function A11yAccordion({ items, C }) {
  const [open, setOpen] = useState(null);
  const toggle = (i) => setOpen(o => o === i ? null : i);

  return (
    <div role="list">
      {items.map((item, i) => {
        const isOpen = open === i;
        return (
          <div key={i} role="listitem" style={{ borderBottom: `1px solid ${C.border}` }}>
            <button
              id={`acc-head-${i}`}
              aria-expanded={isOpen}
              aria-controls={`acc-panel-${i}`}
              onClick={() => toggle(i)}
              style={{ width: '100%', textAlign: 'left', background: 'none', border: 'none', padding: '14px 16px', cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: C.text, fontFamily: "Satoshi,system-ui,sans-serif", fontSize: 14, fontWeight: 500 }}
            >
              <span>{item.question}</span>
              <span style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform .22s var(--ease-spring)', color: C.accent, fontSize: 18, flexShrink: 0 }}>⌄</span>
            </button>
            <div
              id={`acc-panel-${i}`}
              role="region"
              aria-labelledby={`acc-head-${i}`}
              style={{ maxHeight: isOpen ? 400 : 0, overflow: 'hidden', transition: 'max-height .3s var(--ease-out)', padding: isOpen ? '0 16px 14px' : '0 16px' }}
            >
              <p style={{ color: C.sub, fontSize: 13.5, lineHeight: 1.6 }}>{item.answer}</p>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// Focus ring override for custom elements
function useFocusVisible() {
  const [focused, setFocused] = useState(false);
  return {
    focusProps: {
      onFocus: (e) => { if (e.target.matches(':focus-visible')) setFocused(true); },
      onBlur:  ()  => setFocused(false),
    },
    focused,
    focusStyle: focused ? { outline: `2.5px solid currentColor`, outlineOffset: 3, borderRadius: 6 } : {},
  };
}

